INSERT INTO public.subjects (id, name_fr, description, attribute, color_token, icon, display_order, content_language, is_premium, theme_id, grade_id) VALUES
  ('education-islamique-4eme', 'التربية الإسلامية', 'نتلو ونستظهر في خشوعٍ أربعَ سُوَرٍ مكّيّة (الفجر والغاشية والأعلى والطارق) وآياتٍ كريمةً في برّ الوالدين وطاعة الرسول ﷺ وآدابِ السلوك، ونتدبّر دلائلَ عظمة الله في الكون، ونتعلّم الإيمان بالله ورسوله والكتب السماويّة. ونرسّخ مكارم الأخلاق والآداب: برّ الوالدين والأجداد، والاجتهاد في طلب العلم، وواجب المتعلّم نحو معلّمه ومدرسته، وآداب الطريق والزيارة والعيادة، والتعاون بين الجيران، والتواضع. ونتدرّب على العبادات وفق الفقه المالكي: الوضوء والتيمّم والصلاة وأوقاتها ومكوّنات الركعة والتشهّد ودعاء القنوت وصلاة الجمعة وصلاة العيدين، وفق برنامج التربية الإسلامية للسنة الرابعة من التعليم الأساسي.', 'قيم', 'subject-arabic', 'Heart', 3, 'ar', false, 'ecole-tn', (SELECT id FROM public.grades WHERE theme_id = 'ecole-tn' AND slug = '4eme-base'))
