  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('904ff07a-9b70-5096-a807-87cb57f8b09f', '26bf7c26-b9ea-591c-9b01-d19973802f67', 'لماذا ذكّرتنا السورة بمصير عادٍ وثمودَ وفرعون؟', '[{"id":"a","text":"لأنّهم كانوا فقراء"},{"id":"b","text":"لِنعتبر: فمهما قوِيَ الظالمون أهلكهم اللهُ القادر"},{"id":"c","text":"لأنّهم بنوا المساجد"},{"id":"d","text":"لِنُقلّدهم في أعمالهم"}]'::jsonb, 'b', 'ذكّرتنا السورة بمصيرهم لنعتبر: كانوا أقوياءَ أصحابَ بنيانٍ عظيم، لكنّ اللهَ أهلكهم لمّا طغوا، فهذا دليلٌ على قدرة الله. الخطأ الشائع الانبهار بقوّة الظالمين ونسيان قدرة الله.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f146a75b-cde4-5c30-8593-7a6adb4dd0f0', '26bf7c26-b9ea-591c-9b01-d19973802f67', 'قال الإنسانُ حين أعطاه اللهُ مالًا: «رَبِّي أَكْرَمَنِ»، وحين ضُيِّق عليه: «رَبِّي أَهَانَنِ». ما الصواب الذي تُعلّمنا إيّاه السورة؟', '[{"id":"a","text":"المالُ والضيقُ ابتلاءٌ واختبار، لا إكرامٌ ولا إهانة حتمًا"},{"id":"b","text":"الغنيُّ دائمًا مُكرَمٌ عند الله"},{"id":"c","text":"الفقيرُ دائمًا مُهانٌ عند الله"},{"id":"d","text":"المالُ علامةُ رضا الله وحدها"}]'::jsonb, 'a', 'تُعلّمنا السورة أنّ المالَ والضيقَ ابتلاءٌ واختبار من الله، وليسا دليلًا حتميًّا على الإكرام أو الإهانة. الخطأ الشائع الحكم على الناس بالغنى والفقر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7cd05671-d98f-5f72-8492-035096805a79', '26bf7c26-b9ea-591c-9b01-d19973802f67', 'أيُّ هذه الأعمال عاتبَ اللهُ عليها الناسَ في سورة الفجر؟', '[{"id":"a","text":"كثرةُ الصلاة"},{"id":"b","text":"الإحسانُ إلى الجار"},{"id":"c","text":"إكرامُ اليتيم"},{"id":"d","text":"تركُ إكرام اليتيم وعدمُ الحثّ على إطعام المسكين"}]'::jsonb, 'd', 'عاتب اللهُ مَن لا يُكرم اليتيم، ولا يحثُّ على إطعام المسكين، ويأكل الميراثَ بغير حقّ، ويُحبّ المالَ حبًّا شديدًا. الخطأ الشائع الخلط بين ما عاتب اللهُ عليه وما أمر به.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ddd1d065-f16f-52e3-8ca4-dbd96303894c', '26bf7c26-b9ea-591c-9b01-d19973802f67', '«وَجَاءَ رَبُّكَ وَالْمَلَكُ صَفًّا صَفًّا» تصف مشهدًا من ...', '[{"id":"a","text":"حياة الدنيا العاديّة"},{"id":"b","text":"يوم القيامة"},{"id":"c","text":"نوم الإنسان"},{"id":"d","text":"قصص الأمم الماضية فقط"}]'::jsonb, 'b', 'هذه الآية تصف مشهدًا من يوم القيامة: تُدكُّ الأرضُ، ويأتي أمرُ ربّك والملائكةُ مصطفّين صفوفًا. الخطأ الشائع فهم الآية على أنّها وصفٌ لأمرٍ دنيويّ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

