  ('56241a80-4952-523e-903e-72efc7709bf6', 'a8b38c30-100b-5fb1-bde6-b80efd804ba8', 'education-islamique-4eme', '⭐⭐ تمرين مراجعة: سورة الفجر (نمط امتحان)', 2, 75, 15, 'practice', 'admin', 3)
