INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46e6c688-b711-5faa-bf66-be04e79ca83c', '56241a80-4952-523e-903e-72efc7709bf6', 'سورة الفجر سورةٌ ...', '[{"id":"a","text":"مدنيّةٌ طويلة"},{"id":"b","text":"ليست من القرآن"},{"id":"c","text":"من كتب القصص"},{"id":"d","text":"مكّيّةٌ عدد آياتها 30"}]'::jsonb, 'd', 'سورة الفجر سورةٌ مكّيّة من القرآن الكريم، عدد آياتها 30 آية.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('26135ead-ee5b-5dc6-9606-12f80385c367', '56241a80-4952-523e-903e-72efc7709bf6', 'أكمل: وَالشَّفْعِ ...', '[{"id":"a","text":"وَالْوَتْرِ"},{"id":"b","text":"وَالْفَجْرِ"},{"id":"c","text":"وَالنَّهَارِ"},{"id":"d","text":"وَالشَّمْسِ"}]'::jsonb, 'a', 'الآية هي: وَالشَّفْعِ وَالْوَتْرِ، أقسم اللهُ بهما؛ الشَّفع العدد الزوجي، والوَتر العدد الفردي.', 2)
