INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d08aebd6-aeea-51ba-be89-0c28f5979b3e', '56241a80-4952-523e-903e-72efc7709bf6', '«ثمود» التي ذكرتها السورة هي قومُ نبيِّ الله ...', '[{"id":"a","text":"إبراهيم عليه السلام"},{"id":"b","text":"يوسف عليه السلام"},{"id":"c","text":"صالح عليه السلام"},{"id":"d","text":"محمّد ﷺ"}]'::jsonb, 'c', 'ثمودُ هم قومُ نبيِّ الله صالح عليه السلام، الذين جابوا الصخرَ بالوادِ ونحتوه بيوتًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
