  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b8574502-26b7-5298-a76f-211f5922b6fd', '56241a80-4952-523e-903e-72efc7709bf6', 'معنى «التُّرَاثَ» في قوله «وَتَأْكُلُونَ التُّرَاثَ أَكْلًا لَّمًّا» هو ...', '[{"id":"a","text":"الطعامُ اللذيذ"},{"id":"b","text":"الميراثُ، أي المالُ الذي يبقى بعد الناس"},{"id":"c","text":"الكتبُ القديمة"},{"id":"d","text":"الثيابُ"}]'::jsonb, 'b', 'التُّراثُ هو الميراث، أي المالُ الذي يبقى بعد الناس؛ عاتب اللهُ مَن يأكله بغير حقٍّ جامعًا الحلالَ والحرام.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2ca86640-bd85-5b0f-9fde-75ca74777b24', '56241a80-4952-523e-903e-72efc7709bf6', 'ماذا يقول اللهُ للنفس المطمئنّة في آخر السورة؟', '[{"id":"a","text":"ارجعي إلى ربّك راضيةً مرضيّة وادخلي جنّتي"},{"id":"b","text":"ابقي في الدنيا"},{"id":"c","text":"اجمعي المالَ"},{"id":"d","text":"لا بُشرى لكِ"}]'::jsonb, 'a', 'يُنادي اللهُ النفسَ المطمئنّة المؤمنة بالبُشرى: ارجعي إلى ربّك راضيةً مرضيّة، فادخلي في عبادي وادخلي جنّتي.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ed624a26-3fcd-5d4b-8ff4-1ab4303269d1', '56241a80-4952-523e-903e-72efc7709bf6', 'كيف نعرف عظمة الله وقدرته من سورة الفجر؟', '[{"id":"a","text":"من كثرة الأموال"},{"id":"b","text":"من ضعف المخلوقات فقط"},{"id":"c","text":"من تعاقُب الفجر والليل بنظامٍ دقيق، ومن إهلاك الأمم القويّة، ومن قدرته على يوم القيامة"},{"id":"d","text":"لا تدلّ السورةُ على عظمته"}]'::jsonb, 'c', 'تدلّنا السورةُ على عظمة الله من خلال مخلوقاته: تعاقُب الفجر والليل بنظامٍ دقيق، وإهلاكه الأممَ القويّة مهما بلغت قوّتُها، وقدرته على يوم القيامة الذي تُدكّ فيه الأرض.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b2106f3d-a560-5ffa-b69b-e29bc3b9b513', 'a8b38c30-100b-5fb1-bde6-b80efd804ba8', 'education-islamique-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: بطلُ سورة الفجر', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
