INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('77346aa0-9437-5a47-9272-59189aefcd4b', 'b2106f3d-a560-5ffa-b69b-e29bc3b9b513', 'رتّب الأمم كما ذكرتها السورة: (1) فرعون (2) عاد (3) ثمود. ما الترتيب الصحيح من أوّلها؟', '[{"id":"a","text":"1 ثمّ 2 ثمّ 3"},{"id":"b","text":"2 ثمّ 3 ثمّ 1"},{"id":"c","text":"3 ثمّ 1 ثمّ 2"},{"id":"d","text":"1 ثمّ 3 ثمّ 2"}]'::jsonb, 'b', 'ذكرت السورةُ عادًا (2) أوّلًا «بِعَادٍ»، ثمّ ثمودَ (3) «وَثَمُودَ»، ثمّ فرعونَ (1) «وَفِرْعَوْنَ». الخطأ الشائع تقديم فرعون على عادٍ وثمود.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b33d9780-59d3-5a3b-8bc4-6a4714c461e2', 'b2106f3d-a560-5ffa-b69b-e29bc3b9b513', 'قال تلميذٌ: «سورة الفجر تَعِدُ كلَّ غنيٍّ بأنّ اللهَ أكرمه لأنّه يستحقّ». هل قولُه صحيح على ضوء السورة؟', '[{"id":"a","text":"نعم، الغنيُّ مُكرَمٌ دائمًا"},{"id":"b","text":"نعم، الفقيرُ مُهانٌ دائمًا"},{"id":"c","text":"لا يُذكر شيءٌ عن المال في السورة"},{"id":"d","text":"لا، فالمالُ ابتلاءٌ واختبار، لا دليلَ حتميٌّ على الإكرام"}]'::jsonb, 'd', 'السورة صحّحت هذا الفهم: المالُ والضيقُ ابتلاءٌ واختبار، وليسا دليلًا حتميًّا على إكرام الله أو إهانته. الخطأ الشائع فهم النعمة على أنّها دائمًا علامةُ رضا الله.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1f5e0eec-757c-55f1-a935-ae3607ce6756', 'b2106f3d-a560-5ffa-b69b-e29bc3b9b513', 'تلميذٌ رأى صديقًا يتيمًا فلم يُحسن إليه واستهزأ به. ماذا نقول له على ضوء سورة الفجر؟', '[{"id":"a","text":"أحسنت، هذا صواب"},{"id":"b","text":"اليتيمُ لا يستحقّ الإحسان"},{"id":"c","text":"عاتب اللهُ مَن لا يُكرم اليتيم، فالواجبُ الإحسانُ إليه ورحمتُه"},{"id":"d","text":"لا علاقة للسورة باليتيم"}]'::jsonb, 'c', 'قال تعالى «كَلَّا بَل لَّا تُكْرِمُونَ الْيَتِيمَ» عتابًا لمن لا يُكرم اليتيم؛ فالواجبُ الإحسانُ إليه ورحمتُه لا الاستهزاءُ به. الخطأ الشائع الاستخفافُ بحقّ اليتيم.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ef8b2d8c-a586-5f20-9a52-47fbfa884dab', 'b2106f3d-a560-5ffa-b69b-e29bc3b9b513', 'ما الدرسُ العقَدِيُّ الأكبر الذي نأخذه من سورة الفجر؟', '[{"id":"a","text":"أنّ اللهَ عظيمٌ قادر، نعرف عظمته من مخلوقاته وأفعاله"},{"id":"b","text":"أنّ المالَ هو الأهمّ في الحياة"},{"id":"c","text":"أنّ الأمم القويّة لا تهلك أبدًا"},{"id":"d","text":"أنّ يوم القيامة لن يأتي"}]'::jsonb, 'a', 'الدرسُ الأكبر في العقيدة: أنّ اللهَ عظيمٌ قادر، ونعرف عظمته من مخلوقاته (الفجر والليل المنظَّمَين) ومن إهلاكه الأمم ومن قدرته على يوم القيامة. الخطأ الشائع الغفلةُ عن دلائل عظمة الله في الكون.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7d0a3d96-f435-5283-a9f4-d95c2528a314', 'b2106f3d-a560-5ffa-b69b-e29bc3b9b513', '«يَوْمَئِذٍ يَتَذَكَّرُ الْإِنْسَانُ وَأَنَّىٰ لَهُ الذِّكْرَىٰ»: ما المقصود؟', '[{"id":"a","text":"أنّ التذكُّرَ يومئذٍ ينفعه ويُنجيه"},{"id":"b","text":"أنّ الإنسانَ ينسى كلَّ شيء"},{"id":"c","text":"أنّ الذكرى للأطفال فقط"},{"id":"d","text":"أنّه يتذكّر يوم القيامة لكن بعد فوات الأوان فلا ينفعه ندمُه"}]'::jsonb, 'd', 'المعنى أنّ الإنسانَ يتذكّر ويندم يوم القيامة، لكن بعد فوات الأوان فلا ينفعه ذلك؛ فالعملُ الصالحُ يكون في الدنيا. الخطأ الشائع ظنّ أنّ الندمَ يومئذٍ يُنجي صاحبه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0530f665-02d4-5d7f-875a-d77f3a48faef', 'b2106f3d-a560-5ffa-b69b-e29bc3b9b513', 'ما الرسالةُ التي نأخذها من سورة الفجر ونعمل بها في حياتنا؟', '[{"id":"a","text":"نعرف عظمة الله من مخلوقاته، ونعتبر بمصير الظالمين، ونُكرم اليتيمَ والمسكين"},{"id":"b","text":"نجمع المالَ ونُحبّه حبًّا شديدًا"},{"id":"c","text":"نُقلّد الأمم الطاغية"},{"id":"d","text":"نستهزئ بالضعفاء"}]'::jsonb, 'a', 'نعمل بالسورة: نعرف عظمة الله من مخلوقاته فنعبده وحده، ونعتبر بمصير عادٍ وثمودَ وفرعون، ونُكرم اليتيمَ والمسكين، ونسعى لنكون من النفس المطمئنّة. الخطأ الشائع اختزال السورة في معنًى واحد.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('ea2c872e-0f3c-5592-8bb8-03edd3ed1665', 'a8b38c30-100b-5fb1-bde6-b80efd804ba8', 'education-islamique-4eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة لسورة الفجر', 3, 120, 30, 'boss', 'admin', 5)
