INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8acfe49a-b9ba-516e-8ec0-8e4e1e6dcc31', 'ea2c872e-0f3c-5592-8bb8-03edd3ed1665', 'سورة الفجر نزلت في مكّة، فهي سورةٌ ...', '[{"id":"a","text":"مدنيّة"},{"id":"b","text":"من القصص"},{"id":"c","text":"مكّيّة"},{"id":"d","text":"طويلة جدًّا"}]'::jsonb, 'c', 'السورة التي نزلت في مكّة تُسمّى مكّيّة، وسورة الفجر نزلت في مكّة فهي مكّيّة، عدد آياتها 30.', 1)
ON CONFLICT (id) DO UPDATE SET
