INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dcc65832-4f09-531c-8a45-549c15cba494', 'ea2c872e-0f3c-5592-8bb8-03edd3ed1665', 'أكمل: وَالْفَجْرِ ۝ وَلَيَالٍ عَشْرٍ ۝ وَالشَّفْعِ ...', '[{"id":"a","text":"وَالنَّهَارِ"},{"id":"b","text":"وَالْوَتْرِ"},{"id":"c","text":"وَالشَّمْسِ"},{"id":"d","text":"وَالْقَمَرِ"}]'::jsonb, 'b', 'الآية الثالثة هي: وَالشَّفْعِ وَالْوَتْرِ، أقسم اللهُ بهما؛ الشَّفع العدد الزوجي، والوَتر العدد الفردي.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6fef11db-c4e1-5dfc-99b1-38df62ca8964', 'ea2c872e-0f3c-5592-8bb8-03edd3ed1665', '«فِرْعَوْنَ ذِي الْأَوْتَادِ» ذكرته السورةُ مع عادٍ وثمودَ لأنّه ...', '[{"id":"a","text":"كان نبيًّا صالحًا"},{"id":"b","text":"كان فقيرًا ضعيفًا"},{"id":"c","text":"بنى الكعبة"},{"id":"d","text":"طغى وأكثر الفساد فأهلكه الله"}]'::jsonb, 'd', 'ذُكر فرعونُ مع عادٍ وثمودَ لأنّه طغى وأكثر الفساد، فأهلكه اللهُ كما أهلك الأمم الظالمة. الخطأ الشائع ظنّ أنّ قوّته نجّته من عقاب الله.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d1bd1b36-8542-5013-b00c-30586eef8c44', 'ea2c872e-0f3c-5592-8bb8-03edd3ed1665', 'معنى «دُكَّتِ الْأَرْضُ دَكًّا دَكًّا» يوم القيامة أنّ الأرض ...', '[{"id":"a","text":"زُلزلت ودُقَّت حتّى تُسوّى"},{"id":"b","text":"صارت خضراء"},{"id":"c","text":"بقيت كما هي"},{"id":"d","text":"امتلأت بالأموال"}]'::jsonb, 'a', 'دُكَّتِ الأرضُ دَكًّا دَكًّا أي زُلزلت ودُقَّت حتّى تُسوّى، وهذا من أهوال يوم القيامة. الخطأ الشائع فهمُ الآية على غير معناها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd705097-fa3b-59d2-80a3-08dfb304a584', 'ea2c872e-0f3c-5592-8bb8-03edd3ed1665', 'تلميذٌ يريد أن يكون من «النفس المطمئنّة» التي بشّرها اللهُ بالجنّة. ماذا يفعل؟', '[{"id":"a","text":"يجمع المالَ فقط"},{"id":"b","text":"يؤمن بربّه ويرضى به ويعمل صالحًا في الدنيا"},{"id":"c","text":"يستهزئ باليتيم"},{"id":"d","text":"ينتظر القيامة دون عمل"}]'::jsonb, 'b', 'النفسُ المطمئنّة هي المؤمنةُ الراضيةُ بربّها؛ فمن أراد أن يكون منها آمن بربّه ورضِيَ به وعمل صالحًا في الدنيا. الخطأ الشائع تأجيلُ العمل الصالح.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2bad1b16-281d-5844-87fd-3e26c60de8b4', 'ea2c872e-0f3c-5592-8bb8-03edd3ed1665', 'ما الرسالةُ التي نأخذها من سورة الفجر؟', '[{"id":"a","text":"نُحبّ المالَ حبًّا شديدًا"},{"id":"b","text":"نُقلّد الظالمين"},{"id":"c","text":"نستخفّ بحقّ المسكين"},{"id":"d","text":"نعرف عظمة الله من مخلوقاته، ونعتبر بمصير الظالمين، ونُكرم اليتيمَ والمسكين"}]'::jsonb, 'd', 'نعمل بالسورة: نعرف عظمة الله وقدرته من مخلوقاته فنعبده وحده، ونعتبر بمصير عادٍ وثمودَ وفرعون، ونُكرم اليتيمَ والمسكين. الخطأ الشائع الغفلةُ عن دروس السورة وعدمُ العمل بها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

