  ('0327bd63-173d-530f-86aa-d63f44476182', '0a1c116c-29da-5890-a5d4-9d4630088438', 'education-islamique-4eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
