INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7fa1bdd9-2d77-5854-962c-ce9a9488dffc', '0327bd63-173d-530f-86aa-d63f44476182', 'مَن هما الوالدان؟', '[{"id":"a","text":"الجدّ والجدّة"},{"id":"b","text":"الأب والأمّ"},{"id":"c","text":"الأخ والأخت"},{"id":"d","text":"الجيران"}]'::jsonb, 'b', 'الوالدان هما الأب والأمّ اللذان ربّياك صغيرًا، أمّا الجدّ والجدّة فهما من الأجداد.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
