  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bbc56fc9-b645-59c4-8923-36a5a29d7ed2', '0327bd63-173d-530f-86aa-d63f44476182', 'بماذا أمرَنا الله في قوله: «وَبِالْوَالِدَيْنِ إِحْسَانًا»؟', '[{"id":"a","text":"بهجر الوالدين"},{"id":"b","text":"بطاعة الجيران"},{"id":"c","text":"بكثرة اللّعب"},{"id":"d","text":"بالإحسان إلى الوالدين"}]'::jsonb, 'd', 'قال الله: «وَقَضَىٰ رَبُّكَ أَلَّا تَعْبُدُوا إِلَّا إِيَّاهُ وَبِالْوَالِدَيْنِ إِحْسَانًا»، فأمرَنا بالإحسان إلى الوالدين بعد عبادته مباشرة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('74adee38-4dfa-501e-919f-1f6fbc10a090', '0327bd63-173d-530f-86aa-d63f44476182', 'حين تطلب منك أمُّك المساعدة في البيت، ماذا تفعل؟', '[{"id":"a","text":"أُسرع إلى مساعدتها بفرح"},{"id":"b","text":"أتجاهلها وأُكمل اللّعب"},{"id":"c","text":"أقول لها: أُفٍّ"},{"id":"d","text":"أخرج من البيت"}]'::jsonb, 'a', 'من برّ الوالدين أن نُسرع إلى مساعدتهما بفرح؛ فالبرّ عملٌ لا كلامٌ فقط.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('df766335-3091-5959-a257-cd07ca7c15e3', '0327bd63-173d-530f-86aa-d63f44476182', 'في قوله: «وَقُل رَّبِّ ارْحَمْهُمَا كَمَا رَبَّيَانِي صَغِيرًا»، بماذا أمَرَنا الله تجاه الوالدين؟', '[{"id":"a","text":"أن نتركهما"},{"id":"b","text":"أن نرفع أصواتنا عليهما"},{"id":"c","text":"أن ندعو الله لهما بالرّحمة"},{"id":"d","text":"أن نطلب منهما المال"}]'::jsonb, 'c', 'أمرَنا الله أن ندعو لوالدينا بالرّحمة ونذكر أنّهما ربّيانا صغارًا. الخطأ الشائع نسيانُ الدّعاء لهما.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7b3d6861-1afd-5700-a18b-908bf798f11e', '0327bd63-173d-530f-86aa-d63f44476182', 'قال النبيّ ﷺ لمن سأله مَن أحقُّ النّاس بحُسن الصّحبة، فمن ذكَرَ أوّلًا؟', '[{"id":"a","text":"الجارَ"},{"id":"b","text":"الأمَّ"},{"id":"c","text":"الصّديقَ"},{"id":"d","text":"المعلّمَ"}]'::jsonb, 'b', 'قال ﷺ: «أُمُّكَ» ثلاث مرّات ثمّ «أَبُوكَ» (رواه البخاري ومسلم)، فجعل للأمّ ثلاثةَ أضعاف لِعِظَم تعبها.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

