INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cea4d479-e5c4-575d-9f64-43ac3d39a54d', '55a2c720-8340-5f33-b913-376ce38794c7', 'الجدّ والجدّة هما من ...', '[{"id":"a","text":"الجيران"},{"id":"b","text":"الأصدقاء"},{"id":"c","text":"الأجداد"},{"id":"d","text":"المعلّمين"}]'::jsonb, 'c', 'الأجداد هم آباء الوالدين وأمّهاتهم، أي الجدّ والجدّة.', 1)
