INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c8a190cb-7b32-5409-b15d-758a984c580b', '55a2c720-8340-5f33-b913-376ce38794c7', 'أمرَنا الله بالإحسان إلى الوالدين بعد ...', '[{"id":"a","text":"عبادته وحده"},{"id":"b","text":"اللّعب"},{"id":"c","text":"النّوم"},{"id":"d","text":"الأكل"}]'::jsonb, 'a', 'قال الله: «أَلَّا تَعْبُدُوا إِلَّا إِيَّاهُ وَبِالْوَالِدَيْنِ إِحْسَانًا»، فقَرَنَ الإحسانَ إلى الوالدين بعبادته مباشرة.', 2)
