INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2bb04a3e-ecaf-54be-bccf-e5073ee9ecd8', '55a2c720-8340-5f33-b913-376ce38794c7', 'حين يتحدّث إليك جدُّك، فإنّك ...', '[{"id":"a","text":"تقاطعه"},{"id":"b","text":"تنشغل عنه بهاتفك"},{"id":"c","text":"تخرج من الغرفة"},{"id":"d","text":"تُنصِت إليه باحترام"}]'::jsonb, 'd', 'من الإحسان إلى الأجداد أن نُنصِت إليهم باحترامٍ ولا نقاطعهم.', 3)
