INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0baf721f-c148-5a70-99bc-5e8623872672', '55a2c720-8340-5f33-b913-376ce38794c7', 'إذا طلب منك والداك شيئًا، فالكلامُ الطّيّب أن تقول ...', '[{"id":"a","text":"أُفٍّ"},{"id":"b","text":"نعم بلطف"},{"id":"c","text":"لا أريد"},{"id":"d","text":"اتركاني"}]'::jsonb, 'b', 'نُجيب والدينا بلطفٍ وكلامٍ ليّن، فنقول «نعم»، ولا نقول لهما «أُفٍّ».', 4)
