INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('685071ec-c1a1-504b-b0d8-30f9932a0fa7', '55a2c720-8340-5f33-b913-376ce38794c7', 'مَن سهِرت اللّيالي على راحتك حين كنت صغيرًا؟', '[{"id":"a","text":"أمُّك"},{"id":"b","text":"جارُك"},{"id":"c","text":"صديقُك"},{"id":"d","text":"معلّمُك"}]'::jsonb, 'a', 'الأمّ حملتك وأرضعتك وسهِرت على راحتك حين كنت صغيرًا، فلها فضلٌ عظيم.', 5)
