INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cf012626-58aa-52ed-a49c-86a558cf7f3a', '0d50e695-03e2-5508-9242-a2fcb12ccc06', 'في سورة الإسراء قَرَنَ الله الإحسانَ إلى الوالدين بـ ...', '[{"id":"a","text":"حبّ المال"},{"id":"b","text":"كثرة الطّعام"},{"id":"c","text":"اللّعب مع الأصدقاء"},{"id":"d","text":"عبادته وحده لا شريك له"}]'::jsonb, 'd', 'قال الله: «أَلَّا تَعْبُدُوا إِلَّا إِيَّاهُ وَبِالْوَالِدَيْنِ إِحْسَانًا»، فجعل برّ الوالدين بعد التّوحيد مباشرة. الخطأ الشائع التّهوينُ من شأن برّ الوالدين.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('22c00776-46e3-57d4-a3d0-1bbed93cad1f', '0d50e695-03e2-5508-9242-a2fcb12ccc06', 'أمرَك أبوك بأمرٍ فيه خيرٌ وأنت مشغولٌ باللّعب، فالأصحّ أن ...', '[{"id":"a","text":"تتجاهله حتّى تنتهي"},{"id":"b","text":"تقول له: أُفٍّ"},{"id":"c","text":"تُطيعه ولا تتكاسل"},{"id":"d","text":"تخرج من البيت"}]'::jsonb, 'c', 'نُطيع الوالدين في المعروف ولا نتكاسل عن أمرهما. الخطأ الشائع تقديمُ اللّعب على طاعة الوالدين.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('32b69fc0-00e0-5c11-b74f-50054135c7c3', '0d50e695-03e2-5508-9242-a2fcb12ccc06', 'معنى «وَاخْفِضْ لَهُمَا جَنَاحَ الذُّلِّ مِنَ الرَّحْمَةِ» هو ...', '[{"id":"a","text":"أن نبتعد عنهما"},{"id":"b","text":"أن نتواضع لهما ونرحمهما"},{"id":"c","text":"أن نرفع صوتنا عليهما"},{"id":"d","text":"أن نطلب منهما الهدايا"}]'::jsonb, 'b', 'معناها أن نتواضع للوالدين ونكون ليّنين رحيمين معهما، كما يخفض الطّائرُ جناحه على صغاره. الخطأ الشائع فهمُ «الذُّلّ» على أنّه إهانة، وإنّما هو تواضعُ الرّحمة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4a562dfe-2a66-582a-965c-420ac11ea145', '0d50e695-03e2-5508-9242-a2fcb12ccc06', 'أمَرَ والدٌ ابنَه بأمرٍ فيه معصيةٌ لله (كترك الصلاة). ما الصّواب؟', '[{"id":"a","text":"لا يُطيعه في المعصية ويبقى معه بالكلام الطّيّب"},{"id":"b","text":"يُطيعه لأنّه أبوه مهما أمَر"},{"id":"c","text":"يُسيء إليه ويهجره"},{"id":"d","text":"يترك الصلاة طاعةً له"}]'::jsonb, 'a', 'لا طاعةَ لمخلوقٍ في معصية الخالق، لكن نبقى مع الوالدين بالكلام الطّيّب والمعاملة الحسنة. الخطأ الشائع ظنُّ أنّ ترك البرّ يكون بالإساءة، والصّواب أنّ البرّ يبقى مع ترك المعصية.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0bbea1c8-a56f-5ea1-8a44-a40ef8ac1e67', '0d50e695-03e2-5508-9242-a2fcb12ccc06', 'قال النبيّ ﷺ: «رِضَا الرَّبِّ فِي رِضَا الْوَالِدِ»، فماذا نفهم منه؟', '[{"id":"a","text":"أنّ رضا الوالد لا قيمة له"},{"id":"b","text":"أنّ الله يغضب إذا أرضينا والدينا"},{"id":"c","text":"أنّ البرّ يكون بالمال فقط"},{"id":"d","text":"أنّنا إذا أرضينا والدينا أرضينا ربّنا"}]'::jsonb, 'd', 'رضا الله مرتبطٌ برضا الوالد، فمن أرضى والديه أرضى ربّه. الخطأ الشائع التّقليلُ من أثر رضا الوالدين عند الله.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('456fe0c3-450a-5025-9404-ab1692cd52ee', '0d50e695-03e2-5508-9242-a2fcb12ccc06', 'لماذا ذكَرَ النبيُّ ﷺ الأمَّ ثلاث مرّات قبل الأب في حُسن الصّحبة؟', '[{"id":"a","text":"لأنّ الأب لا حقّ له"},{"id":"b","text":"لِعِظَم تعب الأمّ في الحمل والإرضاع والتّربية"},{"id":"c","text":"لأنّها أكبر سنًّا"},{"id":"d","text":"لأنّها تعطي المال"}]'::jsonb, 'b', 'خصّ النبيّ ﷺ الأمّ بثلاثة أضعاف لِعِظَم ما تتحمّله من الحمل والإرضاع والسّهر، ثمّ يأتي حقّ الأب. الخطأ الشائع إهمالُ تقدير تعب الأمّ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

