  ('c118cb85-ee92-57e8-9a29-1ed0714eea45', '0a1c116c-29da-5890-a5d4-9d4630088438', 'education-islamique-4eme', '⭐⭐ تمرين مراجعة: برّ الوالدين والأجداد (نمط امتحان)', 2, 75, 15, 'practice', 'admin', 3)
