INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('daa54cbf-6cbd-50d1-84c5-e13d515a350d', 'c118cb85-ee92-57e8-9a29-1ed0714eea45', 'الأجداد هم ...', '[{"id":"a","text":"إخوتك وأخواتك"},{"id":"b","text":"آباء الوالدين وأمّهاتهم"},{"id":"c","text":"أصدقاء المدرسة"},{"id":"d","text":"جيران الحيّ"}]'::jsonb, 'b', 'الأجداد هم آباء الوالدين وأمّهاتهم: الجدّ والجدّة.', 1)
ON CONFLICT (id) DO UPDATE SET
