INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c391a49b-b13c-5e25-b4b3-083ec90a0405', 'c118cb85-ee92-57e8-9a29-1ed0714eea45', 'الآية «وَقَضَىٰ رَبُّكَ أَلَّا تَعْبُدُوا إِلَّا إِيَّاهُ وَبِالْوَالِدَيْنِ إِحْسَانًا» من سورة ...', '[{"id":"a","text":"الفاتحة"},{"id":"b","text":"الأعلى"},{"id":"c","text":"الإسراء"},{"id":"d","text":"الناس"}]'::jsonb, 'c', 'هذه الآية 23 من سورة الإسراء، أمرَنا الله فيها بعبادته وبالإحسان إلى الوالدين.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c4f4a0f3-016d-5d57-956a-3ad3e5b3fad7', 'c118cb85-ee92-57e8-9a29-1ed0714eea45', '«وَقُل رَّبِّ ارْحَمْهُمَا كَمَا رَبَّيَانِي صَغِيرًا» دعاءٌ نقوله لِـ ...', '[{"id":"a","text":"الوالدين"},{"id":"b","text":"الأعداء"},{"id":"c","text":"أنفسنا فقط"},{"id":"d","text":"الجيران"}]'::jsonb, 'a', 'هو دعاءٌ نرفعه إلى الله لوالدينا بالرّحمة، لأنّهما ربّيانا حين كنّا صغارًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e1ee80aa-6e5a-5382-bb4f-b200caae02f4', 'c118cb85-ee92-57e8-9a29-1ed0714eea45', 'من برّ الجدّ والجدّة ...', '[{"id":"a","text":"نسيانهما"},{"id":"b","text":"رفع الصّوت عليهما"},{"id":"c","text":"الانشغال عنهما دائمًا"},{"id":"d","text":"زيارتهما والسّؤال عن صحّتهما"}]'::jsonb, 'd', 'من الإحسان إلى الأجداد زيارتُهم والسّؤال عن صحّتهم والإنصاتُ إليهم باحترام.', 4)
