INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4fa8de7d-b31b-5ef1-b311-0c2c4425fd86', 'c118cb85-ee92-57e8-9a29-1ed0714eea45', 'حين نخطئ في حقّ والدينا، فالأصحّ أن ...', '[{"id":"a","text":"نُصرّ على الخطأ"},{"id":"b","text":"نعتذر إليهما"},{"id":"c","text":"نهرب من البيت"},{"id":"d","text":"نتجاهل الأمر"}]'::jsonb, 'b', 'من البرّ أن نعتذر لوالدينا عند الخطأ ونعود إلى الكلام الطّيّب والمعاملة الحسنة.', 5)
