INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('53862bf0-fe2e-5e2d-909c-f76cae6a7d52', 'c118cb85-ee92-57e8-9a29-1ed0714eea45', 'قال النبيّ ﷺ لمن سأله مَن أحقُّ بحُسن الصّحبة فأجاب: «أُمُّكَ» ثلاثًا ثمّ ...', '[{"id":"a","text":"جارُك"},{"id":"b","text":"صديقُك"},{"id":"c","text":"أَبُوكَ"},{"id":"d","text":"معلّمُك"}]'::jsonb, 'c', 'قال ﷺ: «أُمُّكَ» ثلاث مرّات ثمّ «أَبُوكَ» (رواه البخاري ومسلم)، فبعد الأمّ يأتي حقّ الأب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
