INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7d0892ac-3be6-5831-ab35-9802d6282fb4', '9c3619af-db3b-5348-b38c-045725b4168e', 'تعبَت أمٌّ في إعداد الطّعام ثمّ طلبت من ابنها أن يساعدها في ترتيب المائدة، فقام مسرعًا وساعدها وابتسم لها. بأيّ خُلُقٍ عمِل هذا الابن؟', '[{"id":"a","text":"بالكسل"},{"id":"b","text":"ببرّ الوالدين والإحسان إليهما"},{"id":"c","text":"بالعقوق"},{"id":"d","text":"بالأنانيّة"}]'::jsonb, 'b', 'مساعدةُ الأمّ بفرحٍ وابتسامة من برّ الوالدين والإحسان إليهما. الخطأ الشائع ظنُّ أنّ المساعدة في البيت ليست عبادة، وهي من أعظم البرّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b52e8f6-aa54-5dce-b42f-17fea30f527b', '9c3619af-db3b-5348-b38c-045725b4168e', 'أراد تلميذٌ أن يُعبّر عن حبّه لوالديه بعملٍ صحيح. أيُّ هذه الأعمال هو التّعبير الصّحيح؟', '[{"id":"a","text":"أن يرفع صوته عليهما"},{"id":"b","text":"أن يتجاهل طلبهما"},{"id":"c","text":"أن ينساهما إذا كبِرا"},{"id":"d","text":"أن يبتسم لهما ويدعو لهما ويُقبّل رأسيهما"}]'::jsonb, 'd', 'التّعبير عن محبّة الوالدين يكون بالابتسامة والدّعاء وتقبيل الرّأس والمعاملة الحسنة. الخطأ الشائع حصرُ المحبّة في الكلام دون العمل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ecfb6deb-4d54-583e-bbe2-3048b10b528c', '9c3619af-db3b-5348-b38c-045725b4168e', 'جلس جدٌّ كبيرٌ يحدّث حفيدَه عن ذكرياته، فأنصت إليه الحفيد باحترامٍ ولم يقاطعه ولم ينشغل عنه. ما اسمُ هذا العمل؟', '[{"id":"a","text":"الإحسان إلى الأجداد"},{"id":"b","text":"إضاعة الوقت"},{"id":"c","text":"قسوةُ القلب"},{"id":"d","text":"قطيعةُ الرّحم"}]'::jsonb, 'a', 'الإنصاتُ إلى الجدّ باحترامٍ وعدمُ مقاطعته من الإحسان إلى الأجداد. الخطأ الشائع الاستهانةُ بمجالسة الكبار والإنصاتِ إليهم.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('488cd756-a6c9-5805-98f9-7d3265f9991e', '9c3619af-db3b-5348-b38c-045725b4168e', 'كبِرَ والدا تلميذٍ وضعُفا، فصار يتكلّم معهما بلينٍ ورحمةٍ ويدعو: «ربِّ ارحمهما كما ربّياني صغيرًا». بأيّ آيةٍ اقتدى؟', '[{"id":"a","text":"بآيةٍ في حبّ المال"},{"id":"b","text":"بآيةٍ في اللّعب"},{"id":"c","text":"بآيةٍ في الطّعام"},{"id":"d","text":"بقوله: «وَاخْفِضْ لَهُمَا جَنَاحَ الذُّلِّ مِنَ الرَّحْمَةِ وَقُل رَّبِّ ارْحَمْهُمَا كَمَا رَبَّيَانِي صَغِيرًا»"}]'::jsonb, 'd', 'هذا عملٌ بآية 24 من سورة الإسراء التي تأمر بالتّواضع للوالدين والرّحمة بهما والدّعاء لهما. الخطأ الشائع نسيانُ الدّعاء للوالدين عند كِبَرهما.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('52b477a0-5e03-5c43-aed5-e25bc85b2556', '9c3619af-db3b-5348-b38c-045725b4168e', 'أمَرَ أبٌ ابنَه أن يكذب على جارهم لِيُخفي عنه أمرًا، فاعتذر الابن بلطفٍ ولم يكذب، وبقي مع أبيه بالكلام الطّيّب. ما حُكمُ تصرّفه؟', '[{"id":"a","text":"أخطأ لأنّه لم يُطع أباه"},{"id":"b","text":"كان عليه أن يكذب طاعةً للأب"},{"id":"c","text":"أحسنَ: لا طاعةَ في معصية الله مع بقاء حُسن المعاملة"},{"id":"d","text":"كان عليه أن يهجر أباه"}]'::jsonb, 'c', 'لا نُطيع الوالدين في معصية الله كالكذب، لكن نبقى معهما بالأدب والكلام الطّيّب. الخطأ الشائع الخلطُ بين عدم الطّاعة في المعصية وبين الإساءة إلى الوالدين.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('64974891-bd42-5f4a-aac7-4abea59aca0c', '9c3619af-db3b-5348-b38c-045725b4168e', 'توفّيت أمُّ تلميذٍ، فصار يدعو لها ويتصدّق عنها ويصِل أقاربها. هل يُعدّ هذا برًّا بها بعد موتها؟', '[{"id":"a","text":"نعم، البرُّ يستمرّ بعد الموت بالدّعاء والصّدقة"},{"id":"b","text":"لا، انقطع البرّ بموتها"},{"id":"c","text":"لا فائدة في الدّعاء للأموات"},{"id":"d","text":"البرُّ يكون في الحياة فقط"}]'::jsonb, 'a', 'من برّ الوالدين بعد موتهما الدّعاءُ لهما والصّدقةُ عنهما وصلةُ أقاربهما. الخطأ الشائع ظنُّ أنّ البرّ ينقطع بموت الوالدين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

