INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ae979d00-3306-5f4b-b98a-d2f54f277618', 'a2defd48-6675-5b72-a6aa-419933133baf', 'أعظمُ النّاس حقًّا عليك بعد الله ورسوله ﷺ هما ...', '[{"id":"a","text":"الجيران"},{"id":"b","text":"الأصدقاء"},{"id":"c","text":"الوالدان"},{"id":"d","text":"زملاء المدرسة"}]'::jsonb, 'c', 'الوالدان أعظمُ النّاس حقًّا علينا بعد الله ورسوله ﷺ، ثمّ يأتي الأجداد.', 1)
ON CONFLICT (id) DO UPDATE SET
