INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e8c67900-de57-50a6-a5f1-7f5ab7796ab2', 'a2defd48-6675-5b72-a6aa-419933133baf', 'في قوله: «وَبِالْوَالِدَيْنِ إِحْسَانًا»، معنى «إِحْسَانًا» ...', '[{"id":"a","text":"الإساءة إليهما"},{"id":"b","text":"هجرهما"},{"id":"c","text":"نسيانهما"},{"id":"d","text":"أن نُحسن إليهما ونعاملهما أحسن معاملة"}]'::jsonb, 'd', '«إِحْسَانًا» أي أن نُحسن إلى الوالدين بأحسن المعاملة والطّاعة في المعروف. الخطأ الشائع فهمُ الآية فهمًا معكوسًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('af20b7ba-1550-5098-9c80-f6695a8dc0e2', 'a2defd48-6675-5b72-a6aa-419933133baf', 'قال النبيّ ﷺ: «رِضَا الرَّبِّ فِي ...»', '[{"id":"a","text":"رِضَا الْوَالِدِ"},{"id":"b","text":"كثرة المال"},{"id":"c","text":"كثرة اللّعب"},{"id":"d","text":"النّوم الطّويل"}]'::jsonb, 'a', 'قال ﷺ: «رِضَا الرَّبِّ فِي رِضَا الْوَالِدِ، وَسَخَطُ الرَّبِّ فِي سَخَطِ الْوَالِدِ» (رواه الترمذي)، فرضا الوالدين سببٌ لرضا الله.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6db392fa-229d-57d6-a249-ae0f4c6809b1', 'a2defd48-6675-5b72-a6aa-419933133baf', 'نُطيع الوالدين والأجداد في ...', '[{"id":"a","text":"كلّ شيءٍ حتّى المعصية"},{"id":"b","text":"كلّ معروفٍ وخير"},{"id":"c","text":"اللّعب فقط"},{"id":"d","text":"لا نُطيعهما أبدًا"}]'::jsonb, 'b', 'نُطيع الوالدين والأجداد في كلّ معروفٍ وخير، ولا نُطيعهما في معصية الله. الخطأ الشائع الطّاعةُ في كلّ شيءٍ حتّى المعصية.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5ed0438e-3866-513f-8da7-db2b612209ba', 'a2defd48-6675-5b72-a6aa-419933133baf', 'بدأ تلميذٌ يقول لوالدته كلّما طلبت منه شيئًا: «أُفٍّ». ما الخطأ في تصرّفه؟', '[{"id":"a","text":"لا خطأ، هذا كلامٌ عاديّ"},{"id":"b","text":"كان عليه أن يصرخ أكثر"},{"id":"c","text":"أساء الأدبَ، والصّوابُ أن يُجيب بكلامٍ ليّن"},{"id":"d","text":"كان عليه أن يتجاهلها"}]'::jsonb, 'c', 'قول «أُفٍّ» للوالدين إساءةُ أدب؛ والصّواب أن نُجيبهما بكلامٍ ليّنٍ طيّب. الخطأ الشائع الاستهانةُ بالكلمة القاسية مع الوالدين.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f2e0768b-bd7a-5bdb-acc3-3e3e0abff719', 'a2defd48-6675-5b72-a6aa-419933133baf', 'لماذا جعل النبيُّ ﷺ حقَّ الأمّ ثلاثةَ أضعاف قبل الأب؟', '[{"id":"a","text":"لِعِظَم تعبها في الحمل والإرضاع والتّربية"},{"id":"b","text":"لأنّها تعطي المال"},{"id":"c","text":"لأنّ الأب لا حقّ له"},{"id":"d","text":"لأنّها أطول عمرًا"}]'::jsonb, 'a', 'خصّ النبيّ ﷺ الأمّ بثلاثة أضعاف لِعِظَم تعبها في الحمل والإرضاع والسّهر، ثمّ يأتي حقّ الأب. الخطأ الشائع التّقليلُ من تعب الأمّ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

