INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('53d2ca4a-7ada-5e82-b41d-2c8b35265d02', '79a6fb75-a868-5251-9ffd-cc927482365a', 'ما أوّلُ كلمةٍ نزلت من القرآن الكريم في سورة العلق؟', '[{"id":"a","text":"صلِّ"},{"id":"b","text":"اقرأ"},{"id":"c","text":"قُم"},{"id":"d","text":"اكتب"}]'::jsonb, 'b', 'بدأ الوحيُ بقوله تعالى «اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ»، فأوّلُ كلمةٍ نزلت هي «اقرأ»، وفيها دعوةٌ إلى العلم والقراءة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
