  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a2f6254-2500-52b3-af70-44d3c933d236', '79a6fb75-a868-5251-9ffd-cc927482365a', 'قال النبيُّ ﷺ: «ومَن سلك طريقًا يلتمسُ فيه علمًا، سهّلَ الله له به طريقًا إلى ...»', '[{"id":"a","text":"السوق"},{"id":"b","text":"البيت"},{"id":"c","text":"اللعب"},{"id":"d","text":"الجنّة"}]'::jsonb, 'd', 'في حديث مسلم: «سهّلَ الله له به طريقًا إلى الجنّة»، فطلبُ العلمِ طريقٌ يقرّب صاحبَه من الجنّة ورضا الله.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83816223-be42-5116-a8e0-038144be9fe8', '79a6fb75-a868-5251-9ffd-cc927482365a', 'بماذا يُنالُ العلمُ؟', '[{"id":"a","text":"بالكسلِ والنوم"},{"id":"b","text":"باللعبِ فقط"},{"id":"c","text":"بالاجتهادِ والمثابرة"},{"id":"d","text":"بالغشِّ في الامتحان"}]'::jsonb, 'c', 'العلمُ لا يُنالُ بالكسل، بل بالاجتهادِ والمثابرة، أي بمواصلةِ العملِ وعدمِ اليأسِ ولو كان الدرسُ صعبًا.', 3)
