  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a96b07bd-7a49-599d-92bb-88b135be53d3', '79a6fb75-a868-5251-9ffd-cc927482365a', 'من آدابِ طالبِ العلم أن يُحسنَ ...', '[{"id":"a","text":"الإصغاءَ للمعلّمِ دون مقاطعة"},{"id":"b","text":"النومَ في القسم"},{"id":"c","text":"الكلامَ مع زميله أثناء الدرس"},{"id":"d","text":"اللعبَ بالأدوات"}]'::jsonb, 'a', 'من آدابِ طالبِ العلمِ الإصغاءُ للمعلّمِ باهتمامٍ دون مقاطعة، فالإصغاءُ بابُ الفهم.', 4)
