INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('69b86a44-f372-5068-a54b-ba0df451f56d', '79a6fb75-a868-5251-9ffd-cc927482365a', 'ماذا نفعلُ إذا لم نفهمْ شيئًا في الدرس؟', '[{"id":"a","text":"نسكتُ ونتركُ الدرسَ كلّه"},{"id":"b","text":"نغضبُ ونخرجُ من القسم"},{"id":"c","text":"ننتظرُ حتّى ننساه"},{"id":"d","text":"نسألُ المعلّمَ بأدبٍ عمّا لم نفهمه"}]'::jsonb, 'd', 'من آدابِ طالبِ العلمِ السؤالُ بأدبٍ عمّا أشكلَ علينا دون خجل، فالسؤالُ يفتحُ لنا ما أُغلق علينا من الفهم.', 5)
