INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('16fd9c68-64e2-5b14-91f0-9fdb2460e736', 'fb2fcef8-7d1d-5476-95df-a660bc2642b9', 'تلميذٌ وجد درسَ الحسابِ صعبًا، فهل الأفضلُ أن يستسلمَ أم يثابر؟', '[{"id":"a","text":"يتركُ الحسابَ نهائيًّا"},{"id":"b","text":"يبكي ويغضب"},{"id":"c","text":"ينتظرُ أن يفهمَ وحده دون عمل"},{"id":"d","text":"يثابرُ ويُعيدُ المحاولةَ ويسألُ معلّمه"}]'::jsonb, 'd', 'المثابرةُ أن نواصلَ ولا نيأس، فيُعيدُ المحاولةَ ويسألُ ويراجع حتّى يفهم. الخطأ الشائع الاستسلامُ عند أوّل صعوبة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b54fb5d-43d8-5cd8-8853-b011c8f4ccc7', 'fb2fcef8-7d1d-5476-95df-a660bc2642b9', 'قال النبيُّ ﷺ إنّ مَن سلك طريقًا يطلبُ فيه العلمَ، سهّلَ الله له طريقًا إلى ...', '[{"id":"a","text":"المال"},{"id":"b","text":"الجنّة"},{"id":"c","text":"اللعب"},{"id":"d","text":"الراحةِ في الدنيا فقط"}]'::jsonb, 'b', 'في حديث مسلم: «سهّلَ الله له به طريقًا إلى الجنّة». الخطأ الشائع ظنُّ أنّ ثمرةَ العلمِ دنيويّةٌ فقط، بل أعظمُها رضا الله والجنّة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5230797c-3561-5ffe-8dea-bca1aae5c8f1', 'fb2fcef8-7d1d-5476-95df-a660bc2642b9', 'تلميذٌ يقاطعُ معلّمَه كلّما تكلّم. أيُّ أدبٍ من آدابِ العلمِ أخلَّ به؟', '[{"id":"a","text":"الصدق"},{"id":"b","text":"النظام"},{"id":"c","text":"الإصغاء"},{"id":"d","text":"المراجعة"}]'::jsonb, 'c', 'الإصغاءُ أن نُنصتَ للمعلّمِ دون مقاطعة، وهو بابُ الفهم. الخطأ الشائع ظنُّ أنّ كثرةَ الكلامِ علامةُ نشاط، بل الإصغاءُ أولى.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1e3566b5-7e5e-545d-bdd7-9a99a440913d', 'fb2fcef8-7d1d-5476-95df-a660bc2642b9', 'ما الدعاءُ الذي نقولُه لنطلبَ من الله الزيادةَ في العلم؟', '[{"id":"a","text":"ربِّ أعطني مالًا"},{"id":"b","text":"ربِّ زِدني علمًا"},{"id":"c","text":"ربِّ أرحني من الدرس"},{"id":"d","text":"ربِّ قصّرِ النهار"}]'::jsonb, 'b', 'ندعو الله أن يزيدَنا علمًا فنقول «ربِّ زِدني علمًا». الخطأ الشائع طلبُ الراحةِ من التعلّمِ بدل طلبِ الزيادةِ فيه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03cf4e1a-0f8e-512b-95c4-7897ac368393', 'fb2fcef8-7d1d-5476-95df-a660bc2642b9', 'تلميذٌ لم يفهمْ مسألةً، فخجلَ أن يسأل وبقيَ ساكتًا. ما الأصوبُ أن يفعل؟', '[{"id":"a","text":"يسألُ المعلّمَ بأدبٍ عمّا لم يفهمه"},{"id":"b","text":"يتركُ المسألةَ وينساها"},{"id":"c","text":"ينقلُ الجوابَ من زميله غشًّا"},{"id":"d","text":"يغضبُ من المعلّم"}]'::jsonb, 'a', 'السؤالُ بأدبٍ أدبٌ من آدابِ العلمِ يفتحُ ما أُغلق علينا. الخطأ الشائع الخجلُ من السؤالِ فيبقى الجهلُ، أو اللجوءُ إلى الغشّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5afe65f0-ceed-513d-871e-e6d9413e094f', 'fb2fcef8-7d1d-5476-95df-a660bc2642b9', 'تلميذٌ نقل أجوبةَ الواجبِ من كتابِ الحلولِ دون أن يفهم. لماذا هذا خطأ؟', '[{"id":"a","text":"لأنّه تعبَ كثيرًا"},{"id":"b","text":"لأنّ الواجبَ طويل"},{"id":"c","text":"لا خطأ في ذلك"},{"id":"d","text":"لأنّه غشٌّ وتركٌ للصدقِ ولم يتعلّمْ شيئًا"}]'::jsonb, 'd', 'الصدقُ من آدابِ العلم: نُنجزُ واجباتِنا بأنفسنا ولا نغشّ، فالغشُّ يمنعُ الفهمَ والبركة. الخطأ الشائع ظنُّ أنّ المهمَّ إتمامُ الواجبِ ولو بالغشّ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('0fb64f4f-950a-5735-bb06-f31332dc43d9', 'f02dfd48-0526-55c4-8460-3fc8537ee62a', 'education-islamique-4eme', '⭐⭐ تمرين مراجعة: الاجتهاد في طلب العلم (نمط امتحان)', 2, 75, 15, 'practice', 'admin', 3)
