INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a7339f43-46ad-5edb-b352-75efc9cda8bb', '0fb64f4f-950a-5735-bb06-f31332dc43d9', 'بأيّ كلمةٍ بدأ الوحيُ على النبيّ ﷺ في سورة العلق؟', '[{"id":"a","text":"بسم"},{"id":"b","text":"الحمد"},{"id":"c","text":"اقرأ"},{"id":"d","text":"قُل"}]'::jsonb, 'c', 'بدأ الوحيُ بقوله تعالى «اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ»، فأوّلُ كلمةٍ نزلت هي «اقرأ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1e6e80bb-4be5-5150-b44b-b403115fdfde', '0fb64f4f-950a-5735-bb06-f31332dc43d9', 'المثابرةُ في طلبِ العلمِ معناها ...', '[{"id":"a","text":"أن نواصلَ العملَ ولا نيأسَ ولو كان صعبًا"},{"id":"b","text":"أن نتركَ الدرسَ إذا تعبنا"},{"id":"c","text":"أن نلعبَ بدل الدرس"},{"id":"d","text":"أن ننامَ في القسم"}]'::jsonb, 'a', 'المثابرةُ أن نواصلَ العملَ ولا نيأسَ ولو كان الدرسُ صعبًا، فهي تصنعُ من الصعبِ سهلًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f870ba04-1853-5bb6-809e-0dc4988e1021', '0fb64f4f-950a-5735-bb06-f31332dc43d9', 'ثمرةُ طلبِ العلمِ كما في حديثِ النبيّ ﷺ أنّ الله يُسهّلُ لطالبه طريقًا إلى ...', '[{"id":"a","text":"الراحة"},{"id":"b","text":"السوق"},{"id":"c","text":"اللعب"},{"id":"d","text":"الجنّة"}]'::jsonb, 'd', 'قال ﷺ: «سهّلَ الله له به طريقًا إلى الجنّة» (رواه مسلم)، فطلبُ العلمِ طريقٌ إلى الجنّةِ ورضا الله.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8946c331-684d-5576-ae8b-691d3e5ab22c', '0fb64f4f-950a-5735-bb06-f31332dc43d9', 'من آدابِ طالبِ العلمِ تجاهَ كتبه وأدواته أن ...', '[{"id":"a","text":"يُمزّقها"},{"id":"b","text":"يُحافظَ عليها ويُرتّبها"},{"id":"c","text":"يُعيرَها ولا يستردّها"},{"id":"d","text":"يرميها بعد الدرس"}]'::jsonb, 'b', 'من آدابِ طالبِ العلمِ النظامُ والمحافظةُ على الكتبِ والأدواتِ وترتيبها، فهي وسيلتُه إلى العلم.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6d234899-85c8-594e-a9b2-32d7b27f4cf7', '0fb64f4f-950a-5735-bb06-f31332dc43d9', 'كي يثبتَ الدرسُ في ذهنِ التلميذِ بعد المدرسة، عليه أن ...', '[{"id":"a","text":"ينساه فورًا"},{"id":"b","text":"يتركَه إلى الامتحان"},{"id":"c","text":"يُراجعَه في البيت"},{"id":"d","text":"يلعبَ طوالَ المساء"}]'::jsonb, 'c', 'المراجعةُ في البيت تثبّتُ ما تعلّمناه وتُعيننا على الفهمِ والحفظ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b2bf91e8-54fc-592c-b65e-c887a42e04b1', '0fb64f4f-950a-5735-bb06-f31332dc43d9', 'إذا أشكلَ على التلميذِ شيءٌ في الدرس، فالأدبُ أن ...', '[{"id":"a","text":"يسألَ بأدبٍ عمّا لم يفهم"},{"id":"b","text":"يسكتَ ويتركَ كلَّ الدرس"},{"id":"c","text":"يخرجَ من القسم"},{"id":"d","text":"يغشَّ من زميله"}]'::jsonb, 'a', 'السؤالُ بأدبٍ من آدابِ العلم، وهو يفتحُ لنا ما أُغلق علينا من الفهم، ولا نخجلُ منه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('8a170f24-0f55-5c3d-aa41-f8eda59870cd', 'f02dfd48-0526-55c4-8460-3fc8537ee62a', 'education-islamique-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: فارسُ العلمِ والاجتهاد', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
