INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('978cac46-bdb1-5b21-aede-c3c6fb17d9e2', '8a170f24-0f55-5c3d-aa41-f8eda59870cd', 'تلميذان: الأوّلُ يُصغي ويراجعُ ويسأل، والثاني يلعبُ ولا يراجع. أيُّهما أقربُ إلى التوفيقِ في طلبِ العلم؟', '[{"id":"a","text":"الثاني لأنّه يرتاح أكثر"},{"id":"b","text":"الأوّل لأنّه أخذ بأسبابِ الاجتهادِ وآدابِ العلم"},{"id":"c","text":"هما سواء"},{"id":"d","text":"لا أحدَ منهما"}]'::jsonb, 'b', 'الاجتهادُ بالإصغاءِ والمراجعةِ والسؤالِ طريقُ النجاح. الخطأ الشائع ظنُّ أنّ الراحةَ واللعبَ يُغنيان عن العملِ والمثابرة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6b9661e1-60ed-5b5d-b7a6-87a6f0a3c4dc', '8a170f24-0f55-5c3d-aa41-f8eda59870cd', 'قال أحدُهم: «ما دامَ العلمُ طريقًا إلى الجنّة، فلا حاجةَ للاجتهاد، يكفي أن أتمنّى.» ما الصواب؟', '[{"id":"a","text":"كلامُه صحيح، التمنّي يكفي"},{"id":"b","text":"يكفي حضورُ الجسدِ دون عمل"},{"id":"c","text":"العلمُ بلا تعب"},{"id":"d","text":"لا بدّ من السعيِ والاجتهاد، فالحديثُ في مَن «سلك طريقًا» أي عمل وسعى"}]'::jsonb, 'd', 'الحديثُ يمدحُ مَن «سلك طريقًا يلتمسُ فيه علمًا» أي بذل واجتهد. الخطأ الشائع انتظارُ الثمرةِ بالتمنّي دون سعيٍ وعمل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('edb05fce-972c-555f-934d-0e6f1fbf6c83', '8a170f24-0f55-5c3d-aa41-f8eda59870cd', 'تلميذٌ مجتهدٌ لكنّه يسخرُ من زميلٍ بطيءِ الفهم. ما الخللُ في سلوكه؟', '[{"id":"a","text":"لا خللَ، ما دام مجتهدًا"},{"id":"b","text":"كان عليه أن يسخرَ أكثر"},{"id":"c","text":"العلمُ يُثمرُ خُلقًا حسنًا، فالأَولى أن يساعدَه لا أن يسخرَ منه"},{"id":"d","text":"كان عليه أن يتركَ المدرسة"}]'::jsonb, 'c', 'العلمُ النافعُ يُورثُ التواضعَ وحسنَ الخلق، فيساعدُ المتعلّمُ زميلَه. الخطأ الشائع الجمعُ بين الاجتهادِ والكِبرِ والسخريةِ من الآخرين.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4453a00f-6297-5b74-a373-f1af84511c43', '8a170f24-0f55-5c3d-aa41-f8eda59870cd', 'تلميذٌ كلّما واجه تمرينًا صعبًا قال «أنا لا أفهمُ أبدًا» وأغلقَ كتابه. ما النصيحةُ المستفادةُ من الدرس؟', '[{"id":"a","text":"أن يقولَ «سأحاولُ مرّةً أخرى» ويثابرَ ويسأل"},{"id":"b","text":"أن يتركَ المادّةَ كلَّها"},{"id":"c","text":"أن يَنتظرَ العامَ القادم"},{"id":"d","text":"أن يطلبَ من غيرِه أن يحلَّ له دائمًا"}]'::jsonb, 'a', 'المثابرةُ تصنعُ من الصعبِ سهلًا، فيُعيدُ المحاولةَ ويسألُ ويراجع. الخطأ الشائع اليأسُ السريعُ وقولُ «لا أفهمُ أبدًا» عند أوّل تعثّر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9881b52e-1655-585d-a452-76c2617bcbb3', '8a170f24-0f55-5c3d-aa41-f8eda59870cd', 'قبلَ الامتحانِ خيّرَ تلميذٌ نفسَه بين أن يراجعَ بجِدّ أو أن يُعِدَّ ورقةَ غشّ. ما الأرشدُ والأبركُ؟', '[{"id":"a","text":"ورقةُ الغشّ لأنّها أسهل"},{"id":"b","text":"يتركُ الاثنين وينام"},{"id":"c","text":"يغشُّ هذه المرّةَ فقط"},{"id":"d","text":"يراجعُ بجِدٍّ ويتوكّلُ على الله، فالصدقُ أبركُ والغشُّ حرام"}]'::jsonb, 'd', 'الصدقُ من آدابِ العلم، والمراجعةُ الجادّةُ مع التوكّلِ هي الطريق. الخطأ الشائع التهوينُ من الغشِّ بحجّة «مرّةً واحدة»، والغشُّ خيانةٌ تمنعُ البركةَ والفهم.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de5e3cae-80ee-54af-8c77-cac11f33f533', '8a170f24-0f55-5c3d-aa41-f8eda59870cd', 'أرادَ تلميذٌ أن يجمعَ أسبابَ التوفيقِ في طلبِ العلم. أيُّ مجموعةٍ هي الأصحّ؟', '[{"id":"a","text":"الكسلُ والنومُ واللعبُ الدائم"},{"id":"b","text":"الإصغاءُ والمراجعةُ والسؤالُ والصدقُ والدعاء"},{"id":"c","text":"الغشُّ ومقاطعةُ المعلّمِ والسخرية"},{"id":"d","text":"تركُ الواجباتِ وإهمالُ الكتب"}]'::jsonb, 'b', 'أسبابُ التوفيق: الإصغاءُ والمراجعةُ والسؤالُ بأدبٍ والصدقُ والدعاءُ «ربِّ زِدني علمًا». الخطأ الشائع توقّعُ النجاحِ مع الكسلِ والغشِّ وإهمالِ الآداب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
