INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9d2dabb0-1de1-528b-9df5-d3ce8c943e73', '2abbfdbe-1b81-5f6f-8557-29a1dd7a0252', 'العلمُ في ديننا ...', '[{"id":"a","text":"مذمومٌ نتركه"},{"id":"b","text":"لا قيمةَ له"},{"id":"c","text":"للكبارِ فقط"},{"id":"d","text":"نعمةٌ من الله نحبّها ونطلبها"}]'::jsonb, 'd', 'العلمُ نعمةٌ من الله، وأوّلُ ما نزل من القرآن «اقرأ»، فنحبّه ونجتهدُ في طلبه.', 1)
