INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d4afb78d-dae3-5435-ad60-7566687d1431', '2abbfdbe-1b81-5f6f-8557-29a1dd7a0252', 'أوّلُ ما نزل من القرآن الكريم كان الأمرَ بـ ...', '[{"id":"a","text":"النوم"},{"id":"b","text":"اللعب"},{"id":"c","text":"القراءة"},{"id":"d","text":"الراحة"}]'::jsonb, 'c', 'أوّلُ ما نزل قولُه تعالى «اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ»، وهو أمرٌ بالقراءةِ والعلم.', 2)
