INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7e7dace4-869c-5382-98bf-33145c692033', '2abbfdbe-1b81-5f6f-8557-29a1dd7a0252', 'من آدابِ طالبِ العلمِ مع المعلّمِ أن ...', '[{"id":"a","text":"يُصغيَ إليه ولا يقاطعه"},{"id":"b","text":"يتكلّمَ فوقَ صوته"},{"id":"c","text":"يخرجَ متى شاء"},{"id":"d","text":"يلعبَ أثناء الشرح"}]'::jsonb, 'a', 'الإصغاءُ للمعلّمِ دون مقاطعةٍ أدبٌ من آدابِ العلم، وهو بابُ الفهم.', 3)
