INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6239798e-b620-5a6d-af17-4b9b67dddfdf', '2abbfdbe-1b81-5f6f-8557-29a1dd7a0252', 'تلميذٌ يراجعُ دروسَه كلَّ مساءٍ في بيته. هذا من ...', '[{"id":"a","text":"إضاعةِ الوقت"},{"id":"b","text":"آدابِ طالبِ العلمِ وأسبابِ النجاح"},{"id":"c","text":"الأشياءِ غيرِ المفيدة"},{"id":"d","text":"الكسل"}]'::jsonb, 'b', 'المراجعةُ في البيت من آدابِ طالبِ العلم، تثبّتُ المعلوماتِ وتُعينُ على الفهمِ والحفظ.', 4)
