INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2ca566e0-ccd4-524f-a584-087a5667137b', '2abbfdbe-1b81-5f6f-8557-29a1dd7a0252', 'أيُّ دعاءٍ يدلّ على حبِّ التلميذِ للعلمِ ورغبتِه في الزيادةِ منه؟', '[{"id":"a","text":"ربِّ أرحني من المدرسة"},{"id":"b","text":"ربِّ أعطني لعبًا كثيرًا"},{"id":"c","text":"ربِّ زِدني علمًا"},{"id":"d","text":"ربِّ قصّرِ الدرس"}]'::jsonb, 'c', 'ندعو الله أن يزيدَنا علمًا فنقول «ربِّ زِدني علمًا»، وهو دعاءٌ يدلّ على حبِّ العلمِ والرغبةِ فيه.', 5)
