INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fea1e211-3ec0-5db5-b63e-03d50cbeaa84', '2abbfdbe-1b81-5f6f-8557-29a1dd7a0252', 'تلميذٌ واجه صعوبةً في درسٍ، فما العملُ الصحيح؟', '[{"id":"a","text":"يستسلمُ ويتركُ الدرس"},{"id":"b","text":"يغشُّ من غيره"},{"id":"c","text":"يبكي وييأس"},{"id":"d","text":"يثابرُ ويُعيدُ المحاولةَ ويسألُ معلّمه"}]'::jsonb, 'd', 'المثابرةُ مفتاحُ النجاح، فيُعيدُ المحاولةَ ويسألُ ويراجع. الخطأ الشائع الاستسلامُ أو الغشُّ عند الصعوبة.', 6)
