INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('383c55d5-8e44-56ee-b2f0-04470d535505', '6a7b8f46-256d-5166-b343-584d709b32a2', 'ما هو الوضوء؟', '[{"id":"a","text":"طهارةٌ بالتراب الطاهر"},{"id":"b","text":"عمليّةُ تطهُّرٍ بالماء الطَّهور تكون قبل الصلاة"},{"id":"c","text":"نومٌ قصيرٌ قبل الصلاة"},{"id":"d","text":"صلاةٌ زائدةٌ في الليل"}]'::jsonb, 'b', 'الوضوءُ عمليّةُ تطهُّرٍ تكون قبل الصلاة بالماء الطَّهور، أي الماء النظيف الباقي على أصله. الخطأ الشائع الخلطُ بينه وبين التيمّم الذي يكون بالتراب.', 1)
