INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a2c4cbe-1e3b-50e4-9ab4-088b708b00f7', '6a7b8f46-256d-5166-b343-584d709b32a2', 'بأيّ ماءٍ نتوضّأ؟', '[{"id":"a","text":"بماءٍ تغيّر طعمُه ولونُه"},{"id":"b","text":"بأيّ سائلٍ كان"},{"id":"c","text":"بالعصير أو الحليب"},{"id":"d","text":"بالماء الطَّهور الذي لم يتغيّر طعمُه أو لونُه أو رائحتُه"}]'::jsonb, 'd', 'نتوضّأ بالماء الطَّهور، وهو الماء الباقي على أصل خِلقته لم يتغيّر طعمُه أو لونُه أو رائحتُه، كماء الأنهار والآبار والمطر. الخطأ الشائع ظنُّ أنّ أيّ سائلٍ يصلح للوضوء.', 2)
