INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fe1374bf-f9de-5ae7-b264-98b98b75884b', '6a7b8f46-256d-5166-b343-584d709b32a2', 'أيُّ هذه من فرائض الوضوء؟', '[{"id":"a","text":"المضمضة"},{"id":"b","text":"الاستنشاق"},{"id":"c","text":"غسل الوجه"},{"id":"d","text":"مسح الأذنين"}]'::jsonb, 'c', 'غسلُ الوجه فريضةٌ من فرائض الوضوء، أمّا المضمضة والاستنشاق ومسح الأذنين فهي من السنن. الخطأ الشائع الخلطُ بين الفرائض والسنن.', 3)
