INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f1d03dda-7e23-5f18-a47a-d964c42d5ca7', '6a7b8f46-256d-5166-b343-584d709b32a2', 'إلى أين نغسل اليدين من فرائض الوضوء؟', '[{"id":"a","text":"إلى المرفقين"},{"id":"b","text":"إلى أطراف الأصابع فقط"},{"id":"c","text":"إلى الكتفين"},{"id":"d","text":"إلى الرُّسغين فقط"}]'::jsonb, 'a', 'من فرائض الوضوء غسلُ اليدين إلى المرفقين، والمرفقُ هو مَفصِلُ اليد. الخطأ الشائع الاكتفاءُ بغسل الكفّ إلى الرُّسغ، وذلك سُنّةٌ لا فريضة.', 4)
