INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0b8a4edc-f985-536f-b6dc-596ce69118df', '6a7b8f46-256d-5166-b343-584d709b32a2', 'كم عددُ فرائض الوضوء على مذهب الإمام مالك؟', '[{"id":"a","text":"3 فرائض"},{"id":"b","text":"5 فرائض"},{"id":"c","text":"7 فرائض"},{"id":"d","text":"10 فرائض"}]'::jsonb, 'c', 'فرائضُ الوضوء سبعٌ: النيّة، وغسل الوجه، وغسل اليدين إلى المرفقين، ومسح الرأس، وغسل الرجلين إلى الكعبين، والفور، والدّلك. الخطأ الشائع نسيانُ الفور والدّلك وهما فريضتان عند الإمام مالك.', 5)
