INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8cf40de7-8534-5f5e-976d-1e1441df3c78', 'd936a373-bffd-5e09-984e-2acbfcbad150', 'أيُّ هذه فريضةٌ في الوضوء وليست سُنّة؟', '[{"id":"a","text":"المضمضة"},{"id":"b","text":"الاستنشاق"},{"id":"c","text":"مسح الأذنين"},{"id":"d","text":"مسح الرأس"}]'::jsonb, 'd', 'مسحُ الرأس فريضةٌ، أمّا المضمضة والاستنشاق ومسح الأذنين فسُنن. الخطأ الشائع الخلطُ بين الفرائض والسنن.', 1)
