  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b5e4d9e0-fa69-5de4-b7d5-02abe45a42a1', 'd936a373-bffd-5e09-984e-2acbfcbad150', 'إذا ترك المتوضّئُ فريضةً من فرائض الوضوء، فإنّ وضوءه ...', '[{"id":"a","text":"يصحّ كاملًا"},{"id":"b","text":"لا يصحّ"},{"id":"c","text":"يصحّ نصفُه"},{"id":"d","text":"يكون أفضلَ"}]'::jsonb, 'b', 'الفرائضُ لا بدّ منها، فإذا تُركت واحدةٌ منها لم يصحّ الوضوء. الخطأ الشائع ظنُّ أنّ الفريضة كالسُّنّة يجوز تركُها.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f5f94ba3-6996-50ba-a6de-7a508eb01b7f', 'd936a373-bffd-5e09-984e-2acbfcbad150', 'ما الفرقُ بين الفريضة والسُّنّة في الوضوء؟', '[{"id":"a","text":"الفريضةُ لا يصحّ الوضوء بتركها، والسُّنّةُ يصحّ بدونها مع نقص الأجر"},{"id":"b","text":"كلاهما لا يصحّ الوضوء بتركه"},{"id":"c","text":"كلاهما يجوز تركُه دون أثر"},{"id":"d","text":"السُّنّةُ آكدُ من الفريضة"}]'::jsonb, 'a', 'الفريضةُ ركنٌ لا يصحّ الوضوء بتركها، أمّا السُّنّةُ فيصحّ الوضوء بدونها ولكن نخسر أجرَها. الخطأ الشائع التسويةُ بين الفريضة والسُّنّة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('88f2c55a-c23a-5b65-a45b-5c3b33416123', 'd936a373-bffd-5e09-984e-2acbfcbad150', 'أيُّ هذه من السنن التي نُكرّرها ثلاث مرّات في الأداء العملي؟', '[{"id":"a","text":"غسل الرجلين إلى الكعبين"},{"id":"b","text":"مسح الرأس"},{"id":"c","text":"المضمضة"},{"id":"d","text":"مسح الأذنين"}]'::jsonb, 'c', 'المضمضةُ سُنّةٌ نُكرّرها 3 مرات، أمّا مسحُ الرأس ومسحُ الأذنين وغسلُ الرجلين فمرّةً واحدة في الأداء العملي. الخطأ الشائع تكرارُ المسح ثلاثًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b25f7521-f825-5991-979a-454b14a9f2f6', 'd936a373-bffd-5e09-984e-2acbfcbad150', 'ما الترتيبُ الصحيح في الأداء العملي للوضوء؟', '[{"id":"a","text":"غسل الوجه ثمّ المضمضة ثمّ غسل اليدين"},{"id":"b","text":"غسل الرجلين أوّلًا ثمّ الوجه"},{"id":"c","text":"مسح الرأس قبل غسل الوجه"},{"id":"d","text":"غسل اليدين والمضمضة والاستنشاق ثمّ غسل الوجه"}]'::jsonb, 'd', 'نبدأ بغسل اليدين إلى الكوعين، ثمّ المضمضة، ثمّ الاستنشاق والاستنثار، ثمّ نغسل الوجه. الخطأ الشائع تقديمُ غسل الوجه على المضمضة والاستنشاق.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47be3281-27e6-5815-8ae6-a3b3693c0fb1', 'd936a373-bffd-5e09-984e-2acbfcbad150', 'تابعَ تلميذٌ وضوءه دون انقطاعٍ طويل، ودَلَك أعضاءه بيده. أيَّ فريضتين راعى؟', '[{"id":"a","text":"المضمضة والاستنشاق"},{"id":"b","text":"الفور والدّلك"},{"id":"c","text":"مسح الأذنين وردّ مسح الرأس"},{"id":"d","text":"الاستنثار والترتيب"}]'::jsonb, 'b', 'الفورُ هو المتابعةُ دون انقطاعٍ طويل، والدّلكُ هو إمرارُ اليد على العضو، وكلاهما فريضةٌ عند الإمام مالك. الخطأ الشائع عَدُّهما من السنن لا من الفرائض.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

