INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0916e39d-68c1-5240-8899-b11db2efc562', 'bc7e3a97-9da8-531b-b838-6f62dcca2a1d', 'الوضوءُ طهارةٌ تكون بـ ...', '[{"id":"a","text":"التراب الطاهر"},{"id":"b","text":"النار"},{"id":"c","text":"الماء الطَّهور"},{"id":"d","text":"الهواء"}]'::jsonb, 'c', 'الوضوءُ طهارةٌ بالماء الطَّهور تكون قبل الصلاة. الخطأ الشائع الخلطُ بينه وبين التيمّم الذي يكون بالتراب.', 1)
