INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6bae21da-2958-534f-8543-0ca53dda6427', 'bc7e3a97-9da8-531b-b838-6f62dcca2a1d', 'من فرائض الوضوء ...', '[{"id":"a","text":"مسح الرأس"},{"id":"b","text":"المضمضة"},{"id":"c","text":"الاستنشاق"},{"id":"d","text":"مسح الأذنين"}]'::jsonb, 'a', 'مسحُ الرأس فريضةٌ من فرائض الوضوء، أمّا المضمضة والاستنشاق ومسح الأذنين فهي من السنن. الخطأ الشائع عَدُّ السنن من الفرائض.', 2)
