INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('14dc556a-c19c-5752-b798-491a79f2834c', 'bc7e3a97-9da8-531b-b838-6f62dcca2a1d', 'نغسل الوجهَ في الوضوء من ...', '[{"id":"a","text":"الأنف إلى الفم فقط"},{"id":"b","text":"العينين فقط"},{"id":"c","text":"الجبهة إلى الرقبة"},{"id":"d","text":"أعلى الجبين إلى أسفل الذَّقن"}]'::jsonb, 'd', 'نغسل الوجهَ كلَّه من أعلى الجبين إلى أسفل الذَّقن وحتّى أطراف الأذنين. الخطأ الشائع الاكتفاءُ بغسل جزءٍ من الوجه.', 3)
