INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0dcb8d62-3317-5f23-8a23-832494cfe6a7', 'bc7e3a97-9da8-531b-b838-6f62dcca2a1d', 'ما عددُ سنن الوضوء؟', '[{"id":"a","text":"3 سنن"},{"id":"b","text":"7 سنن"},{"id":"c","text":"10 سنن"},{"id":"d","text":"سُنّةٌ واحدة"}]'::jsonb, 'b', 'سننُ الوضوء سبعٌ: غسل اليدين إلى الرُّسغين، والمضمضة، والاستنشاق، والاستنثار، ومسح الأذنين، وردّ مسح الرأس، وترتيب الفرائض. الخطأ الشائع حصرُها في سُنّةٍ أو سُنّتين.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
