  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('97a01705-5e27-5933-a929-fbf41d8826a0', 'bc7e3a97-9da8-531b-b838-6f62dcca2a1d', 'الاستنثارُ في الوضوء معناه ...', '[{"id":"a","text":"إخراجُ الماء من الأنف"},{"id":"b","text":"غسلُ الوجه"},{"id":"c","text":"مسحُ الرأس"},{"id":"d","text":"غسلُ الرجلين"}]'::jsonb, 'a', 'الاستنثارُ سُنّةٌ، وهو إخراجُ الماء من الأنف بعد إدخاله بالاستنشاق، ونكرّر ذلك 3 مرات. الخطأ الشائع الخلطُ بين الاستنشاق (الإدخال) والاستنثار (الإخراج).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
