INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ffe18540-8075-5a5f-bec3-8dae89ecf10c', 'bc7e3a97-9da8-531b-b838-6f62dcca2a1d', 'ما معنى الماء «الطَّهور» الذي نتوضّأ به؟', '[{"id":"a","text":"الماءُ الساخنُ فقط"},{"id":"b","text":"الماءُ المخلوطُ بالصابون"},{"id":"c","text":"الماءُ الباقي على أصله لم يتغيّر طعمُه أو لونُه أو رائحتُه"},{"id":"d","text":"الماءُ المالحُ فقط"}]'::jsonb, 'c', 'الماءُ الطَّهور هو الماء الباقي على أصل خِلقته، لم يتغيّر طعمُه أو لونُه أو رائحتُه بفعل شيءٍ خالطه. الخطأ الشائع ظنُّ أنّ الماء المتغيّر يصلح للوضوء.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

