INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a91d566-9074-559c-a9e5-b21798a8aead', '6d0ff9b2-da73-5ba5-aedd-c2ffb10fdf08', 'تلميذٌ توضّأ وغسل أعضاءه كلَّها لكنّه نسي النيّة من أوّله. ما حُكمُ وضوئه؟', '[{"id":"a","text":"صحيحٌ كاملًا لأنّ النيّة سُنّة"},{"id":"b","text":"غيرُ صحيحٍ لأنّ النيّة فريضة"},{"id":"c","text":"أفضلُ وضوء"},{"id":"d","text":"يصحّ نصفُه"}]'::jsonb, 'b', 'النيّةُ فريضةٌ من فرائض الوضوء، فإذا تُركت لم يصحّ الوضوء، لأنّ الأعمال بالنيّات. الخطأ الشائع ظنُّ أنّ النيّة سُنّةٌ يجوز تركُها.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5f38199c-65ca-5772-84bc-fc3bb35381dd', '6d0ff9b2-da73-5ba5-aedd-c2ffb10fdf08', 'صبّ تلميذٌ الماءَ على ذراعه دون أن يَمُرّ عليها بيده. أيَّ فريضةٍ مالكيّةٍ أهمل؟', '[{"id":"a","text":"النيّة"},{"id":"b","text":"مسح الرأس"},{"id":"c","text":"غسل الوجه"},{"id":"d","text":"الدّلك"}]'::jsonb, 'd', 'الدّلكُ فريضةٌ عند الإمام مالك، وهو إمرارُ اليد على العضو لِيَعمَّه الماء، فلا يكفي مجرّدُ صبّ الماء. الخطأ الشائع الاكتفاءُ بالصبّ دون دلك.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7f5dd8a4-297b-54b7-b45c-4b0df9bbecf5', '6d0ff9b2-da73-5ba5-aedd-c2ffb10fdf08', 'انشغل تلميذٌ بعد غسل وجهه مدّةً طويلة حتّى جفّ، ثمّ أكمل وضوءه. أيَّ فريضةٍ أخلَّ بها؟', '[{"id":"a","text":"الفور (الموالاة)"},{"id":"b","text":"المضمضة"},{"id":"c","text":"مسح الأذنين"},{"id":"d","text":"الاستنثار"}]'::jsonb, 'a', 'الفورُ فريضةٌ عند الإمام مالك، ومعناه متابعةُ الأعضاء دون انقطاعٍ طويلٍ يجفّ فيه ما قبله. الخطأ الشائع التساهلُ في الفصل الطويل بين الأعضاء.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('52179fa5-4518-5d45-8270-93a2e4fc559d', '6d0ff9b2-da73-5ba5-aedd-c2ffb10fdf08', 'أرادت تلميذةٌ أن تتوضّأ فلم تجد إلّا ماءً تغيّر لونُه ورائحتُه بسببِ ما خالطه. ماذا تفعل لِتتطهّر للصلاة؟', '[{"id":"a","text":"تتوضّأ بذلك الماء المتغيّر"},{"id":"b","text":"تترك الصلاة"},{"id":"c","text":"تطلب ماءً طَهورًا، فإن عجزت عنه تيمّمت بالصَّعيد الطاهر"},{"id":"d","text":"تُصلّي بلا طهارة"}]'::jsonb, 'c', 'لا يصحّ الوضوءُ بالماء الذي تغيّر طعمُه أو لونُه أو رائحتُه، فتطلب ماءً طَهورًا، فإن لم تجده عجزًا تيمّمت بالصَّعيد الطاهر. الخطأ الشائع الوضوءُ بالماء المتغيّر أو تركُ الصلاة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d61d9dfa-ada5-5136-bed2-8b8214618e84', '6d0ff9b2-da73-5ba5-aedd-c2ffb10fdf08', 'رتّبَ تلميذٌ فرائضَ الوضوء هكذا: «الوجه، ثمّ مسح الرأس، ثمّ اليدان، ثمّ الرجلان». ما الصواب؟', '[{"id":"a","text":"ترتيبُه صحيحٌ تمامًا"},{"id":"b","text":"الصواب: الرجلان أوّلًا ثمّ الوجه"},{"id":"c","text":"الصواب: مسح الرأس قبل الوجه"},{"id":"d","text":"الصواب: الوجه، ثمّ اليدان، ثمّ مسح الرأس، ثمّ الرجلان"}]'::jsonb, 'd', 'ترتيبُ الفرائض: الوجه أوّلًا، ثمّ اليدان، ثمّ مسح الرأس، ثمّ الرجلان. الخطأ الشائع تقديمُ مسح الرأس على غسل اليدين.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e3c3c532-a6fe-58c3-be96-6e7fa40e3dee', '6d0ff9b2-da73-5ba5-aedd-c2ffb10fdf08', 'أحسنَ تلميذٌ وضوءه ففعل الفرائضَ كلَّها وزاد المضمضةَ والاستنشاقَ ومسحَ الأذنين. ماذا نقول عن وضوئه؟', '[{"id":"a","text":"وضوءٌ باطلٌ لأنّه زاد على الفرائض"},{"id":"b","text":"وضوءٌ صحيحٌ كاملٌ جمع الفرائضَ والسننَ فنال أجرًا أكبر"},{"id":"c","text":"وضوءٌ ناقصٌ"},{"id":"d","text":"لا يصحّ إلّا بالتيمّم بعده"}]'::jsonb, 'b', 'من أتى بالفرائض كلِّها صحّ وضوؤه، فإذا زاد السننَ (كالمضمضة والاستنشاق ومسح الأذنين) نال أجرًا أكبرَ اقتداءً بالنبيّ ﷺ. الخطأ الشائع ظنُّ أنّ فعلَ السنن يُبطل الوضوء.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

