  ('bf46616c-72ec-5a35-87a4-170cb3456292', '873e0c1d-76a4-5d7b-9b33-129bee2e3756', 'education-islamique-4eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة للوضوء', 3, 120, 30, 'boss', 'admin', 5)
