INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9d15c3b6-338d-5854-ac99-81a4fad31cd2', 'bf46616c-72ec-5a35-87a4-170cb3456292', 'الوضوءُ يكون ... الصلاة.', '[{"id":"a","text":"قبل"},{"id":"b","text":"بعد"},{"id":"c","text":"بدلَ"},{"id":"d","text":"بدونِ"}]'::jsonb, 'a', 'الوضوءُ طهارةٌ تكون قبل الصلاة، فنتطهّر أوّلًا ثمّ نُصلّي. الخطأ الشائع تأخيرُ الوضوء إلى ما بعد الصلاة.', 1)
ON CONFLICT (id) DO UPDATE SET
