  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('79760a21-44eb-5d42-b494-288af7e1c37e', 'bf46616c-72ec-5a35-87a4-170cb3456292', 'أيُّ هذه ليست من فرائض الوضوء؟', '[{"id":"a","text":"غسل الوجه"},{"id":"b","text":"مسح الرأس"},{"id":"c","text":"مسح الأذنين"},{"id":"d","text":"غسل الرجلين إلى الكعبين"}]'::jsonb, 'c', 'مسحُ الأذنين سُنّةٌ وليس فريضة، أمّا غسلُ الوجه ومسحُ الرأس وغسلُ الرجلين إلى الكعبين فهي من الفرائض. الخطأ الشائع عَدُّ مسح الأذنين فريضة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
