  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('63a77aa7-cc2b-57ee-b427-ddfe285c9976', 'bf46616c-72ec-5a35-87a4-170cb3456292', 'المضمضةُ في الوضوء معناها ...', '[{"id":"a","text":"غسلُ اليدين"},{"id":"b","text":"مسحُ الرأس"},{"id":"c","text":"غسلُ الرجلين"},{"id":"d","text":"إدخالُ الماء إلى الفم وغسلُه من الداخل"}]'::jsonb, 'd', 'المضمضةُ سُنّةٌ، وهي إدخالُ الماء إلى الفم وغسلُه من الداخل، ونكرّرها 3 مرات. الخطأ الشائع الخلطُ بينها وبين الاستنشاق الذي يكون للأنف.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
