  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b656a920-ee7f-5b47-a2f3-6154c62aa39a', 'bf46616c-72ec-5a35-87a4-170cb3456292', 'كم عددُ فرائض الوضوء؟', '[{"id":"a","text":"4 فرائض"},{"id":"b","text":"7 فرائض"},{"id":"c","text":"5 فرائض"},{"id":"d","text":"9 فرائض"}]'::jsonb, 'b', 'فرائضُ الوضوء سبعٌ: النيّة، وغسل الوجه، وغسل اليدين إلى المرفقين، ومسح الرأس، وغسل الرجلين إلى الكعبين، والفور، والدّلك. الخطأ الشائع نسيانُ الفور والدّلك.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d8a6d792-b098-522c-b9e0-4ef7cf44bb09', 'bf46616c-72ec-5a35-87a4-170cb3456292', 'في الأداء العملي، ماذا نفعل بعد غسل الوجه مباشرةً؟', '[{"id":"a","text":"نغسل الرجلين إلى الكعبين"},{"id":"b","text":"نمسح الأذنين"},{"id":"c","text":"نغسل اليدين إلى المرفقين"},{"id":"d","text":"نختم الوضوء"}]'::jsonb, 'c', 'بعد غسل الوجه نغسل اليدين إلى المرفقين، ثمّ نمسح الرأس، ثمّ نمسح الأذنين، ثمّ نغسل الرجلين. الخطأ الشائع تقديمُ مسح الرأس أو غسل الرجلين على غسل اليدين.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
