  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2cc7f0e6-647a-5c27-b682-d590f0c07464', 'bf46616c-72ec-5a35-87a4-170cb3456292', 'تلميذٌ توضّأ بماءٍ صافٍ من النهر لم يتغيّر طعمُه ولا لونُه ولا رائحتُه. ما حُكمُ هذا الماء؟', '[{"id":"a","text":"ماءٌ طَهور يصحّ به الوضوء"},{"id":"b","text":"ماءٌ لا يصحّ به الوضوء"},{"id":"c","text":"لا يُستعمل إلّا للشرب"},{"id":"d","text":"يُستعمل للتيمّم لا للوضوء"}]'::jsonb, 'a', 'ماءُ النهر الصافي الباقي على أصله، الذي لم يتغيّر طعمُه أو لونُه أو رائحتُه، ماءٌ طَهور يصحّ به الوضوء. الخطأ الشائع ظنُّ أنّ الوضوء لا يصحّ إلّا بماءٍ مُعالَجٍ خاص.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
