INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4136c479-9688-5c80-ba30-866bb13af24e', '33a6bc1d-9921-5d7e-98da-44f839dc6106', 'أيُّ هذه فريضةٌ في التيمّم وليست سُنّة؟', '[{"id":"a","text":"الترتيب"},{"id":"b","text":"ضرب اليدين على الصَّعيد (الضربة الأولى)"},{"id":"c","text":"مسح الذِّراعين إلى المرفقين"},{"id":"d","text":"تجديد ضربةٍ ثانية لليدين"}]'::jsonb, 'b', 'ضربُ اليدين على الصَّعيد (الضربة الأولى) فريضةٌ، أمّا الترتيب ومسحُ الذِّراعين إلى المرفقين وتجديدُ الضربة الثانية فسُنن. الخطأ الشائع الخلطُ بين فرائض التيمّم وسننه.', 1)
