  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7b3fc7ce-eca2-5933-b75e-44e84a3335a5', '33a6bc1d-9921-5d7e-98da-44f839dc6106', 'ما الفرق بين الوضوء والتيمّم؟', '[{"id":"a","text":"الوضوء بالتراب والتيمّم بالماء"},{"id":"b","text":"كلاهما بالتراب"},{"id":"c","text":"كلاهما بالماء"},{"id":"d","text":"الوضوء بالماء الطَّهور والتيمّم بالصَّعيد الطاهر"}]'::jsonb, 'd', 'الوضوء طهارةٌ مائيّةٌ بالماء الطَّهور، والتيمّم طهارةٌ ترابيّةٌ بالصَّعيد الطاهر عند فقد الماء. الخطأ الشائع عكسُ الوسيلتين بين الطهارتين.', 2)
