INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('466c54e3-6c22-5d2d-bf4d-0ee196366bef', '33a6bc1d-9921-5d7e-98da-44f839dc6106', 'إلى أين ينتهي مسحُ اليدين في فرائض التيمّم؟', '[{"id":"a","text":"إلى المرفقين"},{"id":"b","text":"إلى أطراف الأصابع فقط"},{"id":"c","text":"إلى الكتفين"},{"id":"d","text":"إلى الكوعين"}]'::jsonb, 'd', 'في فرائض التيمّم نُعمّم الوجه واليدين بالمسح إلى الكوعين. أمّا المسحُ إلى المرفقين فسُنّة. الخطأ الشائع جعلُ المرفقين حدًّا للفريضة، والصواب أنّ حدّ الفرض هو الكوعان.', 3)
ON CONFLICT (id) DO UPDATE SET
