INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f0241686-be3a-5b93-81c6-2da05e367631', '33a6bc1d-9921-5d7e-98da-44f839dc6106', 'طفلٌ مريضٌ يضرّه الماء ولا يستطيع الوضوء، وحضرت الصلاة. ماذا يفعل؟', '[{"id":"a","text":"يتيمّم بالصَّعيد الطاهر ثمّ يُصلّي"},{"id":"b","text":"يترك الصلاة حتّى يشفى"},{"id":"c","text":"يُصلّي دون أيّ طهارة"},{"id":"d","text":"يؤخّر الصلاة عن وقتها"}]'::jsonb, 'a', 'العجزُ عن استعمال الماء سببٌ للتيمّم، فيتيمّم بالصَّعيد الطاهر ويُصلّي في وقتها. الخطأ الشائع تركُ الصلاة أو تأخيرُها بحجّة العجز عن الوضوء.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
