  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7651f860-6063-5f61-8da3-d6772904f7ef', '33a6bc1d-9921-5d7e-98da-44f839dc6106', 'تيمّمَ مسافرٌ لصلاة الظهر، فهل يُصلّي بذلك التيمّم صلاةَ العصر أيضًا؟', '[{"id":"a","text":"نعم، يكفيه تيمُّمٌ واحدٌ لكلّ اليوم"},{"id":"b","text":"نعم، يكفيه تيمُّمٌ واحدٌ للأسبوع"},{"id":"c","text":"لا، يتيمّم لكلِّ فرضٍ وحده"},{"id":"d","text":"لا يُصلّي العصر أصلًا"}]'::jsonb, 'c', 'من فرائض التيمّم أن نتيمّم لكلِّ فرضٍ وحده، فلكلّ صلاةٍ تيمُّمٌ جديد. الخطأ الشائع الاكتفاءُ بتيمُّمٍ واحدٍ لعدّة فروض.', 5)
