  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bc1bc981-1e45-5ab4-8a4c-5edeb247ec72', '33a6bc1d-9921-5d7e-98da-44f839dc6106', 'وجد مسافرٌ متيمِّمٌ الماءَ وقدِر على استعماله قبل الصلاة. ماذا يفعل؟', '[{"id":"a","text":"يبقى على التيمّم دائمًا"},{"id":"b","text":"يعود إلى الوضوء بالماء"},{"id":"c","text":"يُصلّي دون طهارة"},{"id":"d","text":"يجمع بين التيمّم والوضوء معًا"}]'::jsonb, 'b', 'التيمّم بديلٌ عند الحاجة فقط، فإذا وُجد الماء وأمكن استعمالُه عُدنا إلى الوضوء. الخطأ الشائع البقاءُ على التيمّم بعد زوال العذر ووجودِ الماء.', 6)
