INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc597478-3eaa-54b7-a70b-9b6e9da38574', '9078bf2c-ba5d-578f-9920-adaf0c8b8dfd', 'خرج تلميذٌ في رحلةٍ إلى الصحراء فلم يجد ماءً وحضرت الصلاة. ما الأصحّ أن يفعل؟', '[{"id":"a","text":"يترك الصلاة حتّى يرجع إلى البيت"},{"id":"b","text":"يتيمّم بالصَّعيد الطاهر ثمّ يُصلّي في وقتها"},{"id":"c","text":"يُصلّي دون أيّ طهارة"},{"id":"d","text":"ينتظر نزول المطر"}]'::jsonb, 'b', 'فقدانُ الماء سببٌ للتيمّم، فيتيمّم بالصَّعيد الطاهر ويُصلّي في وقتها. الخطأ الشائع تأجيلُ الصلاة عن وقتها بحجّة فقد الماء.', 1)
