INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd7c0741-5dd9-5e71-a089-b981444b6b24', '9078bf2c-ba5d-578f-9920-adaf0c8b8dfd', 'تيمّمَ تلميذٌ فنوى ومسح وجهه ثمّ توقّف زمنًا طويلًا قبل أن يمسح يدَيه. أيّ فريضةٍ أخلَّ بها؟', '[{"id":"a","text":"النيّة"},{"id":"b","text":"ضرب اليدين على الصَّعيد"},{"id":"c","text":"التيمّم لكلّ فرضٍ وحده"},{"id":"d","text":"الموالاة"}]'::jsonb, 'd', 'الموالاةُ فريضةٌ، ومعناها متابعةُ الحركات دون انقطاعٍ طويل، فبالتوقّف الطويل أخلَّ بها. الخطأ الشائع الاستهانةُ بالموالاة بين خطوات التيمّم.', 2)
