INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d16f38b4-d6ac-5a21-b916-f17b424b2423', '9078bf2c-ba5d-578f-9920-adaf0c8b8dfd', 'أرادَ تلميذٌ أن يُتقن حركات التيمّم بالترتيب الصحيح. ما الترتيب؟', '[{"id":"a","text":"مسح اليدين ثمّ الوجه قبل النيّة"},{"id":"b","text":"مسح الرجلين ثمّ الوجه"},{"id":"c","text":"النيّة، ثمّ ضرب اليدين على الصَّعيد، فمسح الوجه، فمسح اليدين"},{"id":"d","text":"غسل الوجه بالماء ثمّ مسح اليدين"}]'::jsonb, 'c', 'يبدأ التيمّم بالنيّة، ثمّ ضربِ اليدين على الصَّعيد، فمسحِ الوجه، فمسحِ اليدين. الخطأ الشائع تقديمُ مسح اليدين على الوجه أو نسيانُ النيّة في البداية.', 3)
