INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73122b5b-0d4d-5c88-838b-406f5a1213f5', '9078bf2c-ba5d-578f-9920-adaf0c8b8dfd', 'مريضٌ تيمّمَ لصلاة الظهر، فلمّا حضر العصر ظنّ أنّ تيمُّمه الأوّل يكفيه فلم يُعِدْه. ما الصواب؟', '[{"id":"a","text":"كان عليه أن يتيمّم للعصر تيمُّمًا جديدًا"},{"id":"b","text":"يكفيه تيمُّمٌ واحدٌ لكلّ اليوم"},{"id":"c","text":"يكفيه تيمُّمٌ واحدٌ للأسبوع"},{"id":"d","text":"لا يُصلّي العصر ما دام مريضًا"}]'::jsonb, 'a', 'من فرائض التيمّم أن نتيمّم لكلِّ فرضٍ وحده، فلكلّ صلاةٍ تيمُّمٌ جديد. الخطأ الشائع الاكتفاءُ بتيمُّمٍ واحدٍ لعدّة فروض.', 4)
