INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('82f9a6f4-24f7-57b1-b07b-297980ffb8db', '9078bf2c-ba5d-578f-9920-adaf0c8b8dfd', 'تيمّمَ مسافرٌ ثمّ نزل في محطّةٍ فوجد ماءً طَهورًا وقدِر على استعماله قبل أن يُصلّي. ماذا يفعل؟', '[{"id":"a","text":"يبقى على تيمُّمه دائمًا"},{"id":"b","text":"يُصلّي بلا طهارة لأنّه تيمّم"},{"id":"c","text":"يتيمّم مرّةً أخرى احتياطًا"},{"id":"d","text":"يعود إلى الوضوء بالماء"}]'::jsonb, 'd', 'التيمّم بديلٌ عند العجز أو فقد الماء فقط، فإذا وُجد الماء وأمكن استعمالُه عُدنا إلى الوضوء. الخطأ الشائع البقاءُ على التيمّم بعد زوال العذر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('49c0c71f-2307-525d-86e6-aa368c89de54', '9078bf2c-ba5d-578f-9920-adaf0c8b8dfd', 'لم يجد بدوٌّ في الجبل ترابًا ليّنًا، لكن وجد حجرًا طاهرًا وثلجًا. هل يصحّ أن يتيمّم بهما؟', '[{"id":"a","text":"لا، لا يصحّ التيمّم إلّا بالتراب وحده"},{"id":"b","text":"نعم، الحجر والثَّلج من الصَّعيد الطاهر"},{"id":"c","text":"لا، يُصلّي بلا طهارة"},{"id":"d","text":"لا، يترك الصلاة"}]'::jsonb, 'b', 'الصَّعيد الطاهر يشمل التُّراب والحجر والثَّلج، فيصحّ التيمّم بأيٍّ منها. الخطأ الشائع حصرُ الصَّعيد في التراب وحده.', 6)
