INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('291a72b7-1c1d-5acb-9fd4-7d936a474750', '480ee80d-a277-5cc4-92a9-2285e63470ff', 'نتيمّم بدلًا من ...', '[{"id":"a","text":"الصلاة"},{"id":"b","text":"الصيام"},{"id":"c","text":"الوضوء"},{"id":"d","text":"الدعاء"}]'::jsonb, 'c', 'التيمّم طهارةٌ ترابيّةٌ نتطهّر بها بدلًا من الوضوء عند فقد الماء أو العجز عن استعماله.', 1)
