  ('6a08fa66-5837-5860-80a7-995a42414a78', '480ee80d-a277-5cc4-92a9-2285e63470ff', 'الصَّعيد الطاهر يشمل ...', '[{"id":"a","text":"الماء والعصير"},{"id":"b","text":"الزيت والعطر"},{"id":"c","text":"الحليب والخلّ"},{"id":"d","text":"التُّراب والحجر والثَّلج"}]'::jsonb, 'd', 'الصَّعيد الطاهر الذي نتيمّم به هو وجهُ الأرض النظيف: التُّراب والحجر والثَّلج.', 3)
