INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dde41a92-90e0-5653-933c-c64a8df72968', '480ee80d-a277-5cc4-92a9-2285e63470ff', 'مسحُ الذِّراعين من الكوعين إلى المرفقين في التيمّم هو ...', '[{"id":"a","text":"سُنّةٌ"},{"id":"b","text":"فريضةٌ لا يصحّ التيمّم بدونها"},{"id":"c","text":"ممنوعٌ"},{"id":"d","text":"بديلٌ عن النيّة"}]'::jsonb, 'a', 'مسحُ الذِّراعين من الكوعين إلى المرفقين سُنّةٌ من سنن التيمّم، أمّا الفرضُ فالمسحُ إلى الكوعين. الخطأ الشائع عدُّ المسح إلى المرفقين فريضةً.', 4)
