INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5815650b-deec-5a15-8e29-3ceb7ca4fbbb', '480ee80d-a277-5cc4-92a9-2285e63470ff', 'تلميذٌ بدأ يمسح وجهه في التيمّم دون أن ينوي بقلبه. ما حُكمُ تيمُّمه؟', '[{"id":"a","text":"صحيحٌ لأنّ النيّة سُنّة"},{"id":"b","text":"غيرُ صحيحٍ لأنّ النيّة فريضة"},{"id":"c","text":"صحيحٌ كاملًا"},{"id":"d","text":"أفضلُ تيمُّم"}]'::jsonb, 'b', 'النيّة فريضةٌ من فرائض التيمّم، فإذا تُركت لم يصحّ، لأنّ الأعمال بالنيّات. الخطأ الشائع ظنُّ أنّ النيّة سُنّةٌ يجوز تركها.', 5)
