INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('843e5f46-c4f4-5d55-90d6-c9b8e5f07e51', '83ccdec1-5ac4-5e7c-be1f-9238ba953447', 'إلامَ تدعونا السورة في قوله تعالى ﴿أَفَلَا يَنظُرُونَ إِلَى الْإِبِلِ كَيْفَ خُلِقَتْ﴾؟', '[{"id":"a","text":"إلى ركوب الإبل في السفر"},{"id":"b","text":"إلى بيع الإبل وشرائها"},{"id":"c","text":"إلى الخوف من الإبل"},{"id":"d","text":"إلى التأمّل في خلق الله لنعرف عظمته وقدرته"}]'::jsonb, 'd', 'تدعونا الآية إلى التأمّل في الإبل كيف خلقها الله، فهي دليلٌ على عظمة الله وقدرته، كالسماء والجبال والأرض.', 3)
