INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('628cab1b-9399-54fe-84a2-84f5b3a396aa', '83ccdec1-5ac4-5e7c-be1f-9238ba953447', 'ماذا تعني كلمة «الغاشية» التي سُمّيت بها السورة؟', '[{"id":"a","text":"اسمٌ من أسماء الملائكة"},{"id":"b","text":"نوعٌ من الطعام"},{"id":"c","text":"اسمٌ من أسماء يوم القيامة"},{"id":"d","text":"اسمٌ لمدينة"}]'::jsonb, 'c', '«الغاشية» من أسماء يوم القيامة، سُمّيت كذلك لأنّها تغشى الناسَ وتعمّهم بأهوالها.', 4)
