INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7c60f1ba-fddd-5fd6-9c5a-2b3fa1fa4e39', '83ccdec1-5ac4-5e7c-be1f-9238ba953447', 'كيف وصفت السورة وجوهَ أهل الجنّة في قوله ﴿وُجُوهٌ يَوْمَئِذٍ نَّاعِمَةٌ﴾؟', '[{"id":"a","text":"وجوهٌ خاشعةٌ ذليلة"},{"id":"b","text":"وجوهٌ ناعمةٌ ذاتُ بهجةٍ وحُسنٍ ونضارة"},{"id":"c","text":"وجوهٌ غاضبةٌ حزينة"},{"id":"d","text":"وجوهٌ خائفةٌ من العذاب"}]'::jsonb, 'b', 'وجوهُ أهل الجنّة «ناعمة»، أي ذاتُ بهجةٍ وحُسنٍ ونضارة، لأنّها راضيةٌ بما عملت من خيرٍ في الدنيا. أمّا «الخاشعة» فهي وجوهُ أهل النار.', 5)
