INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7598a7eb-b47d-563e-b9d9-2fbe2bbb2ac2', 'e9bee892-b23f-5b7e-96bc-c9013024e617', 'بأيّ آيةٍ تختم سورة الغاشية؟', '[{"id":"a","text":"وَإِلَى الْأَرْضِ كَيْفَ سُطِحَتْ"},{"id":"b","text":"ثُمَّ إِنَّ عَلَيْنَا حِسَابَهُمْ"},{"id":"c","text":"فَذَكِّرْ إِنَّمَا أَنتَ مُذَكِّرٌ"},{"id":"d","text":"هَلْ أَتَىٰكَ حَدِيثُ الْغَٰشِيَةِ"}]'::jsonb, 'b', 'تختم السورة بقوله تعالى: ثُمَّ إِنَّ عَلَيْنَا حِسَابَهُمْ، أي أنّ حسابَ الناس على الله وحده.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

