  ('a2cdf847-625e-5f73-95b5-5a6a3430f505', '166c6b9d-e706-53e0-a6fa-0867e0cc056b', 'education-islamique-4eme', '⚔️ زعيم الفصل ⭐⭐⭐: حارسُ سورة الغاشية', 3, 120, 30, 'boss', 'admin', 2)
