INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1311563d-c773-56ce-8ed3-6feb5e7d1df4', 'a2cdf847-625e-5f73-95b5-5a6a3430f505', 'ما المخلوقاتُ الأربعةُ التي دعتنا السورة إلى التأمّل فيها (الآيات 17–20)؟', '[{"id":"a","text":"الشمسُ والقمرُ والنجومُ والرياح"},{"id":"b","text":"الإبلُ والسماءُ والجبالُ والأرض"},{"id":"c","text":"البحرُ والأنهارُ والأشجارُ والطير"},{"id":"d","text":"الإبلُ والخيلُ والبقرُ والغنم"}]'::jsonb, 'b', 'دعتنا السورة إلى النظر في الإبل ثمّ السماء ثمّ الجبال ثمّ الأرض. الخطأ الشائع ذكرُ مخلوقاتٍ أخرى لم تُذكر في هذه الآيات.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('92882293-336f-58b5-a440-de79a54d10c6', 'a2cdf847-625e-5f73-95b5-5a6a3430f505', 'وصفت السورة وجوهَ أهل النار بأنّها «خَٰشِعَةٌ». ما معنى ذلك؟', '[{"id":"a","text":"وجوهٌ فرِحةٌ مسرورة"},{"id":"b","text":"وجوهٌ نائمةٌ مستريحة"},{"id":"c","text":"وجوهٌ بيضاءُ مشرقة"},{"id":"d","text":"وجوهٌ ذليلةٌ خاضعةٌ من الخزي"}]'::jsonb, 'd', '«خاشعة» أي ذليلةٌ خاضعةٌ من الخزي والذلّ، وهي وجوهُ أهل النار. الخطأ الشائع الخلطُ بينها وبين الوجوه «الناعمة» المشرقة وهي لأهل الجنّة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b110f442-79aa-5abc-b0c8-55e16898eba6', 'a2cdf847-625e-5f73-95b5-5a6a3430f505', 'ما طعامُ أهل النار الذي ذكرته السورة في قوله ﴿لَّيْسَ لَهُمْ طَعَامٌ إِلَّا مِن ضَرِيعٍ﴾؟', '[{"id":"a","text":"الضريع، وهو شوكٌ لا يُسمن ولا يُغني من جوع"},{"id":"b","text":"ثمارٌ لذيذةٌ من الجنّة"},{"id":"c","text":"لحمٌ وخبز"},{"id":"d","text":"عسلٌ ولبن"}]'::jsonb, 'a', 'طعامُهم «الضريع» وهو نوعٌ من الشوك لا ترعاه الدوابُّ لخبثه، ولا يُسمن آكلَه ولا يدفع عنه الجوع. الخطأ الشائع نسبةُ طعام الجنّة الطيّب إلى أهل النار.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('16aa0bab-a1bf-5154-a0d0-31bd6b1e11de', 'a2cdf847-625e-5f73-95b5-5a6a3430f505', 'ما الترتيب الصحيح للمخلوقات كما وردت في الآيات 17–20؟', '[{"id":"a","text":"السماءُ ثمّ الإبلُ ثمّ الأرضُ ثمّ الجبال"},{"id":"b","text":"الأرضُ ثمّ الجبالُ ثمّ السماءُ ثمّ الإبل"},{"id":"c","text":"الإبلُ ثمّ السماءُ ثمّ الجبالُ ثمّ الأرض"},{"id":"d","text":"الجبالُ ثمّ الأرضُ ثمّ الإبلُ ثمّ السماء"}]'::jsonb, 'c', 'الترتيب: الإبل (خُلقت) ثمّ السماء (رُفعت) ثمّ الجبال (نُصبت) ثمّ الأرض (سُطحت). الخطأ الشائع تقديمُ السماء على الإبل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d2dea979-ad10-50f5-a9f6-921be4ca4c11', 'a2cdf847-625e-5f73-95b5-5a6a3430f505', 'قال الله لنبيّه ﷺ: ﴿فَذَكِّرْ إِنَّمَا أَنتَ مُذَكِّرٌ ۝ لَّسْتَ عَلَيْهِم بِمُصَيْطِرٍ﴾. ما مهمّةُ النبيّ ﷺ التي تبيّنها الآية؟', '[{"id":"a","text":"أن يُكره الناسَ على الإيمان"},{"id":"b","text":"أن يُعذّب الكافرين بنفسه"},{"id":"c","text":"أن يجمع الأموال"},{"id":"d","text":"أن يُذكّر الناسَ ويُبلّغهم، لا أن يُجبرهم"}]'::jsonb, 'd', 'مهمّةُ النبيّ ﷺ التذكيرُ والبلاغ، وليس عليه أن يُكره الناسَ على الإيمان، فالهدايةُ بيد الله. الخطأ الشائع ظنُّ أنّ على الرسول ﷺ أن يُجبر الناس.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6b3cf02c-d718-5b39-a65a-1a1f8a812da1', 'a2cdf847-625e-5f73-95b5-5a6a3430f505', 'لماذا دعتنا السورة إلى النظر في الإبل والسماء والجبال والأرض؟', '[{"id":"a","text":"لِنخاف منها ونهرب"},{"id":"b","text":"لنعرف من خلقها عظمةَ الله وقدرته ووحدانيّته"},{"id":"c","text":"لِنملكها ونتاجر بها"},{"id":"d","text":"لأنّها أجملُ من غيرها فقط"}]'::jsonb, 'b', 'هذه المخلوقاتُ دلائلُ على عظمة الله وقدرته ووحدانيّته، فالنظرُ فيها يقودنا إلى الإيمان به وحده. الخطأ الشائع النظرُ إليها نظرةً عاديّةً دون تدبّرٍ في خالقها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

