INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f96a71bc-9b75-5ff1-aeb9-dbd1917753fe', 'c2f1783f-2951-5bfb-b106-8c0baae762bd', 'سورة الغاشية سورةٌ مكّيّة عددُ آياتها ...', '[{"id":"a","text":"7 آيات"},{"id":"b","text":"19 آية"},{"id":"c","text":"26 آية"},{"id":"d","text":"30 آية"}]'::jsonb, 'c', 'سورة الغاشية مكّيّة عددُ آياتها 26 آية، نزلت على النبيّ محمّد ﷺ في مكّة.', 1)
