INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('080bcd02-1958-5d5c-afdc-2f1d0f23fc6a', 'c2f1783f-2951-5bfb-b106-8c0baae762bd', 'تتحدّث سورة الغاشية في أوّلها عن حالِ الناس في ...', '[{"id":"a","text":"يوم القيامة"},{"id":"b","text":"يوم الجمعة"},{"id":"c","text":"شهر رمضان"},{"id":"d","text":"ليلة السفر"}]'::jsonb, 'a', 'السورة تصف حالَ الناس يوم القيامة (الغاشية): فريقٌ في النار وفريقٌ في الجنّة.', 2)
