INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fbb9655c-8589-58c2-a086-2fdea49d5ebb', 'c2f1783f-2951-5bfb-b106-8c0baae762bd', 'كيف وصفت السورة شرابَ أهل النار في قوله ﴿تُسْقَىٰ مِنْ عَيْنٍ ءَانِيَةٍ﴾؟', '[{"id":"a","text":"ماءٌ باردٌ عذب"},{"id":"b","text":"لبنٌ صافٍ"},{"id":"c","text":"عسلٌ مصفّى"},{"id":"d","text":"عينٌ بلغت غايتها في الحرارة"}]'::jsonb, 'd', '«عينٍ آنية» أي شديدةِ الحرارة بلغت غايتها، وهذا من عذاب أهل النار. أمّا العين «الجارية» العذبة فهي في الجنّة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
