  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc898e56-85ae-5855-b103-035188f06058', 'c2f1783f-2951-5bfb-b106-8c0baae762bd', 'ذكرت السورة من نعيم أهل الجنّة ﴿فِيهَا سُرُرٌ مَّرْفُوعَةٌ﴾. ما معنى «سُرُر»؟', '[{"id":"a","text":"أبوابٌ مغلقة"},{"id":"b","text":"أَسِرّةٌ مرتفعةٌ يجلسون عليها"},{"id":"c","text":"جبالٌ عالية"},{"id":"d","text":"أنهارٌ جارية"}]'::jsonb, 'b', '«سُرُر» جمعُ سرير، وهي أَسِرّةٌ مرتفعةٌ عاليةُ القدر في الجنّة يجلس عليها أهلُها في نعيم.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9f3096c2-c5f8-57de-ae36-f1d2c9f25658', 'c2f1783f-2951-5bfb-b106-8c0baae762bd', 'ما معنى ﴿وَإِلَى الْأَرْضِ كَيْفَ سُطِحَتْ﴾؟', '[{"id":"a","text":"بُسطت الأرضُ ومُهّدت لنعيش عليها بسهولة"},{"id":"b","text":"رُفعت الأرضُ إلى السماء"},{"id":"c","text":"نُصبت الأرضُ كالجبال"},{"id":"d","text":"أُحرقت الأرضُ بالنار"}]'::jsonb, 'a', '«سُطحت» أي بُسطت وجُعلت مستويةً ممهّدةً ليَسهُل العيشُ والسعيُ عليها، وهذا من نعم الله ودلائل قدرته.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ad478872-7a81-5e12-ad22-4c4c591ec4eb', 'c2f1783f-2951-5bfb-b106-8c0baae762bd', 'ما الدرسُ العقديُّ الذي تُعلّمنا إيّاه آياتُ ﴿أَفَلَا يَنظُرُونَ﴾؟', '[{"id":"a","text":"أنّ المخلوقاتِ خُلقت من غير خالق"},{"id":"b","text":"أنّ الإبلَ أهمُّ من السماء"},{"id":"c","text":"أنّ الأرضَ لا فائدة منها"},{"id":"d","text":"أنّ في مخلوقات الله دلائلَ على عظمته وقدرته ووحدانيّته"}]'::jsonb, 'd', 'تُعلّمنا الآياتُ أنّ النظر في الإبل والسماء والجبال والأرض يدلّنا على عظمة الله وقدرته ووحدانيّته، فنعبده وحده.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

