INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5cf1bc3c-7592-54a4-a9e1-43ccc71c4f1b', '1531d946-1344-54db-9e37-b4adb27d8ec9', 'تلميذٌ نظرَ إلى جملٍ في الصحراء يصبر على العطش ويحمل الأثقال، فقال: «سبحان الله! ما أعظمَ خالقَ هذا الجمل». أيَّ آيةٍ طبّق؟', '[{"id":"a","text":"وَإِلَى السَّمَاءِ كَيْفَ رُفِعَتْ"},{"id":"b","text":"فِيهَا سُرُرٌ مَّرْفُوعَةٌ"},{"id":"c","text":"تَصْلَىٰ نَارًا حَامِيَةً"},{"id":"d","text":"أَفَلَا يَنظُرُونَ إِلَى الْإِبِلِ كَيْفَ خُلِقَتْ"}]'::jsonb, 'd', 'طبّقَ آية ﴿أَفَلَا يَنظُرُونَ إِلَى الْإِبِلِ كَيْفَ خُلِقَتْ﴾ التي تدعو إلى التأمّل في خلق الإبل لمعرفة عظمة الله. الخطأ الشائع اختيارُ آيةِ السماء، والمشهدُ هنا عن الإبل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('035ed77e-0dec-502f-be57-97aa30f784fc', '1531d946-1344-54db-9e37-b4adb27d8ec9', 'قال أحدُهم: «الرسولُ ﷺ مُجبَرٌ أن يجعل كلَّ الناس مؤمنين، وإلّا فقد فشل». بِمَ نردّ عليه من سورة الغاشية؟', '[{"id":"a","text":"نوافقه، فالرسولُ ﷺ مسؤولٌ عن إيمان كلِّ الناس"},{"id":"b","text":"نردّ بقوله ﴿لَّسْتَ عَلَيْهِم بِمُصَيْطِرٍ﴾: مهمّتُه التذكيرُ لا الإكراه"},{"id":"c","text":"نقول إنّ السورةَ لم تذكر مهمّةَ الرسول ﷺ"},{"id":"d","text":"نقول إنّ الرسولَ ﷺ يُعذّب من لا يؤمن"}]'::jsonb, 'b', 'نردّ بقوله تعالى ﴿فَذَكِّرْ إِنَّمَا أَنتَ مُذَكِّرٌ ۝ لَّسْتَ عَلَيْهِم بِمُصَيْطِرٍ﴾: مهمّةُ الرسول ﷺ التذكيرُ والبلاغ، والهدايةُ بيد الله وحده. الخطأ الشائع تحميلُ الرسول ﷺ ما ليس من مهمّته.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8209477c-7078-57c6-a5ed-59b09c860aad', '1531d946-1344-54db-9e37-b4adb27d8ec9', 'خلطَ تلميذٌ فقال: «وجوهٌ ناعمةٌ خاشعةٌ في النار». أين الخطأ في كلامه؟', '[{"id":"a","text":"لا خطأ، فالوصفان للنار معًا"},{"id":"b","text":"الخطأ أنّ الوصفين معًا لأهل الجنّة"},{"id":"c","text":"«الناعمة» لأهل الجنّة و«الخاشعة» لأهل النار، فلا يجتمعان لفريقٍ واحد"},{"id":"d","text":"الخطأ أنّ السورةَ لم تذكر الوجوه أصلًا"}]'::jsonb, 'c', 'الوجوهُ «الخاشعة» الذليلة لأهل النار، والوجوهُ «الناعمة» المشرقة لأهل الجنّة، فلا يجتمع الوصفان لفريقٍ واحد. الخطأ الشائع الخلطُ بين وصف الفريقين.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('39247995-6b51-5e3d-8fe5-cedb799511b2', '1531d946-1344-54db-9e37-b4adb27d8ec9', 'أرادت معلّمةٌ أن تُرتّب آياتِ التأمّل بحسب ورودها في السورة. ما الترتيب الصحيح؟', '[{"id":"a","text":"الإبلُ، فالسماءُ، فالجبالُ، فالأرض"},{"id":"b","text":"الأرضُ، فالسماءُ، فالجبالُ، فالإبل"},{"id":"c","text":"السماءُ، فالأرضُ، فالإبلُ، فالجبال"},{"id":"d","text":"الجبالُ، فالإبلُ، فالأرضُ، فالسماء"}]'::jsonb, 'a', 'الترتيب في السورة: الإبل (17) فالسماء (18) فالجبال (19) فالأرض (20). الخطأ الشائع البدءُ بالسماء أو الأرض قبل الإبل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('29093447-d154-595d-80c1-9192f377f10a', '1531d946-1344-54db-9e37-b4adb27d8ec9', 'سمعَ طفلٌ بيوم القيامة (الغاشية) فخاف. ما العملُ الصحيح الذي تُرشده إليه السورة لينجو؟', '[{"id":"a","text":"أن ينسى أمرَ الآخرة ويلهو"},{"id":"b","text":"أن ييأس من رحمة الله"},{"id":"c","text":"أن يجمع المالَ فقط"},{"id":"d","text":"أن يعمل الصالحاتِ ليكون من أصحاب الوجوه الناعمة في الجنّة"}]'::jsonb, 'd', 'السورةُ تصف نعيمَ أهل الجنّة الراضين بسعيهم، فترشدنا إلى العمل الصالح لنكون منهم. الخطأ الشائع أن يقود الخوفُ إلى اليأس أو الغفلة، والصواب أن يقود إلى العمل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b8c82af7-0315-53cd-996f-189ce453a160', '1531d946-1344-54db-9e37-b4adb27d8ec9', 'ما الفكرةُ الجامعةُ التي تربط بين وصف يوم القيامة في أوّل السورة ودعوةِ التأمّل في الإبل والسماء والجبال والأرض في آخرها؟', '[{"id":"a","text":"أنّ القيامةَ والمخلوقاتِ موضوعان لا علاقة بينهما"},{"id":"b","text":"أنّ الذي خلق هذه المخلوقاتِ العظيمة قادرٌ على بعث الناس وحسابهم يوم القيامة"},{"id":"c","text":"أنّ الإبلَ والجبالَ ستدخل النار"},{"id":"d","text":"أنّ السماءَ أهمُّ من يوم القيامة"}]'::jsonb, 'b', 'الذي قدر على خلق الإبل والسماء والجبال والأرض قادرٌ على إحياء الناس وحسابهم يوم القيامة؛ فدلائلُ القدرة في الدنيا برهانٌ على البعث. الخطأ الشائع الفصلُ بين قدرة الله في الخلق وقدرته على البعث.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a8157a55-df46-54e3-9b61-9f1636b3d6a9', '166c6b9d-e706-53e0-a6fa-0867e0cc056b', 'education-islamique-4eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة لسورة الغاشية', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
