  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d83b81fe-f899-564e-990c-cca42535a998', 'a8157a55-df46-54e3-9b61-9f1636b3d6a9', 'سورة الغاشية سورةٌ مكّيّة، وعددُ آياتها ...', '[{"id":"a","text":"17 آية"},{"id":"b","text":"26 آية"},{"id":"c","text":"11 آية"},{"id":"d","text":"7 آيات"}]'::jsonb, 'b', 'سورة الغاشية مكّيّة عددُ آياتها 26 آية، نزلت على النبيّ محمّد ﷺ في مكّة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ba1d185-81cb-5268-b279-77f3209d8571', 'a8157a55-df46-54e3-9b61-9f1636b3d6a9', 'ما معنى «الضريع» الذي هو طعامُ أهل النار؟', '[{"id":"a","text":"نوعٌ من الفاكهة"},{"id":"b","text":"خبزٌ ولحم"},{"id":"c","text":"ماءٌ عذب"},{"id":"d","text":"نوعٌ من الشوك لا يُسمن ولا يُغني من جوع"}]'::jsonb, 'd', '«الضريع» نوعٌ من الشوك لا ترعاه الدوابُّ لخبثه، لا يُسمن آكلَه ولا يدفع عنه الجوع، وهو طعامُ أهل النار.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b6e8428e-b9f0-55ee-b8f5-53c99046b71f', 'a8157a55-df46-54e3-9b61-9f1636b3d6a9', 'ما معنى ﴿وَإِلَى الْجِبَالِ كَيْفَ نُصِبَتْ﴾؟', '[{"id":"a","text":"الجبالُ نُصبت راسياتٍ ثابتةً تُثبّت الأرض"},{"id":"b","text":"الجبالُ رُفعت إلى السماء"},{"id":"c","text":"الجبالُ بُسطت كالأرض"},{"id":"d","text":"الجبالُ خُلقت من ماء"}]'::jsonb, 'a', '«نُصبت» أي أُقيمت راسياتٍ ثابتةً تُثبّت الأرض، وهذا من دلائل قدرة الله. أمّا «رُفعت» فللسماء و«سُطحت» للأرض.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7111bd0e-34f3-5e7b-b05f-4bcc7a5de623', 'a8157a55-df46-54e3-9b61-9f1636b3d6a9', 'وصفت السورة وجوهَ أهل الجنّة بأنّها ﴿لِّسَعْيِهَا رَاضِيَةٌ﴾. ما معنى ذلك؟', '[{"id":"a","text":"نادمةٌ على ما عملت"},{"id":"b","text":"غافلةٌ عمّا عملت"},{"id":"c","text":"راضيةٌ بما عملته من خيرٍ في الدنيا"},{"id":"d","text":"خائفةٌ من الحساب"}]'::jsonb, 'c', '«لسعيها راضية» أي راضيةٌ مسرورةٌ بما قدّمت من عملٍ صالحٍ في الدنيا، فجزاها اللهُ الجنّة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2fabab98-ee4c-5cc6-be7f-fd215929d78e', 'a8157a55-df46-54e3-9b61-9f1636b3d6a9', 'تلميذٌ نظرَ إلى السماء فوقه بلا أعمدةٍ يراها، فتذكّر قدرة الله. أيَّ آيةٍ تذكّر؟', '[{"id":"a","text":"وَإِلَى الْأَرْضِ كَيْفَ سُطِحَتْ"},{"id":"b","text":"وَإِلَى السَّمَاءِ كَيْفَ رُفِعَتْ"},{"id":"c","text":"أَفَلَا يَنظُرُونَ إِلَى الْإِبِلِ كَيْفَ خُلِقَتْ"},{"id":"d","text":"وَإِلَى الْجِبَالِ كَيْفَ نُصِبَتْ"}]'::jsonb, 'b', 'تذكّرَ آية ﴿وَإِلَى السَّمَاءِ كَيْفَ رُفِعَتْ﴾ التي تدعو إلى التأمّل في رفع السماء فوقنا. الخطأ الشائع الخلطُ بينها وبين آيةِ الأرض أو الجبال.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46150f68-f2f5-5b11-b339-01c81a57c0de', 'a8157a55-df46-54e3-9b61-9f1636b3d6a9', 'بماذا ختم اللهُ السورة في قوله ﴿إِنَّ إِلَيْنَا إِيَابَهُمْ ۝ ثُمَّ إِنَّ عَلَيْنَا حِسَابَهُمْ﴾؟', '[{"id":"a","text":"أنّ الناسَ لا يُبعثون بعد الموت"},{"id":"b","text":"أنّ حسابَ الناس على الملائكة"},{"id":"c","text":"أنّ الإبلَ والجبالَ تُحاسَب"},{"id":"d","text":"أنّ رجوعَ الناس إلى الله وحسابَهم عليه وحده"}]'::jsonb, 'd', 'ختم اللهُ السورة بأنّ مرجعَ الخلق إليه («إيابهم» أي رجوعهم بالبعث)، وأنّ حسابَهم عليه وحده سبحانه. الخطأ الشائع ظنُّ أنّ الحسابَ إلى غير الله.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('aa7f2207-1054-5bea-aabb-24c3c3a5750b', '80900090-0982-51ca-80a9-b03563f99765', 'education-islamique-4eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24abf44a-3838-5851-bbbd-f0019801602a', 'aa7f2207-1054-5bea-aabb-24c3c3a5750b', 'لماذا يجب أن أحترم معلّمي وأُقدّره؟', '[{"id":"a","text":"لأنّه أكبرُ منّي سِنًّا فقط"},{"id":"b","text":"لأنّه يُعلّمني ويُربّيني ويأخذ بيدي إلى العلم النافع"},{"id":"c","text":"لأنّه جاري في الحيّ"},{"id":"d","text":"لأنّه يُعطيني المال"}]'::jsonb, 'b', 'نحترم المعلّم لأنّه يُعلّمنا ويُربّينا ويتعب من أجل نجاحنا، وهو بعد الوالدين يأخذ بأيدينا إلى العلم النافع. الخطأ الشائع ظنُّ أنّ الاحترام للسنّ وحده، وإنّما هو لِفضل المعلّم وعِلمه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3edf688e-ac67-5140-8522-6f701eaef8f7', 'aa7f2207-1054-5bea-aabb-24c3c3a5750b', 'ماذا أفعل والمعلّم يشرح الدرس؟', '[{"id":"a","text":"أتكلّم مع زميلي"},{"id":"b","text":"أنشغل باللّعب"},{"id":"c","text":"أُقاطعه كلّما أردت"},{"id":"d","text":"أُنصِت إليه باحترامٍ ولا أنشغل عنه"}]'::jsonb, 'd', 'من احترام المعلّم أن أُنصِت إليه وهو يشرح ولا أُقاطعه ولا أنشغل عنه. الخطأ الشائع الانشغالُ أو الكلامُ أثناء الشرح، وذلك من قلّة الأدب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('065fd633-e3bf-517b-8f88-9ca845f4b555', 'aa7f2207-1054-5bea-aabb-24c3c3a5750b', 'وجدتُ قلمَ زميلي على طاولته. ما الصواب؟', '[{"id":"a","text":"لا آخذه إلّا إذا أذِن لي، فهو مِلكُه"},{"id":"b","text":"آخذه لأنّي أحتاجه"},{"id":"c","text":"أُخفيه عنه مازحًا"},{"id":"d","text":"أكسره"}]'::jsonb, 'a', 'أدواتُ زميلي مِلكٌ له، فلا آخذ شيئًا منها إلّا بإذنه. الخطأ الشائع أخذُ متاع الغير بحجّة الحاجة أو المزاح، وهو اعتداءٌ على مِلك الآخرين.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b2579347-a78f-56b1-be63-c2ba41594604', 'aa7f2207-1054-5bea-aabb-24c3c3a5750b', 'هل يجوز أن أكتب على طاولة القسم أو على الجدران؟', '[{"id":"a","text":"نعم، فهي مِلكي"},{"id":"b","text":"نعم، إذا كان القلم جميلًا"},{"id":"c","text":"لا، فالطاولات والجدران تجهيزاتٌ أمانةٌ أُحافظ عليها"},{"id":"d","text":"نعم، ما دام أحدٌ لا يراني"}]'::jsonb, 'c', 'الطاولاتُ والجدرانُ من تجهيزات المدرسة، وهي أمانةٌ في عنقي أُحافظ عليها لِيَنتفع بها غيري بعدي. الخطأ الشائع الكتابةُ والخدشُ عليها بظنّ أنّها مِلكٌ خاصّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d70f75b2-2fcf-54cd-a7ea-c7f90b5de91f', 'aa7f2207-1054-5bea-aabb-24c3c3a5750b', 'أكمل قول رسول الله ﷺ: «لَيْسَ مِنَّا مَنْ لَمْ يَرْحَمْ صَغِيرَنَا وَ...»', '[{"id":"a","text":"يُطعِمْ جائعَنا"},{"id":"b","text":"يُوَقِّرْ كَبِيرَنَا"},{"id":"c","text":"يَزُرْ مريضَنا"},{"id":"d","text":"يُساعِدْ فقيرَنا"}]'::jsonb, 'b', 'الحديث: «ليس منّا من لم يرحم صغيرنا ويُوقّر كبيرنا»، أي نرحم الصغير ونحترم الكبير، ومعلّمي من الكبار الذين أُوقّرهم. الخطأ الشائع نسيانُ «يُوقّر كبيرنا» بعد «يرحم صغيرنا».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('8fbc6c91-f698-5273-b446-6e3197cd095d', '80900090-0982-51ca-80a9-b03563f99765', 'education-islamique-4eme', '⭐ تمرين: أحترم معلّمي وأصون مدرستي', 1, 50, 10, 'practice', 'admin', 1)
