INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d0bbfdcd-a9a2-5f8c-a70f-4d07a4269165', '8fbc6c91-f698-5273-b446-6e3197cd095d', 'عند لقاء معلّمي صباحًا ...', '[{"id":"a","text":"أتجاهله"},{"id":"b","text":"أُحيّيه بالسلام وأبتسم له"},{"id":"c","text":"أُديره ظهري"},{"id":"d","text":"أرفع صوتي عليه"}]'::jsonb, 'b', 'من احترام المعلّم أن أُحيّيه بالسلام وأبتسم له عند لقائه. الخطأ الشائع تجاهلُ المعلّم أو عدمُ تحيّته.', 1)
