  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b425a4f-4929-5afe-be2e-fbb52f4b484c', '8fbc6c91-f698-5273-b446-6e3197cd095d', 'إذا أردتُ أن أسأل المعلّم في القسم ...', '[{"id":"a","text":"أصيح بأعلى صوتي"},{"id":"b","text":"أتكلّم دون إذن"},{"id":"c","text":"أرفع يدي وأنتظر الإذن"},{"id":"d","text":"أقاطع زميلي"}]'::jsonb, 'c', 'من الأدب مع المعلّم أن أرفع يدي إذا أردتُ السؤال أو الإجابة، وأنتظر إذنه. الخطأ الشائع الكلامُ دون استئذانٍ أو الصياح.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
