  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6cd4332b-d95f-59ed-92b0-eadd8d1ec5fc', '8fbc6c91-f698-5273-b446-6e3197cd095d', 'كتابُ زميلي وقلمُه وكرّاسُه هي ...', '[{"id":"a","text":"مِلكٌ له، لا أعبث بها"},{"id":"b","text":"مِلكي أنا"},{"id":"c","text":"مِلكٌ للجميع نأخذه بلا إذن"},{"id":"d","text":"أشياءُ لا قيمة لها"}]'::jsonb, 'a', 'أدواتُ زميلي مِلكٌ له، فلا أعبث بها ولا آخذها دون إذن. الخطأ الشائع ظنُّ أنّ متاع الزميل يجوز أخذُه بلا إذن.', 3)
ON CONFLICT (id) DO UPDATE SET
