  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7b251ed5-4c16-54aa-ba35-1385eab29635', '8fbc6c91-f698-5273-b446-6e3197cd095d', 'الطاولاتُ والكراسي والسبّورة في المدرسة هي ...', '[{"id":"a","text":"أشياءُ نكسرها كما نشاء"},{"id":"b","text":"مِلكٌ خاصٌّ بي"},{"id":"c","text":"لا تهمّني"},{"id":"d","text":"تجهيزاتٌ أمانةٌ أُحافظ عليها"}]'::jsonb, 'd', 'تجهيزاتُ المدرسة أمانةٌ هُيِّئت لنا، أُحافظ عليها لِيَنتفع بها غيري بعدي. الخطأ الشائع العبثُ بها بظنّ أنّها مِلكٌ خاصّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('92ce2a6a-2e7d-5723-90ba-2b39ed473daf', '8fbc6c91-f698-5273-b446-6e3197cd095d', 'بعد أن أشرب الماء أو أتوضّأ، ...', '[{"id":"a","text":"أترك الصنبور مفتوحًا"},{"id":"b","text":"أُغلق الصنبور حتّى لا يضيع الماء"},{"id":"c","text":"أرشّ الماء على زملائي"},{"id":"d","text":"أكسر الصنبور"}]'::jsonb, 'b', 'من المحافظة على مرافق المدرسة أن أُغلق الصنبور بعد استعماله حتّى لا يضيع الماء. الخطأ الشائع تركُ الصنبور مفتوحًا فيضيع الماء.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
