  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b878b57a-bd5b-5928-ba85-344f9f69cb09', '8fbc6c91-f698-5273-b446-6e3197cd095d', 'أين أُلقي ورقةً متّسخةً في المدرسة؟', '[{"id":"a","text":"على أرض القسم"},{"id":"b","text":"في السّاحة"},{"id":"c","text":"في سلّة المهملات"},{"id":"d","text":"تحت الطاولة"}]'::jsonb, 'c', 'أُلقي الأوساخَ في سلّة المهملات حفاظًا على نظافة المدرسة. الخطأ الشائع رميُ الأوساخ في القسم أو السّاحة.', 6)
