  ('603b49cb-bf39-5fc7-96ef-e5a43f589b12', '80900090-0982-51ca-80a9-b03563f99765', 'education-islamique-4eme', '⚔️ زعيم الفصل ⭐⭐⭐: حارسُ القسم الأمين', 3, 120, 30, 'boss', 'admin', 2)
