INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('444f1f5c-55d1-59f2-b41e-161c9a3fa5c4', '603b49cb-bf39-5fc7-96ef-e5a43f589b12', 'رأى تلميذٌ معلّمَه يحمل كُتبًا كثيرة. ما التصرّفُ الذي يدلّ على حُسن الأدب؟', '[{"id":"a","text":"يتركه ويذهب للّعب"},{"id":"b","text":"يُسارع لمساعدته بأدبٍ واحترام"},{"id":"c","text":"يضحك عليه"},{"id":"d","text":"يطلب منه أجرًا مقابل المساعدة"}]'::jsonb, 'b', 'من توقير المعلّم مساعدتُه وخدمتُه بأدبٍ واحترام. الخطأ الشائع التهاونُ في إكرام المعلّم أو طلبُ مقابلٍ على خدمته.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3d44d9f6-217e-538c-ba1a-77a0b481521e', '603b49cb-bf39-5fc7-96ef-e5a43f589b12', 'استعار تلميذٌ مِسطرةَ زميله. متى وكيف يردّها؟', '[{"id":"a","text":"لا يردّها أبدًا"},{"id":"b","text":"يردّها مكسورةً"},{"id":"c","text":"يحتفظ بها لنفسه"},{"id":"d","text":"يردّها إليه سليمةً ويشكره"}]'::jsonb, 'd', 'إذا استعرتُ شيئًا من زميلي أُعيده إليه سليمًا وأشكره، فهو أمانةٌ عندي. الخطأ الشائع التساهلُ في ردّ العاريّة أو إعادتُها تالفة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cd571bd5-ce22-54f5-8de4-7c56e4552c60', '603b49cb-bf39-5fc7-96ef-e5a43f589b12', 'ما معنى أنّ تجهيزات المدرسة «أمانةٌ» في عنقي؟', '[{"id":"a","text":"أنتفع بها وأصونها لِيَنتفع بها غيري بعدي"},{"id":"b","text":"أنّها مِلكي أتصرّف فيها كما أشاء"},{"id":"c","text":"أنّها لا تخصّني فلا تهمّني"},{"id":"d","text":"أنّ لي أن أبيعها"}]'::jsonb, 'a', 'كونُها أمانةً يعني أنّي أنتفع بها وأحافظ عليها لِيَنتفع بها التلاميذُ بعدي، فلا أُتلِفها ولا أتملّكها. الخطأ الشائع التعاملُ مع المال العامّ كأنّه مِلكٌ خاصّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b7a54ba6-1eb7-57bf-a640-79ba1dd9ac6a', '603b49cb-bf39-5fc7-96ef-e5a43f589b12', 'وجد تلميذٌ صديقَه يخدش الطاولة بالقلم. ما الأصحّ أن يفعل؟', '[{"id":"a","text":"يُشاركه في الخدش"},{"id":"b","text":"يضحك ويشجّعه"},{"id":"c","text":"ينصحه برِفقٍ أنّ الطاولة أمانةٌ لا تُخدَش"},{"id":"d","text":"يكتب هو أيضًا على الجدار"}]'::jsonb, 'c', 'أنصح زميلي برِفقٍ بالمحافظة على التجهيزات، فالطاولةُ أمانةٌ لا نخدشها. الخطأ الشائع مجاراةُ المخطئ أو تشجيعُه بدل نصحه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('29f07662-8612-509d-8aad-c95cd802066e', '603b49cb-bf39-5fc7-96ef-e5a43f589b12', 'أكمل قول رسول الله ﷺ: «أَدِّ الْأَمَانَةَ إِلَى مَنِ ...»', '[{"id":"a","text":"خانَكَ"},{"id":"b","text":"ظَلَمَكَ"},{"id":"c","text":"سَبَقَكَ"},{"id":"d","text":"ائْتَمَنَكَ"}]'::jsonb, 'd', 'الحديث: «أدِّ الأمانة إلى من ائتمنك»، أي رُدَّ إلى الناس ما حفظوه عندك أو ائتمنوك عليه. الخطأ الشائع الخلطُ بين «ائتمنك» وغيرها من الكلمات.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('33c62e01-0f09-536e-a769-21c8b75a33b7', '603b49cb-bf39-5fc7-96ef-e5a43f589b12', 'أيُّ هذه التصرّفات يدلّ على تلميذٍ يصون مدرسته؟', '[{"id":"a","text":"يكتب اسمه على الجدار"},{"id":"b","text":"يُلقي الأوساخ في السلّة ويُغلق الصنبور"},{"id":"c","text":"يكسر الكرسيّ بعد الدرس"},{"id":"d","text":"يُمزّق كتاب المكتبة"}]'::jsonb, 'b', 'الذي يصون مدرسته يُحافظ على نظافتها ومرافقها، فيُلقي الأوساخ في السلّة ويُغلق الصنبور. الخطأ الشائع ظنُّ أنّ إتلاف التجهيزات أمرٌ هيّنٌ لا يضرّ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

