INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fc3a107d-5242-5921-bf00-dc958af3faaa', '25311be8-e9ac-5e31-b03b-acb4b3403b7c', 'المعلّمُ بعد الوالدين هو الذي ...', '[{"id":"a","text":"يُلهينا عن الدرس"},{"id":"b","text":"يبيع لنا الأدوات"},{"id":"c","text":"يأخذ بأيدينا إلى العلم النافع"},{"id":"d","text":"يلعب معنا فقط"}]'::jsonb, 'c', 'المعلّمُ بعد الوالدين يُعلّمنا ويُربّينا ويأخذ بأيدينا إلى العلم النافع، فنحترمه ونُقدّره. الخطأ الشائع التقليلُ من فضل المعلّم.', 1)
