INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c903b949-9f19-596a-b4fa-08581cd2137f', '25311be8-e9ac-5e31-b03b-acb4b3403b7c', 'من احترام المعلّم أثناء الدرس ...', '[{"id":"a","text":"الإنصاتُ إليه وعدمُ مقاطعته"},{"id":"b","text":"اللّعبُ بالأدوات"},{"id":"c","text":"الحديثُ مع الزملاء"},{"id":"d","text":"النومُ في القسم"}]'::jsonb, 'a', 'من احترام المعلّم الإنصاتُ إليه وهو يشرح وعدمُ مقاطعته أو الانشغال عنه. الخطأ الشائع الكلامُ أو اللّعب أثناء الشرح.', 2)
