INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cee98bda-3ace-5b82-95e1-7dca0dd8da84', '25311be8-e9ac-5e31-b03b-acb4b3403b7c', 'نُحافظ على متاع زملائنا وتجهيزات مدرستنا ...', '[{"id":"a","text":"في القسم فقط دون السّاحة"},{"id":"b","text":"في السّاحة فقط دون القسم"},{"id":"c","text":"في القسم وفي السّاحة على السواء"},{"id":"d","text":"عند حضور المعلّم فقط"}]'::jsonb, 'c', 'نُحافظ على متاع الغير وتجهيزات المدرسة في كلّ مكانٍ: في القسم وفي السّاحة، سواء حضر المعلّم أو غاب. الخطأ الشائع حصرُ الأدب بمكانٍ أو بحضور المعلّم.', 5)
