INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('e236a843-6703-5c15-aa58-ec12c8211d93', '80900090-0982-51ca-80a9-b03563f99765', 'education-islamique-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: تلميذُ المدرسة الأمين', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
