INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('40fa014b-70f2-5913-b456-20fc48a65a76', 'e236a843-6703-5c15-aa58-ec12c8211d93', 'دخل المعلّمُ القسمَ فقام التلاميذ يحترمونه، لكنّ تلميذًا بقي يلعب ويتكلّم. بماذا تنصحه؟', '[{"id":"a","text":"أنّه أحسن، فاللّعب أهمّ"},{"id":"b","text":"أن يُنصِت للمعلّم ويحترمه كما يفعل زملاؤه"},{"id":"c","text":"أن يرفع صوته أكثر"},{"id":"d","text":"أن يخرج من القسم"}]'::jsonb, 'b', 'من توقير المعلّم الإنصاتُ إليه واحترامُه عند دخوله، فأنصح زميلي بذلك. الخطأ الشائع الانشغالُ باللّعب والكلام أثناء حضور المعلّم.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a6f5ced1-581b-5fb6-940f-1dddc22a9e44', 'e236a843-6703-5c15-aa58-ec12c8211d93', 'أراد تلاميذُ القسم أن يكون قسمُهم نظيفًا جميلًا طوال السنة. ما الطريقُ إلى ذلك؟', '[{"id":"a","text":"أن يحرص كلٌّ منهم على النظافة والمحافظة على التجهيزات"},{"id":"b","text":"أن ينتظروا عامل النظافة وحده"},{"id":"c","text":"أن يكتبوا على الجدران رسومًا"},{"id":"d","text":"أن يتركوا الأوساخ في السّاحة"}]'::jsonb, 'a', 'نظافةُ القسم وسلامةُ تجهيزاته مسؤوليّةُ كلّ تلميذ، فيحرص الجميع على النظافة والمحافظة. الخطأ الشائع إلقاءُ المسؤوليّة كلِّها على عامل النظافة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a20ace74-01e5-5197-a572-c0c8b0b93416', 'e236a843-6703-5c15-aa58-ec12c8211d93', 'نسي تلميذٌ كرّاسَه فأراد أن يأخذ كرّاسَ زميله الغائب ليكتب فيه. ما الصواب؟', '[{"id":"a","text":"يأخذه ويكتب فيه ما دام صاحبُه غائبًا"},{"id":"b","text":"يُمزّق منه ورقةً"},{"id":"c","text":"لا يأخذه؛ فهو مِلكُ زميله ولا يجوز أخذُه دون إذن"},{"id":"d","text":"يبيعه لزميلٍ آخر"}]'::jsonb, 'c', 'كرّاسُ الزميل مِلكُه، وغيابُه لا يُبيح أخذَ متاعه دون إذن. الخطأ الشائع استباحةُ متاع الغير بحجّة غياب صاحبه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ce6233ec-da4a-5d65-82ec-16870ba409c9', 'e236a843-6703-5c15-aa58-ec12c8211d93', 'وجد تلميذٌ محفظةَ زميلٍ ضائعةً في السّاحة فيها نقودٌ وكتب. ما التصرّفُ الأمين؟', '[{"id":"a","text":"يأخذ ما فيها لنفسه"},{"id":"b","text":"يتركها ويمشي"},{"id":"c","text":"يُخفيها عن صاحبها"},{"id":"d","text":"يردّها إلى صاحبها أو يُسلّمها للمعلّم، فهي أمانة"}]'::jsonb, 'd', 'ما وجدتُه من متاع الغير أمانةٌ أردّه إلى صاحبه أو أُسلّمه للمعلّم، عملًا بقوله ﷺ: «أدِّ الأمانة إلى من ائتمنك». الخطأ الشائع أخذُ ما يُعثَر عليه بحجّة أنّه «لُقطة».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('67ffa22f-145f-5ce4-a6c4-22b99f879c39', 'e236a843-6703-5c15-aa58-ec12c8211d93', 'استعار تلميذٌ كتابًا من مكتبة المدرسة. كيف يكون أمينًا معه؟', '[{"id":"a","text":"يكتب على صفحاته ملاحظاته"},{"id":"b","text":"يُمزّق منه ما لا يُعجبه"},{"id":"c","text":"يُحافظ عليه نظيفًا ويُعيده في وقته سليمًا"},{"id":"d","text":"يحتفظ به ولا يُعيده"}]'::jsonb, 'c', 'كتابُ المكتبة أمانةٌ، أُحافظ عليه نظيفًا سليمًا وأُعيده في وقته لِيَنتفع به غيري. الخطأ الشائع الكتابةُ على الكتب العامّة أو إتلافُها أو حبسُها.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7b3d3bf2-d228-55b6-8f35-d0cf8f525c13', 'e236a843-6703-5c15-aa58-ec12c8211d93', 'قال رسول الله ﷺ: «ليس منّا من لم يرحم صغيرنا ويُوقّر كبيرنا». كيف نطبّق «توقير الكبير» في المدرسة؟', '[{"id":"a","text":"بالسخرية من المعلّم والعاملين"},{"id":"b","text":"باحترام المعلّم والإداريّين والعاملين وتقديرهم"},{"id":"c","text":"بتجاهلهم جميعًا"},{"id":"d","text":"برفع الصوت عليهم"}]'::jsonb, 'b', 'توقيرُ الكبير في المدرسة يكون باحترام المعلّم والإداريّين والعاملين وتقديرهم، فهم من الكبار الذين أمرنا النبيّ ﷺ بتوقيرهم. الخطأ الشائع حصرُ الاحترام في موضعٍ دون غيره أو السخريةُ من العاملين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('7e8cd744-0a28-5cc8-b941-982e9042dd48', '80900090-0982-51ca-80a9-b03563f99765', 'education-islamique-4eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة لواجب المتعلّم نحو معلّمه ومدرسته', 3, 120, 30, 'boss', 'admin', 5)
