  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('903c4f9e-2a81-5ffa-b1f2-cb6236822ccd', '7e8cd744-0a28-5cc8-b941-982e9042dd48', 'أحترمُ معلّمي لأنّه ...', '[{"id":"a","text":"يُعطيني الحلوى"},{"id":"b","text":"يسكن قريبًا منّي"},{"id":"c","text":"أطولُ منّي قامةً"},{"id":"d","text":"يُعلّمني ويُربّيني ويتعب من أجل نجاحي"}]'::jsonb, 'd', 'نحترم المعلّم لِفضله: فهو يُعلّمنا ويُربّينا ويتعب من أجل نجاحنا. الخطأ الشائع ربطُ الاحترام بالمصلحة أو بالقامة بدل العِلم والفضل.', 1)
ON CONFLICT (id) DO UPDATE SET
