  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d7a29590-dd9b-565c-8489-6663aae7755f', '7e8cd744-0a28-5cc8-b941-982e9042dd48', 'من الأدب مع المعلّم في القسم ...', '[{"id":"a","text":"أن أُقاطعه كلّما تكلّم"},{"id":"b","text":"أن ألعب أثناء الشرح"},{"id":"c","text":"أن أرفع يدي للسؤال وأُنفّذ إرشاداته"},{"id":"d","text":"أن أرفع صوتي عليه"}]'::jsonb, 'c', 'من الأدب مع المعلّم رفعُ اليد للسؤال وتنفيذُ إرشاداته والإنصاتُ إليه. الخطأ الشائع المقاطعةُ أو اللّعب أو رفعُ الصوت.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a39bd66d-2f11-5f4a-ae97-40304f5cdbed', '7e8cd744-0a28-5cc8-b941-982e9042dd48', 'متاعُ زميلي (كتابُه وأدواتُه) أتعامل معه على أنّه ...', '[{"id":"a","text":"مِلكي آخذه متى شئت"},{"id":"b","text":"أمانةٌ ومِلكٌ له لا أعبث به ولا آخذه بلا إذن"},{"id":"c","text":"بلا صاحب"},{"id":"d","text":"شيءٌ يجوز إتلافه"}]'::jsonb, 'b', 'متاعُ زميلي مِلكُه وأمانةٌ، لا أعبث به ولا آخذه إلّا بإذنه، وأُعيده سليمًا. الخطأ الشائع التعاملُ مع متاع الغير بلا احترامٍ لمِلكيّته.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e7fdac7d-27ea-51d1-9a12-4972e67e7f7c', '7e8cd744-0a28-5cc8-b941-982e9042dd48', 'ما الذي يدلّ على تلميذٍ يُحافظ على تجهيزات مدرسته؟', '[{"id":"a","text":"لا يكتب على الطاولات والجدران ولا يكسر الكراسي"},{"id":"b","text":"يخدش السبّورة"},{"id":"c","text":"يُمزّق الكتب"},{"id":"d","text":"يكسر الصنبور"}]'::jsonb, 'a', 'المحافظةُ على التجهيزات تكون بترك الكتابة على الطاولات والجدران، وعدم كسر الكراسي والأدوات. الخطأ الشائع عَدُّ إتلاف التجهيزات أمرًا هيّنًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bb63c621-26a8-5fb2-a570-aab55256a211', '7e8cd744-0a28-5cc8-b941-982e9042dd48', 'ما الحديثُ الذي يدلّ على وجوب ردّ متاع الغير إلى أصحابه؟', '[{"id":"a","text":"«المسلمُ من سَلِمَ المسلمون من لسانه ويده»"},{"id":"b","text":"«أفشُوا السلامَ بينكم تحابُّوا»"},{"id":"c","text":"«الصلاةُ عمادُ الدين»"},{"id":"d","text":"«أدِّ الأمانةَ إلى من ائتمنك»"}]'::jsonb, 'd', 'قوله ﷺ: «أدِّ الأمانة إلى من ائتمنك» يدلّ على وجوب ردّ ما يُؤتمن عليه الإنسان إلى أصحابه، ومنه متاعُ الزملاء وتجهيزاتُ المدرسة. الخطأ الشائع الخلطُ بين الأحاديث في موضوعاتها.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bee49a36-7ee2-5efe-9196-fabb06439d1d', '7e8cd744-0a28-5cc8-b941-982e9042dd48', 'خرج التلاميذ إلى السّاحة، فأين يكون واجبُ المحافظة على المتاع والنظافة؟', '[{"id":"a","text":"يسقط الواجبُ في السّاحة"},{"id":"b","text":"في القسم فقط"},{"id":"c","text":"في القسم وفي السّاحة معًا"},{"id":"d","text":"عند المعلّم فقط"}]'::jsonb, 'c', 'واجبُ المحافظة على المتاع والنظافة قائمٌ في القسم وفي السّاحة معًا، حضر المعلّم أو غاب. الخطأ الشائع ظنُّ أنّ الأدب يقتصر على القسم أو على حضور المعلّم.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

