INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd59d44f-9c3b-5a35-b2c8-9eb331011cfc', '66170999-46e6-5184-a216-dae22961df31', 'كم عددُ آيات سورة الأعلى؟', '[{"id":"a","text":"8 آيات"},{"id":"b","text":"30 آية"},{"id":"c","text":"19 آية"},{"id":"d","text":"11 آية"}]'::jsonb, 'c', 'سورة الأعلى سورةٌ مكّيّة عددُ آياتها 19 آية، وأوّلها: سَبِّحِ اسْمَ رَبِّكَ الْأَعْلَىٰ.', 1)
