INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4f1c9c38-987a-5fb5-aec4-9b0e4849a239', '66170999-46e6-5184-a216-dae22961df31', 'بِمَ أمرَنا الله في أوّل سورة الأعلى؟', '[{"id":"a","text":"بالنوم الطويل"},{"id":"b","text":"بكثرة اللعب"},{"id":"c","text":"بترك الصلاة"},{"id":"d","text":"بتسبيح اسمه الأعلى"}]'::jsonb, 'd', 'بدأت السورة بقول الله: سَبِّحِ اسْمَ رَبِّكَ الْأَعْلَىٰ، أي نزّهْ ومجّدْ ربَّك الأعلى. وبهذا الأمر سُمّيت السورة «الأعلى».', 2)
ON CONFLICT (id) DO UPDATE SET
