INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b12f1702-2647-5d06-9655-2a6059737fb8', '66170999-46e6-5184-a216-dae22961df31', 'قال الله لنبيّه ﷺ: «سَنُقْرِئُكَ فَلَا تَنسَىٰ». ما معنى هذا الوعد؟', '[{"id":"a","text":"سنحفظ لك القرآن في صدرك فلا تنساه"},{"id":"b","text":"سننسيك بعضَ القرآن"},{"id":"c","text":"ستقرأ كتبًا غير القرآن"},{"id":"d","text":"لن تقرأ شيئًا أبدًا"}]'::jsonb, 'a', 'معنى سَنُقْرِئُكَ فَلَا تَنسَىٰ أنّ الله سيُقرئ نبيَّه ﷺ القرآن ويحفظه له فلا ينساه، وهذا من عناية الله برسوله ﷺ.', 3)
ON CONFLICT (id) DO UPDATE SET
