  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('386614c2-4c5c-589f-9472-d2da99a2eb99', '66170999-46e6-5184-a216-dae22961df31', 'قال الله: «قَدْ أَفْلَحَ مَن تَزَكَّىٰ». من هو الذي أفلح وفاز؟', '[{"id":"a","text":"من جمع المال الكثير"},{"id":"b","text":"من طهّر نفسه وذكر ربّه وصلّى"},{"id":"c","text":"من نام ولم يعمل شيئًا"},{"id":"d","text":"من آثَرَ الدنيا على الآخرة"}]'::jsonb, 'b', 'قال الله: قَدْ أَفْلَحَ مَن تَزَكَّىٰ وَذَكَرَ اسْمَ رَبِّهِ فَصَلَّىٰ، أي فاز من طهّر نفسه من الذنوب وذكر الله وأقام الصلاة.', 4)
