INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('40e78270-79fe-5af0-ba24-3e1135f77d04', '3e88253c-8875-5129-89ee-15c7a517ee4e', 'ما الترتيب الصحيح لأوائل آيات سورة الأعلى بعد البَسملة؟', '[{"id":"a","text":"الَّذِي خَلَقَ فَسَوَّىٰ ثمّ سَبِّحِ اسْمَ رَبِّكَ"},{"id":"b","text":"وَالَّذِي أَخْرَجَ الْمَرْعَىٰ ثمّ سَبِّحِ اسْمَ رَبِّكَ"},{"id":"c","text":"سَبِّحِ اسْمَ رَبِّكَ الْأَعْلَىٰ ثمّ الَّذِي خَلَقَ فَسَوَّىٰ"},{"id":"d","text":"قَدْ أَفْلَحَ مَن تَزَكَّىٰ ثمّ الَّذِي خَلَقَ"}]'::jsonb, 'c', 'ترتيب الآيات: سَبِّحِ اسْمَ رَبِّكَ الْأَعْلَىٰ، ثمّ الَّذِي خَلَقَ فَسَوَّىٰ، ثمّ وَالَّذِي قَدَّرَ فَهَدَىٰ. الخطأ الشائع تقديمُ آية الخلق على آية الأمر بالتسبيح.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('defc9059-da54-5515-b0c2-a93f12e61b23', '3e88253c-8875-5129-89ee-15c7a517ee4e', 'قال الله: «وَالَّذِي أَخْرَجَ الْمَرْعَىٰ». ما معنى «الْمَرْعَىٰ»؟', '[{"id":"a","text":"العشبُ الأخضر الذي ترعاه الحيوانات"},{"id":"b","text":"الجبالُ العالية"},{"id":"c","text":"ماءُ البحر"},{"id":"d","text":"نجومُ السماء"}]'::jsonb, 'a', 'أخرج المرعى أي أنبتَ العشبَ رطبًا غضًّا ترعاه الحيوانات، وهذا دليلٌ على قدرة الله. الخطأ الشائع ظنّ أنّ المرعى جبلٌ أو ماء.', 2)
ON CONFLICT (id) DO UPDATE SET
