  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9f0a6173-b8f6-50b5-a8c6-f389e5cd62b0', '3e88253c-8875-5129-89ee-15c7a517ee4e', 'قال الله: «فَجَعَلَهُ غُثَآءً أَحْوَىٰ». ما معنى «غُثَآءً»؟', '[{"id":"a","text":"ماءً عذبًا"},{"id":"b","text":"ثمرًا ناضجًا"},{"id":"c","text":"زهرًا جميلًا"},{"id":"d","text":"يابسًا هشيمًا بعد أن كان أخضر"}]'::jsonb, 'd', 'غُثَآءً أَحْوَىٰ أي صار العشبُ يابسًا هشيمًا ضاربًا إلى السّواد بعد أن كان أخضر، وهذا من تدبير الله. الخطأ الشائع ظنّ أنّ الغثاء شيءٌ طريّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
