  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('85f35149-1d19-54d3-a52c-ec0803af85dc', '3e88253c-8875-5129-89ee-15c7a517ee4e', 'قال الله: «إِنَّهُ يَعْلَمُ الْجَهْرَ وَمَا يَخْفَىٰ». ماذا يعني ذلك؟', '[{"id":"a","text":"أنّ الله يعلم الجهرَ فقط"},{"id":"b","text":"أنّ الله يعلم ما نُعلنه وما نُخفيه جميعًا"},{"id":"c","text":"أنّ الله لا يعلم الغيب"},{"id":"d","text":"أنّ الله يعلم ما يخفى فقط"}]'::jsonb, 'b', 'يَعْلَمُ الْجَهْرَ وَمَا يَخْفَىٰ أي يعلم ما نُجهر به ونُعلنه وما نُسرّه ونُخفيه، فعِلمُ الله شاملٌ كلَّ شيء. الخطأ الشائع حصرُ عِلم الله في الظاهر وحده.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('761b2cad-8363-5b95-b1ef-1c023a2203d9', '3e88253c-8875-5129-89ee-15c7a517ee4e', 'قال الله: «فَذَكِّرْ إِن نَّفَعَتِ الذِّكْرَىٰ». من الذي ينتفع بالموعظة والتذكير؟', '[{"id":"a","text":"من يجمع المال"},{"id":"b","text":"من يلعب كثيرًا"},{"id":"c","text":"من يخشى الله"},{"id":"d","text":"الكافرُ المُعرض وحده"}]'::jsonb, 'c', 'قال الله بعدها: سَيَذَّكَّرُ مَن يَخْشَىٰ، فالذي يخشى الله ينتفع بالموعظة ويتذكّر، أمّا الأشقى فيُعرض. الخطأ الشائع ظنّ أنّ الموعظة تنفع المُعرض الكافر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3751efde-b80d-51c6-b43f-15c710144474', '3e88253c-8875-5129-89ee-15c7a517ee4e', 'قال الله عن نبيّه ﷺ: «سَنُقْرِئُكَ فَلَا تَنسَىٰ». على ماذا يدلّ هذا؟', '[{"id":"a","text":"على عناية الله بنبيّه ﷺ وحفظِه القرآنَ له"},{"id":"b","text":"على أنّ النبيّ ﷺ سينسى القرآن"},{"id":"c","text":"على أنّ القرآن كتابٌ عاديّ"},{"id":"d","text":"على أنّ النبيّ ﷺ لن يبلّغ الرسالة"}]'::jsonb, 'a', 'سَنُقْرِئُكَ فَلَا تَنسَىٰ تدلّ على عناية الله بنبيّه محمّد ﷺ، إذ حفظ له القرآن في صدره فلا ينساه. الخطأ الشائع فهمُ الآية على عكس معناها.', 6)
