INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c550f82b-41bb-5aa6-879f-b87a2af3bd25', '109a2883-3f10-5844-aa57-c0413bc05afb', '«وَالْآخِرَةُ خَيْرٌ وَأَبْقَىٰ» معناها أنّ الآخرة ...', '[{"id":"a","text":"أقلُّ نفعًا من الدنيا"},{"id":"b","text":"تنتهي سريعًا"},{"id":"c","text":"مثلُ الدنيا تمامًا"},{"id":"d","text":"خيرٌ وأنفع، وتدوم ولا تنتهي"}]'::jsonb, 'd', 'خَيْرٌ وَأَبْقَىٰ أي الآخرة خيرٌ وأنفعُ من الدنيا، وأبقى أي دائمةٌ لا تنتهي، فلا نُؤثر الدنيا الفانية عليها.', 5)
