  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4148c015-94eb-5744-ac21-d6476552b58e', '109a2883-3f10-5844-aa57-c0413bc05afb', 'ختمت السورة بأنّ هذه المعاني موجودةٌ في صُحف ...', '[{"id":"a","text":"كلِّ الناس"},{"id":"b","text":"إبراهيم وموسى عليهما السلام"},{"id":"c","text":"الشعراء والكتّاب"},{"id":"d","text":"لا أحد"}]'::jsonb, 'b', 'قال الله: إِنَّ هَٰذَا لَفِي الصُّحُفِ الْأُولَىٰ، صُحُفِ إِبْرَاهِيمَ وَمُوسَىٰ، فهذه حقائقُ ثابتةٌ في كتب الأنبياء.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('49aa6fb2-24e2-55ac-8afe-0140c6edf297', '588bcd9a-b7be-5c35-9ffe-92da860f6f2a', 'education-islamique-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: بطلُ سورة الأعلى', 4, 300, 60, 'challenge', 'admin', 4)
