INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2428741a-4e0d-5265-960c-09216e6077b6', '49aa6fb2-24e2-55ac-8afe-0140c6edf297', 'أرادَ تلميذٌ أن يستظهر سورة الأعلى. ما أوّلُ آيةٍ يقرؤها بعد البَسملة؟', '[{"id":"a","text":"سَبِّحِ اسْمَ رَبِّكَ الْأَعْلَىٰ"},{"id":"b","text":"قَدْ أَفْلَحَ مَن تَزَكَّىٰ"},{"id":"c","text":"وَالْآخِرَةُ خَيْرٌ وَأَبْقَىٰ"},{"id":"d","text":"صُحُفِ إِبْرَاهِيمَ وَمُوسَىٰ"}]'::jsonb, 'a', 'أوّل آيةٍ في سورة الأعلى هي: سَبِّحِ اسْمَ رَبِّكَ الْأَعْلَىٰ. الخطأ الشائع البدءُ بآيةٍ من وسط السورة أو آخرها.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('696667a9-31d7-5774-af81-0be962b0decd', '49aa6fb2-24e2-55ac-8afe-0140c6edf297', 'قال تلميذٌ: «الموعظة تنفع كلَّ الناس بلا استثناء». ما الصواب وفق السورة؟', '[{"id":"a","text":"كلامُه صحيحٌ تمامًا"},{"id":"b","text":"لا تنفع أحدًا أبدًا"},{"id":"c","text":"ينتفع بها من يخشى الله، ويُعرض عنها الأشقى"},{"id":"d","text":"تنفع الأشقى وحده"}]'::jsonb, 'c', 'قال الله: سَيَذَّكَّرُ مَن يَخْشَىٰ وَيَتَجَنَّبُهَا الْأَشْقَى، فمن يخشى الله ينتفع، والأشقى الكافر يُعرض. الخطأ الشائع تعميمُ الانتفاع على الجميع.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4165b188-1d66-5ce6-a644-622c00366f87', '49aa6fb2-24e2-55ac-8afe-0140c6edf297', 'تلميذٌ يُطيع رسولَ الله ﷺ ويعمل بما جاء به. كيف نصف عملَه في ضوء الدرس؟', '[{"id":"a","text":"عملٌ لا قيمة له"},{"id":"b","text":"مخالفةٌ لأمر الله"},{"id":"c","text":"لا علاقة له بطاعة الله"},{"id":"d","text":"طاعةٌ للرّسول ﷺ وهي من طاعة الله"}]'::jsonb, 'd', 'طاعةُ الرّسول ﷺ من طاعة الله، والسورة تأمر بالتذكير والعمل بما جاء به النبيّ ﷺ. الخطأ الشائع الفصلُ بين طاعة الرّسول ﷺ وطاعة الله.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fc8b169c-8499-5c6d-9dc7-ccf33b406932', '49aa6fb2-24e2-55ac-8afe-0140c6edf297', 'تلميذٌ يُقدّم اللعبَ ومتاعَ الدنيا دائمًا على صلاته وواجباته. أيُّ آيةٍ تُعاتبه؟', '[{"id":"a","text":"الَّذِي خَلَقَ فَسَوَّىٰ"},{"id":"b","text":"بَلْ تُؤْثِرُونَ الْحَيَوٰةَ الدُّنْيَا"},{"id":"c","text":"وَالَّذِي أَخْرَجَ الْمَرْعَىٰ"},{"id":"d","text":"سَنُقْرِئُكَ فَلَا تَنسَىٰ"}]'::jsonb, 'b', 'قال الله: بَلْ تُؤْثِرُونَ الْحَيَوٰةَ الدُّنْيَا وَالْآخِرَةُ خَيْرٌ وَأَبْقَىٰ، فهي تُعاتب من يُقدّم الدنيا على الآخرة. الخطأ الشائع اختيارُ آيةٍ في موضوعٍ آخر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6c98252b-1e98-53d9-ad64-542311752e0b', '49aa6fb2-24e2-55ac-8afe-0140c6edf297', 'ما العلاقة بين «قَدْ أَفْلَحَ مَن تَزَكَّىٰ» و«وَذَكَرَ اسْمَ رَبِّهِ فَصَلَّىٰ»؟', '[{"id":"a","text":"الفلاح يكون بتطهير النفس ثمّ ذكر الله وإقامة الصلاة"},{"id":"b","text":"لا علاقة بينهما"},{"id":"c","text":"كلاهما يصف الكافر"},{"id":"d","text":"الفلاح يكون بجمع المال فقط"}]'::jsonb, 'a', 'الآيتان متّصلتان: قَدْ أَفْلَحَ مَن تَزَكَّىٰ وَذَكَرَ اسْمَ رَبِّهِ فَصَلَّىٰ، فالفائز من طهّر نفسه ثمّ ذكر الله وأقام الصلاة. الخطأ الشائع فصلُ التزكية عن ذكر الله والصلاة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2ac4aad9-6e1e-53cc-8517-4d9b13b45b49', '49aa6fb2-24e2-55ac-8afe-0140c6edf297', 'قرأ تلميذٌ «صُحُفِ إِبْرَاهِيمَ وَمُوسَىٰ» وسأل: ماذا تُفيد هذه الآية؟', '[{"id":"a","text":"أنّ هذه المعاني جديدةٌ لم تُذكر من قبل"},{"id":"b","text":"أنّ إبراهيم وموسى لم يكن لهما كتاب"},{"id":"c","text":"أنّ معاني السورة حقائقُ ثابتةٌ وردت في كتب الأنبياء السابقين"},{"id":"d","text":"أنّ القرآن نسخةٌ من صحف إبراهيم"}]'::jsonb, 'c', 'إِنَّ هَٰذَا لَفِي الصُّحُفِ الْأُولَىٰ، صُحُفِ إِبْرَاهِيمَ وَمُوسَىٰ تدلّ على أنّ هذه الحقائق ثابتةٌ في كتب الأنبياء السابقين. الخطأ الشائع ظنُّ أنّ القرآن منقولٌ عنها، بل هو وحيٌ من الله يصدّق ما قبله.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

