INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('63936241-2163-58d2-af1e-c30451f4bda8', '8bd08008-83cc-5c57-a26e-7c648cee3459', 'سُمّيت السورة «الأعلى» لأنّها بدأت بأمر الله أن نُسبّح ...', '[{"id":"a","text":"اسمَ المخلوقات"},{"id":"b","text":"اسمَه الأعلى"},{"id":"c","text":"أسماءَ الجبال"},{"id":"d","text":"اسمَ الإنسان"}]'::jsonb, 'b', 'سُمّيت «الأعلى» لقول الله: سَبِّحِ اسْمَ رَبِّكَ الْأَعْلَىٰ، فأمرَنا أن نُسبّح اسمَه الأعلى.', 1)
