INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ca364eef-63e2-568a-b54f-4bc0a1a2d46e', '8bd08008-83cc-5c57-a26e-7c648cee3459', 'كم عددُ آيات سورة الأعلى، وأين نزلت؟', '[{"id":"a","text":"30 آية، نزلت في المدينة"},{"id":"b","text":"8 آيات، نزلت في مكّة"},{"id":"c","text":"26 آية، نزلت في المدينة"},{"id":"d","text":"19 آية، نزلت في مكّة"}]'::jsonb, 'd', 'سورة الأعلى عددُ آياتها 19 آية، وقد نزلت في مكّة فهي سورةٌ مكّيّة.', 2)
