INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b653fabc-7563-523f-bb09-03e338054a6e', '8bd08008-83cc-5c57-a26e-7c648cee3459', '«فَسَوَّىٰ» في قوله «الَّذِي خَلَقَ فَسَوَّىٰ» تعني أنّ الله ...', '[{"id":"a","text":"جعل المخلوقات متناسبةً كاملةً غيرَ متفاوتة"},{"id":"b","text":"تركها ناقصةً"},{"id":"c","text":"خلق شيئًا واحدًا"},{"id":"d","text":"لم يخلق شيئًا"}]'::jsonb, 'a', 'فَسَوَّىٰ أي جعل المخلوقات متناسبةَ الأجزاء كاملةً غيرَ متفاوتة، فكلُّ شيءٍ في أحسن صورة.', 3)
