INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8c6cfab4-7d9b-51a4-a747-67d0fb6e3528', '8bd08008-83cc-5c57-a26e-7c648cee3459', 'تلميذٌ يخشى الله فينتفع بالموعظة ويتذكّر. أيُّ آيةٍ تنطبق عليه؟', '[{"id":"a","text":"وَيَتَجَنَّبُهَا الْأَشْقَى"},{"id":"b","text":"بَلْ تُؤْثِرُونَ الْحَيَوٰةَ الدُّنْيَا"},{"id":"c","text":"سَيَذَّكَّرُ مَن يَخْشَىٰ"},{"id":"d","text":"الَّذِي يَصْلَى النَّارَ الْكُبْرَىٰ"}]'::jsonb, 'c', 'قال الله: سَيَذَّكَّرُ مَن يَخْشَىٰ، فمن يخشى الله ينتفع بالتذكير، بخلاف الأشقى الذي يتجنّب الموعظة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aa44df88-df97-5380-93f3-347d78078034', '8bd08008-83cc-5c57-a26e-7c648cee3459', 'ماذا وعدَ الله نبيَّه ﷺ بخصوص القرآن في هذه السورة؟', '[{"id":"a","text":"أنّه سينساه كلَّه"},{"id":"b","text":"أنّه سيُقرئه إيّاه فلا ينساه"},{"id":"c","text":"أنّه لن ينزل عليه قرآن"},{"id":"d","text":"أنّه سيقرأ كتبًا أخرى"}]'::jsonb, 'b', 'قال الله: سَنُقْرِئُكَ فَلَا تَنسَىٰ، أي سيُقرئ نبيَّه ﷺ القرآن ويحفظه له في صدره فلا ينساه، وهذا من عناية الله برسوله ﷺ.', 5)
