  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('046cad56-cca2-56c7-a6e7-97fd57e8693c', '8bd08008-83cc-5c57-a26e-7c648cee3459', 'تلميذٌ سأل: لماذا نعمل للآخرة ولا نُؤثر الدنيا عليها؟ ما الجواب من السورة؟', '[{"id":"a","text":"لأنّ الدنيا أبقى من الآخرة"},{"id":"b","text":"لأنّ الآخرة والدنيا سواء"},{"id":"c","text":"لأنّ الدنيا لا تنتهي"},{"id":"d","text":"لأنّ الآخرة خيرٌ وأبقى، تدوم ولا تنتهي"}]'::jsonb, 'd', 'قال الله: وَالْآخِرَةُ خَيْرٌ وَأَبْقَىٰ، فالآخرة خيرٌ وأنفعُ من الدنيا، وأبقى أي دائمةٌ لا تنتهي، فالعاقل يعمل لها. الخطأ الشائع تقديمُ الدنيا الفانية على الآخرة الباقية.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
