INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('74c4413b-3701-5fb4-9e4d-1287c843a442', '4d958f26-75ed-5bba-a133-1e999cbf8164', 'الصلاةُ في الإسلام هي ...', '[{"id":"a","text":"عادةٌ نفعلها إذا فرغنا"},{"id":"b","text":"ركنٌ من أركان الإسلام نؤدّيه 5 مرّاتٍ في اليوم"},{"id":"c","text":"صلاةٌ واحدةٌ في الأسبوع"},{"id":"d","text":"دعاءٌ نقوله عند النوم فقط"}]'::jsonb, 'b', 'الصلاةُ ركنٌ من أركان الإسلام، وهي عبادةٌ وشكرٌ لله وتطهيرٌ للنّفس، نؤدّيها خمسَ مرّاتٍ في اليوم والليلة في مواقيتها.', 1)
