INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f5014ab2-753e-5b60-8a58-c17c6ae12f24', '4d958f26-75ed-5bba-a133-1e999cbf8164', 'كم ركعةً في صلاة المغرب؟', '[{"id":"a","text":"ركعتان"},{"id":"b","text":"4 ركعات"},{"id":"c","text":"3 ركعات"},{"id":"d","text":"5 ركعات"}]'::jsonb, 'c', 'صلاةُ المغرب 3 ركعات، وهي الصلاةُ الوحيدةُ التي عددُ ركعاتها ثلاث.', 2)
