  ('59c3207b-2ae5-5778-a588-d0cbf7164a34', '5bb0c600-4e73-5535-a858-a6bc449be0c2', 'ذكرُ «سبحان ربّي الأعلى» نقوله في ...', '[{"id":"a","text":"السجود"},{"id":"b","text":"قراءة الفاتحة"},{"id":"c","text":"الرفع من الركوع"},{"id":"d","text":"السلام"}]'::jsonb, 'a', 'نقول «سبحان ربّي الأعلى» في السجود 3 مرّات، وفي الركوع نقول «سبحان الله العظيم».', 6)
