INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('25198565-449c-5b45-acb1-b96f6326d0ef', '84010f3c-0fbe-5ad1-be00-d25121d1f103', 'أرادَ تلميذٌ أن يبدأ صلاته. ما أوّلُ ما يفعله بعد أن يقف مستقبلًا القبلة؟', '[{"id":"a","text":"يركع مباشرة"},{"id":"b","text":"يسجد مباشرة"},{"id":"c","text":"يقرأ التشهّد"},{"id":"d","text":"يُكبّر تكبيرة الإحرام ويرفع يدَيه"}]'::jsonb, 'd', 'ندخل الصلاة بتكبيرة الإحرام («الله أكبر») مع رفع اليدين، ثمّ نقرأ الفاتحة. فأوّلُ ما يفعله هو التكبير. الخطأ الشائع البدءُ بالركوع قبل التكبير والقراءة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd49c259-f9f7-5e18-a77c-c68d84903744', '84010f3c-0fbe-5ad1-be00-d25121d1f103', 'تلميذٌ ركعَ فقال: «سبحان ربّي الأعلى». ما الخطأ؟', '[{"id":"a","text":"ذكرُ الركوع هو «سبحان الله العظيم» لا «سبحان ربّي الأعلى»"},{"id":"b","text":"لا خطأ، الذكران سواء"},{"id":"c","text":"كان عليه أن يسكت في الركوع"},{"id":"d","text":"كان عليه أن يقرأ الفاتحة في الركوع"}]'::jsonb, 'a', 'ذكرُ الركوع هو «سبحان الله العظيم»، و«سبحان ربّي الأعلى» للسجود. الخطأ الشائع الخلطُ بين ذكرَي الركوع والسجود.', 2)
ON CONFLICT (id) DO UPDATE SET
