  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fbffbaa4-17e7-5114-8b06-288197974b86', '84010f3c-0fbe-5ad1-be00-d25121d1f103', 'صلّى تلميذٌ الصبح فأتمَّ الركعتين دون أن يقنت في الركعة الثانية. أين كان موضعُ القنوت الذي تركه؟', '[{"id":"a","text":"بعد السلام"},{"id":"b","text":"في السجود الأوّل"},{"id":"c","text":"في الركعة الثانية قبل الركوع"},{"id":"d","text":"في تكبيرة الإحرام"}]'::jsonb, 'c', 'دعاءُ القنوت في صلاة الصبح موضعُه الركعة الثانية قبل الركوع. الخطأ الشائع ظنُّ أنّه يكون بعد السلام.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd3a8305-a7c0-5bad-a5ca-634117a60dc9', '84010f3c-0fbe-5ad1-be00-d25121d1f103', 'تلميذٌ يريد أن يُصلّيَ صلاةً عددُ ركعاتها 3. أيُّ صلاةٍ هي؟', '[{"id":"a","text":"الصبح"},{"id":"b","text":"المغرب"},{"id":"c","text":"العصر"},{"id":"d","text":"العشاء"}]'::jsonb, 'b', 'صلاةُ المغرب وحدها 3 ركعات، أمّا الصبحُ فركعتان، والعصرُ والعشاءُ فأربعٌ. الخطأ الشائع خلطُ المغرب بالعشاء.', 4)
