  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('68f745d2-7e9d-5632-a367-3e43871fc5df', '84010f3c-0fbe-5ad1-be00-d25121d1f103', 'تلميذٌ يحفظ أوّل التشهّد. أيُّ هذه هو بدايتُه الصحيحة؟', '[{"id":"a","text":"بسم الله الرحمن الرحيم"},{"id":"b","text":"الحمد لله ربّ العالمين"},{"id":"c","text":"سبحان ربّي الأعلى"},{"id":"d","text":"التحيّاتُ لله، الزّاكياتُ لله"}]'::jsonb, 'd', 'يبدأ التشهّدُ بقولنا: «التحيّاتُ لله، الزّاكياتُ لله، الطّيّباتُ الصلواتُ لله...». الخطأ الشائع الخلطُ بين التشهّد وفاتحة القراءة.', 5)
ON CONFLICT (id) DO UPDATE SET
