  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0daab65f-b99f-54a5-bdfd-849b976a2e4e', '84010f3c-0fbe-5ad1-be00-d25121d1f103', 'تلميذٌ أراد أن يُنهيَ صلاته بالتسليم بالطريقة الصحيحة. كيف يفعل؟', '[{"id":"a","text":"يقول «السلام عليكم» ملتفتًا يمينًا ثمّ يسارًا"},{"id":"b","text":"يقوم بسرعةٍ دون سلام"},{"id":"c","text":"يلتفت إلى الخلف ويصمت"},{"id":"d","text":"يُكبّر تكبيرة الإحرام من جديد"}]'::jsonb, 'a', 'نُنهي الصلاة بالتسليم: نقول «السلام عليكم» ونلتفت بالوجه يمينًا، ثمّ نُعيدها ونلتفت يسارًا في الجماعة. الخطأ الشائع تركُ السلام أو القيامُ قبله.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

