INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8ae7b2d1-79ff-5272-a8f1-70d593ed29e3', 'ce16b9c2-c47a-5aa0-8014-ec783f414cfa', 'نُصلّي كلَّ صلاةٍ في ...', '[{"id":"a","text":"وقتها الذي حدّده الله"},{"id":"b","text":"أيّ وقتٍ نشاء"},{"id":"c","text":"وقتِ النوم فقط"},{"id":"d","text":"مرّةً في الأسبوع"}]'::jsonb, 'a', 'لكلِّ صلاةٍ وقتٌ حدّده الله، فنؤدّي كلَّ صلاةٍ في وقتها المحدّد أثناء الليل والنهار.', 1)
