INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c7fc93ab-8ea4-5efe-bd49-d83d5d86a5fa', 'ce16b9c2-c47a-5aa0-8014-ec783f414cfa', 'ما الترتيبُ الصحيحُ بعد قراءة الفاتحة في الركعة؟', '[{"id":"a","text":"السلام ثمّ الركوع"},{"id":"b","text":"الركوع ثمّ الرفع منه ثمّ السجود"},{"id":"c","text":"السجود ثمّ الفاتحة من جديد"},{"id":"d","text":"التشهّد ثمّ تكبيرة الإحرام"}]'::jsonb, 'b', 'بعد الفاتحة نركع، ثمّ نرفع من الركوع، ثمّ نسجد السجود الأوّل. هذا ترتيبُ مكوّنات الركعة.', 2)
