INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6ed3bb3c-a2c3-5694-8437-53aed00363bd', 'ce16b9c2-c47a-5aa0-8014-ec783f414cfa', 'صلاتان عددُ ركعات كلٍّ منهما 4 وتُقرآن سرًّا تمامًا، هما ...', '[{"id":"a","text":"الصبح والمغرب"},{"id":"b","text":"المغرب والعشاء"},{"id":"c","text":"الظهر والعصر"},{"id":"d","text":"الصبح والعشاء"}]'::jsonb, 'c', 'الظهرُ والعصرُ كلتاهما 4 ركعات وتُقرآن سرًّا. الخطأ الشائع إدخالُ العشاء معهما، مع أنّ العشاء يُجهر في ركعتيها الأوليين.', 3)
