INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f186bf4f-bb0d-509c-ac21-72ed6d644262', 'ce16b9c2-c47a-5aa0-8014-ec783f414cfa', 'عند الانتقال من ركنٍ إلى ركنٍ (كالرفع من السجود الأوّل) نقول ...', '[{"id":"a","text":"سبحان الله العظيم"},{"id":"b","text":"سمع الله لمن حمده"},{"id":"c","text":"بسم الله الرحمن الرحيم"},{"id":"d","text":"الله أكبر"}]'::jsonb, 'd', 'عند الانتقال بين الأركان، كالرفع من السجود الأوّل والانتقال إلى الثاني، نقول: «الله أكبر».', 4)
