INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ab8ac82-e7e2-5e2b-ab47-ff3ec2c17e49', 'ce16b9c2-c47a-5aa0-8014-ec783f414cfa', 'في التشهّد نقول: «السلام عليك أيّها النبيُّ ورحمةُ الله ...»', '[{"id":"a","text":"وحدها"},{"id":"b","text":"ونومُه"},{"id":"c","text":"وبركاتُه"},{"id":"d","text":"وطعامُه"}]'::jsonb, 'c', 'في التشهّد نقول: «السلام عليك أيّها النبيُّ ورحمةُ الله وبركاتُه». الخطأ الشائع نقصُ كلمةٍ من هذا اللفظ.', 5)
