INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dae537d2-098c-5f33-bba2-8be1c1d89e11', 'ce16b9c2-c47a-5aa0-8014-ec783f414cfa', 'تلميذٌ صلّى الصبح ركعتين، وجهرَ بالقراءة، وقنتَ في الركعة الثانية قبل الركوع. ماذا نقول عنه؟', '[{"id":"a","text":"زادَ ركعةً غير مشروعة"},{"id":"b","text":"أدّى صلاة الصبح أداءً صحيحًا"},{"id":"c","text":"نسي تكبيرة الإحرام"},{"id":"d","text":"وضعَ القنوت بعد السلام"}]'::jsonb, 'b', 'صلاةُ الصبح ركعتان جهريّتان، ودعاءُ القنوت فيها يكون في الركعة الثانية قبل الركوع، فقد أدّاها أداءً صحيحًا.', 6)
