INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0037bd90-d20d-5680-96b0-e850d3254b78', '5ee27a21-8e30-51c8-ad24-2781f0a47f57', 'بماذا تبدأ سورة الطارق؟', '[{"id":"a","text":"قُلْ هُوَ اللَّهُ أَحَدٌ"},{"id":"b","text":"وَالشَّمْسِ وَضُحَاهَا"},{"id":"c","text":"وَالسَّمَاءِ وَالطَّارِقِ"},{"id":"d","text":"الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ"}]'::jsonb, 'c', 'تبدأ سورة الطارق بقول الله: وَالسَّمَاءِ وَالطَّارِقِ، فأقسم الله بالسماء وبالطارق وهو النّجم الذي يطلع ليلًا.', 1)
