INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bcde8f8c-8091-55a5-a599-1145958157ce', '5ee27a21-8e30-51c8-ad24-2781f0a47f57', 'ما هو «الطارق» الذي أقسم الله به؟', '[{"id":"a","text":"النّجمُ الثّاقبُ الذي يطلع ليلًا"},{"id":"b","text":"المطرُ النازلُ من السحاب"},{"id":"c","text":"الرّيحُ الشديدة"},{"id":"d","text":"الجبلُ العالي"}]'::jsonb, 'a', 'قال الله: النَّجْمُ الثَّاقِبُ. فالطارق هو النّجم الثّاقب الذي يطلع ليلًا ويثقب بضوئه ظلمة الليل.', 2)
