INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c8c73706-1f54-5e52-89c2-43d84559ecfd', '5ee27a21-8e30-51c8-ad24-2781f0a47f57', 'سورة الطارق نزلت في مكّة، فهي سورةٌ ...', '[{"id":"a","text":"مدنيّة"},{"id":"b","text":"من التوراة"},{"id":"c","text":"ليست من القرآن"},{"id":"d","text":"مكّيّة"}]'::jsonb, 'd', 'سورة الطارق سورةٌ مكّيّة، أي نزلت على النبيّ ﷺ في مكّة المكرّمة، وعدد آياتها 17 آية.', 3)
