INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2652b7e9-c4a1-5798-a6ad-e7eb41982371', '5ee27a21-8e30-51c8-ad24-2781f0a47f57', 'قال الله: إِن كُلُّ نَفْسٍ لَّمَّا عَلَيْهَا حَافِظٌ. ما معنى ذلك؟', '[{"id":"a","text":"بعضُ النّفوس لا حسابَ عليها"},{"id":"b","text":"ما من نفسٍ إلّا عليها حافظٌ يحفظ عملها"},{"id":"c","text":"النّفوسُ تحفظ نفسَها بنفسها"},{"id":"d","text":"الحافظُ هو المالُ والولد"}]'::jsonb, 'b', 'معنى الآية أنّه ما من نفسٍ إلّا عليها حافظٌ، وهو مَلَكٌ يحفظ أعمالها ويُحصيها، فعلينا أن نُراقب الله في أعمالنا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cdc6d419-0b3c-5d5f-9233-0ba02fcd32c8', '5ee27a21-8e30-51c8-ad24-2781f0a47f57', 'قال الله: مَّن يُطِعِ الرَّسُولَ فَقَدْ أَطَاعَ ... (النساء: 80). أكمل الآية.', '[{"id":"a","text":"اللَّهَ"},{"id":"b","text":"النَّاسَ"},{"id":"c","text":"الْمُلُوكَ"},{"id":"d","text":"الْآبَاءَ"}]'::jsonb, 'a', 'قال الله: مَّن يُطِعِ الرَّسُولَ فَقَدْ أَطَاعَ اللَّهَ. فطاعةُ الرّسول ﷺ من طاعةِ الله، لأنّه يُبلّغنا أمرَ الله.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

