INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9418fa55-db28-5ded-a560-90d0adad78b3', 'ffc36909-91db-5957-959d-2c8b44e6e3bb', 'أكمل أوّل آية من سورة الطارق: وَالسَّمَاءِ ...', '[{"id":"a","text":"وَالطَّارِقِ"},{"id":"b","text":"وَالْقَمَرِ"},{"id":"c","text":"وَالضُّحَىٰ"},{"id":"d","text":"وَالنَّهَارِ"}]'::jsonb, 'a', 'أوّل آية في سورة الطارق هي: وَالسَّمَاءِ وَالطَّارِقِ، فأقسم الله بالسماء وبالطارق وهو النّجم الذي يطلع ليلًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8d70e9bb-cc5a-53ff-ad10-e2c597512d15', 'ffc36909-91db-5957-959d-2c8b44e6e3bb', 'كم عدد آيات سورة الطارق؟', '[{"id":"a","text":"5 آيات"},{"id":"b","text":"30 آية"},{"id":"c","text":"17 آية"},{"id":"d","text":"آية واحدة"}]'::jsonb, 'c', 'سورة الطارق عدد آياتها 17 آية، وهي سورة مكّيّة من القرآن الكريم.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
