  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cea29354-98fb-5ac7-b30a-808c3060ce51', 'ffc36909-91db-5957-959d-2c8b44e6e3bb', 'أين نزلت سورة الطارق؟', '[{"id":"a","text":"في المدينة"},{"id":"b","text":"في مكّة"},{"id":"c","text":"في الشام"},{"id":"d","text":"في مصر"}]'::jsonb, 'b', 'سورة الطارق سورةٌ مكّيّة، أي نزلت على النبيّ محمّد ﷺ في مكّة المكرّمة.', 3)
ON CONFLICT (id) DO UPDATE SET
