INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('448dbb1b-2ffb-532c-8ab2-fa452d584f7e', 'ffc36909-91db-5957-959d-2c8b44e6e3bb', 'قال الله: وَمَا أَدْرَىٰكَ مَا الطَّارِقُ، ثمّ أجاب: النَّجْمُ ...', '[{"id":"a","text":"الْبَعِيدُ"},{"id":"b","text":"الصَّغِيرُ"},{"id":"c","text":"السَّاقِطُ"},{"id":"d","text":"الثَّاقِبُ"}]'::jsonb, 'd', 'قال الله: النَّجْمُ الثَّاقِبُ، أي النّجم الذي يثقب بضوئه ظلمة الليل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
