  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4005416e-eec0-5e38-889f-4990e1bb2680', 'ffc36909-91db-5957-959d-2c8b44e6e3bb', 'من خلق الإنسان من ماءٍ دافقٍ، فهو قادرٌ على ...', '[{"id":"a","text":"بعثه وإحيائه بعد موته"},{"id":"b","text":"أن يتركه بلا حساب"},{"id":"c","text":"أن ينساه"},{"id":"d","text":"أن يُعطيه مالًا فقط"}]'::jsonb, 'a', 'قال الله: إِنَّهُ عَلَىٰ رَجْعِهِ لَقَادِرٌ. فالذي خلق الإنسان أوّل مرّةٍ قادرٌ على بعثه وإحيائه بعد موته.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a1faf634-2e13-54c5-983a-30f12009d6b8', 'ffc36909-91db-5957-959d-2c8b44e6e3bb', 'قال الله في سورة النساء: مَّن يُطِعِ الرَّسُولَ فَقَدْ أَطَاعَ اللَّهَ. فطاعةُ الرّسول ﷺ هي ...', '[{"id":"a","text":"أمرٌ لا فائدةَ فيه"},{"id":"b","text":"مخالفةٌ لأمر الله"},{"id":"c","text":"من طاعةِ الله"},{"id":"d","text":"خاصّةٌ بالكبار فقط"}]'::jsonb, 'c', 'قال الله: مَّن يُطِعِ الرَّسُولَ فَقَدْ أَطَاعَ اللَّهَ. فطاعةُ الرّسول ﷺ من طاعةِ الله، لأنّه يُبلّغنا أمرَ الله ونهيَه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9b23b254-c7e4-5bc1-9af8-ee64658d80fb', 'a2f2a53d-33b9-53be-8c45-3bf00eec40e5', 'education-islamique-4eme', '⚔️ زعيم الفصل ⭐⭐⭐: حارسُ سورة الطارق', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
