INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5fa3dd7f-684f-5753-95c3-5e3d9c06b1f7', '9b23b254-c7e4-5bc1-9af8-ee64658d80fb', 'قال الله: إِن كُلُّ نَفْسٍ لَّمَّا عَلَيْهَا حَافِظٌ. ما المقصود بـ«حافظ» هنا؟', '[{"id":"a","text":"الطبيبُ الذي يحفظ الصحّة"},{"id":"b","text":"مَلَكٌ يحفظ أعمالَ النّفس ويُحصيها"},{"id":"c","text":"الوالدُ الذي يحفظ ابنَه"},{"id":"d","text":"المالُ الذي يحفظه صاحبُه"}]'::jsonb, 'b', '«حافظ» هنا مَلَكٌ يحفظ أعمال النّفس ويُحصيها، فما من نفسٍ إلّا عليها حافظ. الخطأ الشائع ظنّ أنّ الحافظ هو المال أو الطبيب.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('44668314-37e2-535d-8481-3f1fe8feeb8d', '9b23b254-c7e4-5bc1-9af8-ee64658d80fb', 'قال الله: خُلِقَ مِن مَّاءٍ دَافِقٍ. ما معنى «دافق»؟', '[{"id":"a","text":"ماءٌ بارد"},{"id":"b","text":"ماءٌ كثير"},{"id":"c","text":"ماءٌ عَذب"},{"id":"d","text":"ماءٌ مصبوبٌ يندفع بسرعة"}]'::jsonb, 'd', '«دافق» معناها ماءٌ مصبوبٌ يندفع بسرعة، خُلِق منه الإنسان. الخطأ الشائع ربطُ الكلمة ببرودة الماء أو كثرته، والصواب أنّها تصف اندفاعه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ea60db02-49f8-523f-aaad-22fd2fe41ffe', '9b23b254-c7e4-5bc1-9af8-ee64658d80fb', 'قال الله: يَخْرُجُ مِن بَيْنِ الصُّلْبِ وَالتَّرَائِبِ. ما المقصود بـ«الصُّلب»؟', '[{"id":"a","text":"البطن"},{"id":"b","text":"الرّأس"},{"id":"c","text":"الظّهر"},{"id":"d","text":"اليد"}]'::jsonb, 'c', '«الصُّلب» هو الظّهر، و«الترائب» ضلوع الصّدر. الخطأ الشائع الخلط بين الصُّلب والبطن، والصواب أنّه الظّهر.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7990bec3-4cc1-59e2-87da-36da1298e97e', '9b23b254-c7e4-5bc1-9af8-ee64658d80fb', 'قال الله: يَوْمَ تُبْلَى السَّرَائِرُ. ما معنى «تُبلى السّرائر»؟', '[{"id":"a","text":"تُكشف خفايا القلوب وتظهر"},{"id":"b","text":"تُغلق الأبواب"},{"id":"c","text":"تنزل الأمطار"},{"id":"d","text":"تُبنى البيوت"}]'::jsonb, 'a', '«تُبلى السّرائر» معناها تُكشف مكنوناتُ القلوب وخفاياها يوم القيامة فتظهر. الخطأ الشائع ظنّ أنّها تتعلّق بالمطر أو البناء.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e44d6126-79c4-5ea2-b130-67b6829770c2', '9b23b254-c7e4-5bc1-9af8-ee64658d80fb', 'قال الله عن القرآن: إِنَّهُ لَقَوْلٌ فَصْلٌ وَمَا هُوَ بِالْهَزْلِ. ما معنى «بالهزل»؟', '[{"id":"a","text":"بالصِّدق"},{"id":"b","text":"بالعدل"},{"id":"c","text":"بالحقّ"},{"id":"d","text":"باللّعب"}]'::jsonb, 'd', '«بالهزل» معناها باللّعب؛ فالقرآن قولٌ فصلٌ جادّ يفصل بين الحقّ والباطل، وليس لعبًا. الخطأ الشائع ظنّ أنّ «الهزل» بمعنى الصِّدق، والصواب أنّه ضدّ الجِدّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6def8b18-7dae-5ca2-aa8e-b306690b9ff1', '9b23b254-c7e4-5bc1-9af8-ee64658d80fb', 'قال الله: وَمَن تَوَلَّىٰ فَمَا أَرْسَلْنَاكَ عَلَيْهِمْ حَفِيظًا (النساء: 80). فمَن أعرض عن طاعة الرّسول ﷺ ...', '[{"id":"a","text":"لا يضرّ أحدًا أبدًا"},{"id":"b","text":"لن يضرَّ إلّا نفسَه"},{"id":"c","text":"يُكافَأ على إعراضه"},{"id":"d","text":"يصير حافظًا للنّاس"}]'::jsonb, 'b', 'معنى الآية أنّ مَن تولّى وأعرض عن طاعة الرّسول ﷺ فلن يضرَّ إلّا نفسَه، والنّبيّ ﷺ ليس حفيظًا مُحاسِبًا عليهم. الخطأ الشائع ظنّ أنّ الإعراض لا أثرَ له على صاحبه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

