INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7ded0d9d-693a-59ce-9c36-19f345e7c0a9', 'f88ab07c-b952-5b7f-b885-55938156416b', 'سورة الطارق سورةٌ ...', '[{"id":"a","text":"مدنيّةٌ طويلة"},{"id":"b","text":"مكّيّةٌ عددُ آياتها 17"},{"id":"c","text":"ليست من القرآن"},{"id":"d","text":"من كتب القصص"}]'::jsonb, 'b', 'سورة الطارق سورةٌ مكّيّة من القرآن الكريم، عددُ آياتها 17 آية، سُمّيت «الطارق» لأنّ الله أقسم فيها بالنّجم الذي يطلع ليلًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
