  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b4d3cdb5-a57c-518f-833c-c777de6e26f9', 'f88ab07c-b952-5b7f-b885-55938156416b', 'أكمل قول الله: وَمَا أَدْرَىٰكَ مَا الطَّارِقُ، النَّجْمُ ...', '[{"id":"a","text":"الْبَعِيدُ"},{"id":"b","text":"السَّاقِطُ"},{"id":"c","text":"الصَّغِيرُ"},{"id":"d","text":"الثَّاقِبُ"}]'::jsonb, 'd', 'قال الله: النَّجْمُ الثَّاقِبُ، أي النّجم الذي يثقب بضوئه ظلمةَ الليل. فالطارق هو هذا النّجم الذي يطلع ليلًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
