  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f1e6fbd-d227-5d58-85e0-e7d508f97167', 'f88ab07c-b952-5b7f-b885-55938156416b', 'معنى «النَّجْمُ الثَّاقِبُ» أنّه النّجم الذي ...', '[{"id":"a","text":"يثقب بضوئه ظلمةَ الليل"},{"id":"b","text":"يطلع في النّهار فقط"},{"id":"c","text":"لا يُرى أبدًا"},{"id":"d","text":"يسقط على الأرض"}]'::jsonb, 'a', 'الثّاقب معناه الذي يثقب بضوئه ظلمةَ الليل، أي يخترق الظلام بنوره. وهو وصفٌ للطارق الذي أقسم الله به.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
