  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8c40a620-fba4-5a3f-987f-49e86277f3c0', 'f88ab07c-b952-5b7f-b885-55938156416b', 'قال الله: إِنَّهُ عَلَىٰ رَجْعِهِ لَقَادِرٌ. ما معنى «رجعه»؟', '[{"id":"a","text":"إنزال المطر"},{"id":"b","text":"ذهابه إلى السّفر"},{"id":"c","text":"إرجاعه حيًّا بعد موته"},{"id":"d","text":"رجوعه إلى بيته"}]'::jsonb, 'c', '«رجعه» معناها إرجاعه حيًّا بعد موته، فالذي خلق الإنسانَ أوّلَ مرّةٍ قادرٌ على بعثه يومَ القيامة. الخطأ الشائع فهم «الرجع» على أنّه رجوعٌ من سفر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0bee224f-4f82-5cc9-8553-cb13782db396', 'f88ab07c-b952-5b7f-b885-55938156416b', 'قال الله: يَوْمَ تُبْلَى السَّرَائِرُ. متى تُكشف خفايا القلوب؟', '[{"id":"a","text":"كلّ ليلة"},{"id":"b","text":"في النّوم"},{"id":"c","text":"عند المطر"},{"id":"d","text":"يومَ القيامة"}]'::jsonb, 'd', '«يومَ تُبلى السّرائر» أي يومَ القيامة تُكشف مكنوناتُ القلوب وخفاياها فتظهر، فلا يبقى للإنسان قوّةٌ ولا ناصرٌ إلّا عملُه الصالح.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ef5df3d8-8cc7-5fb2-b170-1426a6531b0b', 'f88ab07c-b952-5b7f-b885-55938156416b', 'وصف الله القرآن بأنّه «قَوْلٌ فَصْلٌ»، ومعنى ذلك أنّه ...', '[{"id":"a","text":"قولٌ يفصل بين الحقّ والباطل وليس لعبًا"},{"id":"b","text":"قولٌ فيه لعبٌ ومزاح"},{"id":"c","text":"كلامٌ من تأليف النّاس"},{"id":"d","text":"قصّةٌ من قصص القدماء"}]'::jsonb, 'a', '«قولٌ فصلٌ» أي قولٌ جادٌّ يفصل بين الحقّ والباطل، «وما هو بالهزل» أي ليس لعبًا، بل هو كلامُ الله. الخطأ الشائع ظنّ أنّ القرآن فيه هزلٌ ولعب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9e21aaca-6e52-5e08-aaaf-91ac9fe5277e', 'a2f2a53d-33b9-53be-8c45-3bf00eec40e5', 'education-islamique-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: بطلُ سورة الطارق', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e86f2e96-c263-52da-8805-32220bbcab42', '9e21aaca-6e52-5e08-aaaf-91ac9fe5277e', 'رتّب آيات أوّل سورة الطارق: (1) النَّجْمُ الثَّاقِبُ (2) وَالسَّمَاءِ وَالطَّارِقِ (3) وَمَا أَدْرَىٰكَ مَا الطَّارِقُ. ما الترتيب الصحيح من أوّلها؟', '[{"id":"a","text":"1 ثمّ 2 ثمّ 3"},{"id":"b","text":"3 ثمّ 2 ثمّ 1"},{"id":"c","text":"2 ثمّ 3 ثمّ 1"},{"id":"d","text":"2 ثمّ 1 ثمّ 3"}]'::jsonb, 'c', 'تبدأ السورة بـ«وَالسَّمَاءِ وَالطَّارِقِ» (2) ثمّ «وَمَا أَدْرَىٰكَ مَا الطَّارِقُ» (3) ثمّ «النَّجْمُ الثَّاقِبُ» (1). الخطأ الشائع تقديم جواب السؤال على السؤال نفسه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('063c4149-59cb-50d9-94fb-7b30034c8de3', '9e21aaca-6e52-5e08-aaaf-91ac9fe5277e', 'قال تلميذٌ: «قول الله إِن كُلُّ نَفْسٍ لَّمَّا عَلَيْهَا حَافِظٌ يعني أنّ بعض النّاس لا حسابَ عليهم». هل قوله صحيح؟', '[{"id":"a","text":"لا، بل ما من نفسٍ إلّا عليها حافظٌ يحفظ عملها"},{"id":"b","text":"نعم، الأغنياء لا حسابَ عليهم"},{"id":"c","text":"نعم، الصِّغار لا حسابَ عليهم"},{"id":"d","text":"نعم، بعض النّاس بلا حافظ"}]'::jsonb, 'a', 'معنى الآية أنّه ما من نفسٍ إلّا عليها حافظٌ، وهو مَلَكٌ يحفظ أعمالها ويُحصيها على كلّ إنسان. الخطأ الشائع ظنّ أنّ بعض النّاس بلا حسابٍ ولا حافظ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8c7e4a93-3b05-5371-937d-b19f3dec7eee', '9e21aaca-6e52-5e08-aaaf-91ac9fe5277e', 'قال الله: فَلْيَنظُرِ الْإِنسَٰنُ مِمَّ خُلِقَ، خُلِقَ مِن مَّاءٍ دَافِقٍ. ما الحكمة من تذكير الإنسان بأصل خلقه؟', '[{"id":"a","text":"ليجمع المال"},{"id":"b","text":"ليفتخر على النّاس بقوّته"},{"id":"c","text":"ليتعلّم السِّباحة"},{"id":"d","text":"ليعلم أنّ الذي خلقه من ماءٍ ضعيفٍ قادرٌ على بعثه"}]'::jsonb, 'd', 'ذكّر الله الإنسانَ بأنّه خُلِق من ماءٍ دافقٍ ضعيفٍ ليتواضع ويعلم أنّ الذي خلقه أوّلَ مرّةٍ قادرٌ على بعثه ومحاسبته. الخطأ الشائع فهم الآية على أنّها دعوةٌ للفخر بالقوّة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ee86615e-7046-51b0-b1c5-cd8367bb5c13', '9e21aaca-6e52-5e08-aaaf-91ac9fe5277e', 'قال الله: فَمَا لَهُ مِن قُوَّةٍ وَلَا نَاصِرٍ. تلميذٌ ظنّ أنّ ماله وأصحابه ينفعونه يومَ القيامة. ما الصواب على ضوء الآية؟', '[{"id":"a","text":"ينفعه ماله يومئذٍ"},{"id":"b","text":"لا قوّةَ له يومئذٍ ولا ناصرَ إلّا عملُه الصالح"},{"id":"c","text":"ينصره أصحابه يومئذٍ"},{"id":"d","text":"ينفعه جاهُه يومئذٍ"}]'::jsonb, 'b', 'يومَ تُبلى السّرائر لا قوّةَ للإنسان ولا ناصرَ يدفع عنه إلّا عملُه الصالح ورحمةُ الله. الخطأ الشائع الاعتماد على المال والأصحاب يومَ القيامة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('48babcca-6a6a-5d35-ac58-3174fb61ff5b', '9e21aaca-6e52-5e08-aaaf-91ac9fe5277e', 'قال الله عن القرآن: إِنَّهُ لَقَوْلٌ فَصْلٌ وَمَا هُوَ بِالْهَزْلِ. أيُّ موقفٍ يوافق هذه الآية؟', '[{"id":"a","text":"نقرأ القرآن للتّسلية واللّعب"},{"id":"b","text":"نظنّ القرآن قصصًا من تأليف النّاس"},{"id":"c","text":"نُعظّم القرآن ونعمل به لأنّه قولٌ فصلٌ جادّ"},{"id":"d","text":"نقرؤه مرّةً ثمّ نتركه"}]'::jsonb, 'c', 'القرآن قولٌ فصلٌ يفصل بين الحقّ والباطل وليس بالهزل، فحقُّه أن نُعظّمه ونتدبّره ونعمل به. الخطأ الشائع التّعامل مع القرآن على أنّه لعبٌ أو كلامُ بشر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3821f82b-f168-5552-b782-832d8aabb761', '9e21aaca-6e52-5e08-aaaf-91ac9fe5277e', 'قال الله: مَّن يُطِعِ الرَّسُولَ فَقَدْ أَطَاعَ اللَّهَ (النساء: 80). تلميذٌ سمع أمرًا للنّبيّ ﷺ فقال: «هذا أمرُ النّبيّ ﷺ لا أمرُ الله فلا يلزمني». ما الصواب؟', '[{"id":"a","text":"طاعةُ الرّسول ﷺ من طاعةِ الله، فمن أطاعه فقد أطاع الله"},{"id":"b","text":"أوامرُ النّبيّ ﷺ لا تلزمنا"},{"id":"c","text":"نُطيع النّبيّ ﷺ في بعض الأمور فقط"},{"id":"d","text":"طاعةُ النّبيّ ﷺ مخالفةٌ لأمر الله"}]'::jsonb, 'a', 'قال الله: مَّن يُطِعِ الرَّسُولَ فَقَدْ أَطَاعَ اللَّهَ، فطاعةُ الرّسول ﷺ من طاعةِ الله لأنّه يُبلّغنا أمرَه؛ ومن فوائدها محبّةُ الله ودخولُ الجنّة. الخطأ الشائع التّفريق بين طاعة الله وطاعة رسوله ﷺ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('da13c57b-08fa-58e6-9e7e-73cd126a6b44', 'a2f2a53d-33b9-53be-8c45-3bf00eec40e5', 'education-islamique-4eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة لسورة الطارق', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
