  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d9cb51ed-c578-5159-9b08-296f99a9ee42', 'da13c57b-08fa-58e6-9e7e-73cd126a6b44', 'سورة الطارق نزلت في مكّة، فهي سورةٌ ...', '[{"id":"a","text":"مكّيّة"},{"id":"b","text":"مدنيّة"},{"id":"c","text":"من القصص"},{"id":"d","text":"طويلة"}]'::jsonb, 'a', 'السورة التي نزلت في مكّة تُسمّى مكّيّة، وسورة الطارق نزلت في مكّة فهي مكّيّة، وعددُ آياتها 17 آية.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('30883bcb-c4a2-546a-81a9-85222ef7d60f', 'da13c57b-08fa-58e6-9e7e-73cd126a6b44', 'أكمل قول الله: وَالسَّمَاءِ ...', '[{"id":"a","text":"وَالْقَمَرِ"},{"id":"b","text":"وَالنَّهَارِ"},{"id":"c","text":"وَالضُّحَىٰ"},{"id":"d","text":"وَالطَّارِقِ"}]'::jsonb, 'd', 'أوّل آيةٍ في السورة هي: وَالسَّمَاءِ وَالطَّارِقِ، فأقسم الله بالسماء وبالطارق وهو النّجم الذي يطلع ليلًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('92e45d2a-0e79-56f9-ba1a-96cbf07dc16b', 'da13c57b-08fa-58e6-9e7e-73cd126a6b44', 'قال الله: يَخْرُجُ مِن بَيْنِ الصُّلْبِ وَالتَّرَائِبِ. ما المقصود بـ«الترائب»؟', '[{"id":"a","text":"الرّأس"},{"id":"b","text":"ضلوعُ الصّدر"},{"id":"c","text":"اليدان"},{"id":"d","text":"القدمان"}]'::jsonb, 'b', '«الترائب» هي ضلوعُ الصّدر، و«الصُّلب» هو الظّهر. الخطأ الشائع الخلط بين الترائب وأعضاءٍ أخرى، والصواب أنّها ضلوعُ الصّدر.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e76383bc-8266-5b79-8f96-360b7a7c4f41', 'da13c57b-08fa-58e6-9e7e-73cd126a6b44', 'قال الله في آخر السورة: فَمَهِّلِ الْكَافِرِينَ أَمْهِلْهُمْ رُوَيْدًا. ما معنى «رويدًا»؟', '[{"id":"a","text":"قليلًا"},{"id":"b","text":"كثيرًا"},{"id":"c","text":"أبدًا"},{"id":"d","text":"بسرعةٍ شديدة"}]'::jsonb, 'a', '«رويدًا» معناها قليلًا، فأمر الله نبيَّه ﷺ أن يُمهل الكافرين قليلًا، فإنّ الله يُبطل كيدَهم. الخطأ الشائع فهم «رويدًا» على أنّها مدّةٌ طويلة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47f0e0e9-7096-5183-8886-9cbc3ad1adb1', 'da13c57b-08fa-58e6-9e7e-73cd126a6b44', 'أقسم الله بـ«السَّمَاءِ ذَاتِ الرَّجْعِ»، والمقصود بها السماءُ ...', '[{"id":"a","text":"التي لا مطرَ فيها"},{"id":"b","text":"التي تسقط على الأرض"},{"id":"c","text":"صاحبةُ المطر الذي يرجع مرّةً بعد مرّة"},{"id":"d","text":"التي تنشقّ عن النّبات"}]'::jsonb, 'c', '«ذات الرّجع» أي السماءُ صاحبةُ المطر، لأنّ المطر يرجع وينزل مرّةً بعد مرّة. أمّا التي تنشقّ عن النّبات فهي «الأرضُ ذاتُ الصّدع». الخطأ الشائع الخلط بين وصف السماء ووصف الأرض.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f76d0a75-0d4d-55f0-87da-03293d88d68e', 'da13c57b-08fa-58e6-9e7e-73cd126a6b44', 'ما الرسالةُ التي نأخذها من سورة الطارق ونعمل بها في حياتنا؟', '[{"id":"a","text":"نجمع المال لأنّه ينفعنا يومَ القيامة"},{"id":"b","text":"نفتخر بقوّتنا على النّاس"},{"id":"c","text":"نُكذّب بالبعث كما فعل المتكبّرون"},{"id":"d","text":"نُراقب الله لأنّ علينا حافظًا، ونؤمن بالبعث، ونُطيع الرّسول ﷺ"}]'::jsonb, 'd', 'نعمل بالسورة: نُراقب الله لأنّ على كلّ نفسٍ حافظًا، ونؤمن بالبعث والحساب، ونُعظّم القرآن، ونُطيع الرّسول ﷺ فطاعتُه من طاعةِ الله. الخطأ الشائع الاعتماد على المال والقوّة وإنكار البعث.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a49ecccb-91a0-5ec9-b216-b2da35e5c6f4', '8cfa1210-dd8b-57cf-a33a-41b87730d3c5', 'education-islamique-4eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
