INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d9356a47-fa79-5ae3-bdeb-baea5f5e3f04', 'a49ecccb-91a0-5ec9-b216-b2da35e5c6f4', 'مَن هو الجار؟', '[{"id":"a","text":"المعلّمُ في المدرسة"},{"id":"b","text":"بائعُ السّوق البعيد"},{"id":"c","text":"مَن يسكن بجوارنا في البيت أو الحيّ"},{"id":"d","text":"صاحبُ المدينة الأخرى"}]'::jsonb, 'c', 'الجارُ هو مَن يسكن بجوارنا، في البيت المجاور أو في الحيّ، قريبًا كان أم بعيدًا، وله حقٌّ علينا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
