INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4f5418bf-9274-5b56-8b13-cc44ed84d05d', 'a49ecccb-91a0-5ec9-b216-b2da35e5c6f4', 'أمرَنا الله أن نتعاون على ...', '[{"id":"a","text":"الخيرِ وطاعةِ الله"},{"id":"b","text":"إيذاءِ الناس"},{"id":"c","text":"إزعاجِ الجيران"},{"id":"d","text":"ما يُغضب الله"}]'::jsonb, 'a', 'التعاونُ يكون على البِرّ والتقوى، أي على الخير وطاعة الله؛ ولا نتعاون أبدًا على الأذى أو ما يُغضب الله.', 2)
