INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2ea3b55-b47d-5539-aa94-82d80bcbcd79', 'a49ecccb-91a0-5ec9-b216-b2da35e5c6f4', 'أكمل قول الله: «وَتَعَاوَنُوا عَلَى الْبِرِّ وَ...».', '[{"id":"a","text":"الْمَالِ"},{"id":"b","text":"اللَّعِبِ"},{"id":"c","text":"الْعُدْوَانِ"},{"id":"d","text":"التَّقْوَىٰ"}]'::jsonb, 'd', 'قال الله: «وَتَعَاوَنُوا عَلَى الْبِرِّ وَالتَّقْوَىٰ»، أي تعاونوا على كلّ خيرٍ وعلى طاعة الله.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
