  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2e5b4325-4dde-581e-8c9a-99664e28af4f', 'a49ecccb-91a0-5ec9-b216-b2da35e5c6f4', 'بمَن كان جبريلُ عليه السلام يوصي النبيَّ ﷺ مرّةً بعد مرّة؟', '[{"id":"a","text":"بالبيع والشّراء"},{"id":"b","text":"بالجار"},{"id":"c","text":"باللّعب"},{"id":"d","text":"بالسّفر"}]'::jsonb, 'b', 'قال النبيّ ﷺ: «ما زال جبريل يوصيني بالجار حتّى ظننتُ أنّه سيورّثه»؛ فقد كرّر جبريلُ الوصيّةَ بالجار حتّى ظنّ النبيّ ﷺ أنّ له نصيبًا من الميراث.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e3de164d-06be-5e37-b5b6-a3150ac47c04', 'a49ecccb-91a0-5ec9-b216-b2da35e5c6f4', 'فرِح جارُك بنجاحه في الامتحان. ما الذي تفعله؟', '[{"id":"a","text":"أحسده ولا أُكلّمه"},{"id":"b","text":"أتجاهله تمامًا"},{"id":"c","text":"أفرح لفرحه وأُهنّئه"},{"id":"d","text":"أرفع صوتي لأُزعجه"}]'::jsonb, 'c', 'من حُسن الجوار أن نُشارك الجارَ أفراحَه، فنفرح لفرحه ونُهنّئه؛ فبذلك تقوى المحبّة بين الجيران.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

