INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9461470f-4450-5434-994b-4401e442b932', '24c6e478-8530-55bd-9951-63cc8e3faf75', 'الجارُ هو مَن يسكن ...', '[{"id":"a","text":"بجوارنا"},{"id":"b","text":"في بلدٍ بعيد"},{"id":"c","text":"في مدينةٍ أخرى"},{"id":"d","text":"في قارّةٍ أخرى"}]'::jsonb, 'a', 'الجارُ هو مَن يسكن بجوارنا، في البيت المجاور أو في الحيّ. الخطأ الشائع ظنُّ أنّ الجار هو البعيدُ في بلدٍ آخر.', 1)
