INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f8655e4b-f023-53b7-b79c-a732091f938d', '24c6e478-8530-55bd-9951-63cc8e3faf75', 'إذا مرِض جارُنا واحتاج مساعدة، فإنّنا ...', '[{"id":"a","text":"نتركه وحده"},{"id":"b","text":"نسخر منه"},{"id":"c","text":"نُسارع إلى عونه"},{"id":"d","text":"نُغلق الباب"}]'::jsonb, 'c', 'من حقّ الجار أن نُساعده عند الحاجة، فإذا مرِض أو احتاج شيئًا سارعنا إلى عونه بما نقدر عليه. الخطأ الشائع تركُ الجار وحده وقتَ حاجته.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('08bb97f1-a966-5428-89b0-8e68d9d3b7ef', '24c6e478-8530-55bd-9951-63cc8e3faf75', 'حين نلتقي جارَنا نُلقي عليه ...', '[{"id":"a","text":"الحجارة"},{"id":"b","text":"الكلامَ السّيّئ"},{"id":"c","text":"القُمامة"},{"id":"d","text":"السّلام"}]'::jsonb, 'd', 'من إكرام الجار أن نُلقي عليه السلام ونبتسم في وجهه، فالكلمةُ الطيّبة من حُسن الجوار. الخطأ الشائع مقابلةُ الجار بالكلام السّيّئ أو الأذى.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db45c4be-a078-5291-a351-4dc5f20f268b', '24c6e478-8530-55bd-9951-63cc8e3faf75', 'نتعاون مع جيراننا على ...', '[{"id":"a","text":"الإزعاج"},{"id":"b","text":"الخير"},{"id":"c","text":"الأذى"},{"id":"d","text":"الكسل"}]'::jsonb, 'b', 'أمرَنا الله أن نتعاون على البِرّ والتقوى، أي على الخير وطاعة الله، لا على الأذى. الخطأ الشائع ظنُّ أنّ التعاون يكون على أيّ شيءٍ ولو كان أذى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
