  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a0dc0e9f-74d0-51a6-a61c-f4712fa15842', '24c6e478-8530-55bd-9951-63cc8e3faf75', 'إذا فرِح جارُنا بمولودٍ جديد، فإنّنا ...', '[{"id":"a","text":"نُهنّئه ونفرح لفرحه"},{"id":"b","text":"نحزن ونغضب"},{"id":"c","text":"نتجاهله"},{"id":"d","text":"نُزعجه بالصّوت"}]'::jsonb, 'a', 'من حُسن الجوار أن نُشارك الجارَ أفراحَه، فنُهنّئه ونفرح لفرحه؛ فتقوى المحبّة بيننا. الخطأ الشائع الحسدُ أو تجاهلُ فرح الجار.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
