  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('30237999-87fd-5440-8f62-3af1c4c7c243', '24c6e478-8530-55bd-9951-63cc8e3faf75', 'من إيذاء الجار الذي ننهى عنه ...', '[{"id":"a","text":"مساعدتُه"},{"id":"b","text":"إلقاءُ السّلام عليه"},{"id":"c","text":"رمْيُ القُمامة أمام بابه"},{"id":"d","text":"زيارتُه عند المرض"}]'::jsonb, 'c', 'نكُفّ عن الجار كلَّ أذى، فلا نرمي القُمامة أمام بابه ولا نرفع الصوتَ المزعج؛ أمّا المساعدةُ والسلامُ والزيارةُ فهي من حُسن الجوار. الخطأ الشائع عدُّ إيذاء الجار أمرًا هيّنًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

