  ('4336768d-921c-5884-9687-3f605b2d0784', '8cfa1210-dd8b-57cf-a33a-41b87730d3c5', 'education-islamique-4eme', '⚔️ زعيم الفصل ⭐⭐⭐: بطلُ حُسنِ الجوار', 3, 120, 30, 'boss', 'admin', 2)
