INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('edc2c5b5-e4c4-5761-8848-9a62fc9662dc', '4336768d-921c-5884-9687-3f605b2d0784', 'قال الله: «وَتَعَاوَنُوا عَلَى الْبِرِّ وَالتَّقْوَىٰ». ما المقصود بالتعاون على «البِرّ»؟', '[{"id":"a","text":"التعاونُ على إيذاء الناس"},{"id":"b","text":"التعاونُ على كلّ عملٍ صالحٍ نافع"},{"id":"c","text":"التعاونُ على اللّعب فقط"},{"id":"d","text":"التعاونُ على ما يُغضب الله"}]'::jsonb, 'b', 'البِرّ هو كلُّ عملٍ صالحٍ نافع، فنتعاون عليه وعلى التقوى. الخطأ الشائع ظنُّ أنّ التعاون يكون على أيّ شيء، والصواب أنّه على الخير فقط لا على الأذى.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2bd46fc3-8ee7-5614-9c8d-b7a07d7cf2e9', '4336768d-921c-5884-9687-3f605b2d0784', 'رأى تلميذٌ جارَه العجوزَ يحمل أكياسًا ثقيلة. ما الأحسن أن يفعل؟', '[{"id":"a","text":"يُسارع إلى مساعدته في حملها"},{"id":"b","text":"يمرّ ولا يلتفت إليه"},{"id":"c","text":"يضحك عليه"},{"id":"d","text":"يطلب منه أجرًا"}]'::jsonb, 'a', 'من التعاون مع الجار أن نُسارع إلى مساعدته عند الحاجة دون مقابل. الخطأ الشائع الانشغالُ عن الجار أو طلبُ أجرٍ على معروفٍ بسيط.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ea0052e5-5a30-5495-992c-264011637c9f', '4336768d-921c-5884-9687-3f605b2d0784', 'ماذا نفهم من قول النبيّ ﷺ: «ما زال جبريل يوصيني بالجار حتّى ظننتُ أنّه سيورّثه»؟', '[{"id":"a","text":"أنّ الجار لا حقَّ له"},{"id":"b","text":"أنّ الجار يأخذ الميراثَ فعلًا"},{"id":"c","text":"أنّ الوصيّة بالجار مرّةٌ واحدة"},{"id":"d","text":"أنّ حقَّ الجار عظيمٌ جدًّا"}]'::jsonb, 'd', 'كثرةُ وصيّةِ جبريل بالجار جعلت النبيّ ﷺ يظنّ أنّ للجار نصيبًا من الميراث، وهذا يدلّ على عِظَمِ حقّ الجار. الخطأ الشائع فهمُ أنّ الجار يرث فعلًا، وإنّما هو تعبيرٌ عن عظم حقّه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4bb5999f-650e-5c53-8d11-f07fa19625c1', '4336768d-921c-5884-9687-3f605b2d0784', 'الجارُ الذي له حقٌّ علينا هو ...', '[{"id":"a","text":"المسلمُ القريب فقط"},{"id":"b","text":"الكبيرُ دون الصغير"},{"id":"c","text":"كلُّ جارٍ قريبًا كان أم بعيدًا، مسلمًا أم غيرَ مسلم"},{"id":"d","text":"الغنيُّ دون الفقير"}]'::jsonb, 'c', 'للجار حقٌّ علينا سواءٌ أكان قريبًا أم بعيدًا، مسلمًا أم غيرَ مسلم. الخطأ الشائع حصرُ حقّ الجوار في الجار المسلم القريب وحده.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2ac113e5-bfdc-5888-a146-31c95cfaeda2', '4336768d-921c-5884-9687-3f605b2d0784', 'أصاب جارَنا حُزنٌ بمرضٍ في بيته. ما الذي يدلّ على حُسن الجوار؟', '[{"id":"a","text":"أن نُقيم حفلةً صاخبة"},{"id":"b","text":"أن نتجاهل حُزنه"},{"id":"c","text":"أن نرفع أصواتنا فرحين"},{"id":"d","text":"أن نُواسيَه ونعوده ونقف بجانبه"}]'::jsonb, 'd', 'من حُسن الجوار مشاركةُ الجار أتراحَه، فنُواسيه ونعوده عند المرض ونقف بجانبه. الخطأ الشائع إظهارُ الفرح أو إزعاجُه وهو في حُزن.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('36dcdf96-68ce-54dc-95e4-ad3a79331bf1', '4336768d-921c-5884-9687-3f605b2d0784', 'طلب صديقٌ من تلميذٍ أن يتعاونا على إزعاج جارٍ يكرهانه. ما الصواب؟', '[{"id":"a","text":"يتعاون معه لأنّ التعاون مطلوبٌ دائمًا"},{"id":"b","text":"يرفض؛ لأنّ التعاون يكون على الخير لا على الأذى"},{"id":"c","text":"يُزعج الجارَ مرّةً واحدة فقط"},{"id":"d","text":"يساعده ثمّ يعتذر للجار"}]'::jsonb, 'b', 'التعاونُ مأمورٌ به على البِرّ والتقوى لا على الإثم والعدوان، فيرفض إيذاءَ الجار. الخطأ الشائع ظنُّ أنّ كلَّ تعاونٍ محمود، والصواب أنّ التعاون على الأذى محرَّم.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

