INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('37cd8df3-76c2-55c7-b74f-b6df814695dd', '0312ced8-7cf4-50d7-8090-61fa360c44d4', 'نُشاركُ جارَنا في أفراحه، مثلَ ...', '[{"id":"a","text":"إزعاجِه في العُرس"},{"id":"b","text":"تهنئتِه بنجاحه"},{"id":"c","text":"السّخريةِ منه"},{"id":"d","text":"تجاهلِه"}]'::jsonb, 'b', 'من مشاركة الجار أفراحَه أن نُهنّئه بنجاحه أو عُرسه أو مولوده، فنفرح لفرحه؛ فتقوى المحبّة بيننا. الخطأ الشائع إظهارُ السّخرية أو الإزعاج في فرح الجار.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9493fb7d-726a-573d-81bc-cc3b6ac2117c', '0312ced8-7cf4-50d7-8090-61fa360c44d4', 'قال الله: «وَتَعَاوَنُوا عَلَى ...».', '[{"id":"a","text":"الْبِرِّ وَالتَّقْوَىٰ"},{"id":"b","text":"الْإِثْمِ وَالْعُدْوَانِ"},{"id":"c","text":"اللّهوِ واللّعبِ"},{"id":"d","text":"المالِ والجاهِ"}]'::jsonb, 'a', 'قال الله: «وَتَعَاوَنُوا عَلَى الْبِرِّ وَالتَّقْوَىٰ»، أي على الخير وطاعة الله، ونهانا عن التعاون على الإثم والعدوان. الخطأ الشائع الخلطُ فنظنّ الآيةَ تأمر بالتعاون على الإثم.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0271ef8d-31ef-5b07-a3af-18bc5a4ac067', '0312ced8-7cf4-50d7-8090-61fa360c44d4', 'أوصى جبريلُ عليه السلام النبيَّ ﷺ كثيرًا بـ...', '[{"id":"a","text":"المالِ"},{"id":"b","text":"الجارِ"},{"id":"c","text":"السّفرِ"},{"id":"d","text":"الطّعامِ"}]'::jsonb, 'b', 'قال النبيّ ﷺ: «ما زال جبريل يوصيني بالجار حتّى ظننتُ أنّه سيورّثه»؛ فقد كثُرت وصيّةُ جبريل بالجار. الخطأ الشائع ظنُّ أنّ الوصيّة كانت بالمال أو الطعام لا بالجار.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6e429cb5-4e84-5a67-876a-ad0dbfbe68f6', '0312ced8-7cf4-50d7-8090-61fa360c44d4', 'من حقوق الجار علينا أن ...', '[{"id":"a","text":"نرفع الصوتَ المزعج عليه"},{"id":"b","text":"نرمي القُمامة أمام بابه"},{"id":"c","text":"نساعده عند الحاجة ونكُفّ عنه الأذى"},{"id":"d","text":"نُفشيَ أسراره"}]'::jsonb, 'c', 'من حقوق الجار أن نساعده عند الحاجة ونكُفّ عنه الأذى ونحفظ سِرّه؛ أمّا الإزعاجُ ورمْيُ القُمامة وإفشاءُ السرّ فهي من الأذى المنهيّ عنه. الخطأ الشائع عدُّ هذه الإساءات أمورًا بسيطةً لا تضرّ الجار.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5f80970c-d9b8-54cf-bb10-6de56af02327', '0312ced8-7cf4-50d7-8090-61fa360c44d4', 'نتعاون على البِرّ والتقوى، ولا نتعاون على ...', '[{"id":"a","text":"الخيرِ"},{"id":"b","text":"طاعةِ الله"},{"id":"c","text":"العملِ الصالح"},{"id":"d","text":"الإثمِ والأذى"}]'::jsonb, 'd', 'التعاونُ يكون على الخير والطاعة والعمل الصالح، ولا يكون على الإثم والأذى؛ قال الله: «وَلَا تَعَاوَنُوا عَلَى الْإِثْمِ وَالْعُدْوَانِ». الخطأ الشائع ظنُّ أنّ التعاون محمودٌ مهما كان الهدف.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3723e818-01cb-5156-9d94-aa22d7ff9679', '8cfa1210-dd8b-57cf-a33a-41b87730d3c5', 'education-islamique-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: بطلُ التعاون والجوار', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
