  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6109c17b-47ac-59f9-b570-a5dd452bdadc', '3723e818-01cb-5156-9d94-aa22d7ff9679', 'سكنَ بجوار سعيدٍ جارٌ غيرُ مسلم. كيف يُعامله سعيدٌ وفق ما تعلّمناه؟', '[{"id":"a","text":"يُهمله لأنّه ليس مسلمًا"},{"id":"b","text":"يؤذيه ليرحل"},{"id":"c","text":"يُحسن جِوارَه؛ فحقُّ الجوار للجميع"},{"id":"d","text":"يرفض مساعدته أبدًا"}]'::jsonb, 'c', 'حقُّ الجوار ثابتٌ لكلّ جارٍ، مسلمًا كان أم غيرَ مسلم، فيُحسن إليه ويكُفّ عنه الأذى. الخطأ الشائع حصرُ حُسن الجوار في الجار المسلم وحده.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b3ffd29e-a44e-5b57-b85d-55d4979c50b3', '3723e818-01cb-5156-9d94-aa22d7ff9679', 'طلب صبيٌّ من جاره أن يتعاونا على أخذ ثمارٍ من بستان جارٍ آخر دون إذنه. ما الصواب؟', '[{"id":"a","text":"يتعاون معه؛ لأنّ التعاون خيرٌ كلُّه"},{"id":"b","text":"يرفض؛ فهذا تعاونٌ على الأذى وأخذِ ما ليس له"},{"id":"c","text":"يأخذ القليلَ فقط"},{"id":"d","text":"يأخذ ثمّ يُخبر الجار بعد ذلك"}]'::jsonb, 'b', 'التعاونُ يكون على البِرّ والتقوى لا على الإثم والعدوان، وأخذُ مال الغير بغير إذنه أذى. الخطأ الشائع ظنُّ أنّ كلَّ تعاونٍ محمود، والصواب أنّ التعاون على الأذى محرَّم.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('31d3b855-0709-5153-b493-6c247bfdf4e4', '3723e818-01cb-5156-9d94-aa22d7ff9679', 'سمِعت سلمى أنّ جارتَها مريضةٌ في البيت. ما التصرّفُ الأفضل الذي يدلّ على حُسن الجوار؟', '[{"id":"a","text":"تُقيم حفلةً صاخبةً بجوارها"},{"id":"b","text":"تتجاهلها تمامًا"},{"id":"c","text":"تنتظر حتّى تشفى وحدها"},{"id":"d","text":"تعودُها وتسأل عن حاجتها وتُساعدها"}]'::jsonb, 'd', 'من مشاركة الجار أتراحَه عيادتُه عند المرض والسؤالُ عن حاجته ومساعدتُه. الخطأ الشائع الانشغالُ عن الجار وقتَ حاجته، أو إزعاجُه وهو مريض.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cce0f1b0-72c9-55e7-bb23-61235311db04', '3723e818-01cb-5156-9d94-aa22d7ff9679', 'أيُّ هذه التصرّفات يجمع بين التعاون مع الجار وكفِّ الأذى عنه معًا؟', '[{"id":"a","text":"أُساعده في حمل أمتعته وأخفض صوتي قُربَ بيته"},{"id":"b","text":"أُساعده ثمّ أرمي القُمامة أمام بابه"},{"id":"c","text":"أُلقي السلام عليه ثمّ أُزعجه ليلًا"},{"id":"d","text":"أُعيره أدواتي ثمّ أُفشي سِرّه"}]'::jsonb, 'a', 'حُسنُ الجوار يجمع فعلَ المعروف (المساعدة) وتركَ الأذى (خفض الصوت)، والخيارات الأخرى تخلط معروفًا بأذى فتُفسده. الخطأ الشائع ظنُّ أنّ المعروف يُبرّر ما يصاحبه من أذى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3cb37d00-dd41-56d5-9183-26bcb71b7919', '3723e818-01cb-5156-9d94-aa22d7ff9679', 'نجح جارُ كريمٍ في امتحانه ففرِح، وفي اليوم نفسه مرِض جارٌ آخر. كيف يجمع كريمٌ بين الأمرين؟', '[{"id":"a","text":"يفرح للأوّل فقط ويترك المريض"},{"id":"b","text":"يحزن للجميع"},{"id":"c","text":"يُهنّئ الناجحَ ويُواسي المريضَ ويعوده"},{"id":"d","text":"يتجاهلهما معًا"}]'::jsonb, 'c', 'الجارُ الحقّ يُشارك جيرانَه أفراحَهم وأتراحَهم معًا، فيُهنّئ الناجحَ ويُواسي المريضَ ويعوده. الخطأ الشائع الاكتفاءُ بمشاركة الفرح وإهمالُ صاحب الحزن.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d16bd773-7430-51c5-ad53-5a246713e892', '3723e818-01cb-5156-9d94-aa22d7ff9679', 'قال تلميذٌ: «حقُّ الجار يسقط إذا أساء إليّ مرّةً». هل قولُه صحيح؟', '[{"id":"a","text":"نعم، نقطع كلَّ إحسانٍ عنه"},{"id":"b","text":"لا، نُقابل إساءتَه بالصبر وحُسن الجوار ونكُفّ الأذى"},{"id":"c","text":"نعم، ونؤذيه أكثرَ منه"},{"id":"d","text":"نعم، ونطرده من الحيّ"}]'::jsonb, 'b', 'حُسنُ الجوار خُلقٌ ثابتٌ يحبّه الله، فنصبر على أذى الجار ونُحسن إليه ونكُفّ عنه الأذى. الخطأ الشائع مقابلةُ الإساءة بالإساءة، والأفضلُ الإحسانُ والصبر.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

