  ('50b0b10a-1a91-5162-8299-ec370bd96fa1', '8cfa1210-dd8b-57cf-a33a-41b87730d3c5', 'education-islamique-4eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة للتعاون وحقّ الجار', 3, 120, 30, 'boss', 'admin', 5)
