INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3a7f8906-4590-5fe5-9256-bb23c2aaacf5', '50b0b10a-1a91-5162-8299-ec370bd96fa1', 'حُسنُ الجوار خُلقٌ ...', '[{"id":"a","text":"يحبّه الله"},{"id":"b","text":"يكرهه الله"},{"id":"c","text":"لا قيمةَ له"},{"id":"d","text":"خاصٌّ بالكبار فقط"}]'::jsonb, 'a', 'حُسنُ الجوار خُلقٌ جميلٌ يحبّه الله، وقد أوصى به النبيُّ ﷺ كثيرًا. الخطأ الشائع الاستهانةُ بحُسن الجوار وعدُّه أمرًا لا قيمةَ له.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
