  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a62438d5-381a-5f97-a404-51f6c65ff8c2', '50b0b10a-1a91-5162-8299-ec370bd96fa1', 'معنى التقوى في قول الله «وَتَعَاوَنُوا عَلَى الْبِرِّ وَالتَّقْوَىٰ» ...', '[{"id":"a","text":"جمعُ المال"},{"id":"b","text":"كثرةُ اللّعب"},{"id":"c","text":"طاعةُ الله واجتنابُ ما نهى عنه"},{"id":"d","text":"السّفرُ الطويل"}]'::jsonb, 'c', 'التقوى هي طاعةُ الله واجتنابُ ما نهى عنه، فنتعاون عليها وعلى البِرّ، أي على كلّ خير. الخطأ الشائع حصرُ التقوى في جمع المال أو غيره ممّا لا علاقة له بطاعة الله.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('195a8433-e4d8-5b3a-9d46-f953a316cf88', '50b0b10a-1a91-5162-8299-ec370bd96fa1', 'كرّر جبريلُ عليه السلام الوصيّةَ بالجار حتّى ظنّ النبيّ ﷺ أنّ الجار ...', '[{"id":"a","text":"لا حقَّ له"},{"id":"b","text":"سيكون له نصيبٌ من الميراث"},{"id":"c","text":"يجب أن يرحل"},{"id":"d","text":"لا يُزار أبدًا"}]'::jsonb, 'b', 'قال النبيّ ﷺ: «ما زال جبريل يوصيني بالجار حتّى ظننتُ أنّه سيورّثه»؛ وهذا تعبيرٌ عن عِظَمِ حقّ الجار، لا أنّه يرث فعلًا. الخطأ الشائع فهمُ أنّ الجار يأخذ الميراثَ حقيقةً.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
