  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c5fe45da-c272-580c-b6e2-298c00337db6', '50b0b10a-1a91-5162-8299-ec370bd96fa1', 'أيُّ هذه الأعمال ليس من حُسن الجوار؟', '[{"id":"a","text":"مساعدةُ الجار عند الحاجة"},{"id":"b","text":"إلقاءُ السلام عليه"},{"id":"c","text":"عيادتُه عند المرض"},{"id":"d","text":"رفعُ الصوتِ المزعج قُربَ بيته"}]'::jsonb, 'd', 'رفعُ الصوت المزعج أذى للجار، ونحن مأمورون بكفّ الأذى عنه؛ أمّا المساعدةُ والسلامُ والعيادةُ فهي من حُسن الجوار. الخطأ الشائع التساهلُ في إزعاج الجار بالأصوات المرتفعة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
