  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c52f4d82-5b52-58dd-98bb-c5f085906baa', '50b0b10a-1a91-5162-8299-ec370bd96fa1', 'طلب منك جارُك أن تُعيره أداةً يحتاجها، وأنت تقدر على ذلك. ما الأحسن؟', '[{"id":"a","text":"أرفض دون سبب"},{"id":"b","text":"أطلب منه مالًا"},{"id":"c","text":"أُعيره إيّاها وأُعينه"},{"id":"d","text":"أتجاهل طلبه"}]'::jsonb, 'c', 'من التعاون مع الجار أن نُعيره ما يحتاج ونُعينه بما نقدر عليه. الخطأ الشائع البخلُ على الجار بمعروفٍ يسير أو طلبُ مقابلٍ عليه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
