INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4bd90587-c80e-586d-9ec6-28e24b5a20eb', '50b0b10a-1a91-5162-8299-ec370bd96fa1', 'تلميذٌ يُحسن إلى جاره القريب ويُهمل جاره البعيد بحجّة بُعده. ما الصواب؟', '[{"id":"a","text":"حقُّ الجوار للقريب والبعيد معًا، فيُحسن إليهما"},{"id":"b","text":"يكفي الإحسانُ إلى القريب وحده"},{"id":"c","text":"يُهمل القريبَ ويُحسن إلى البعيد"},{"id":"d","text":"لا حقَّ لأيّ جار"}]'::jsonb, 'a', 'الجارُ القريبُ والجارُ البعيدُ كلاهما له حقٌّ علينا، فنُحسن إليهما جميعًا. الخطأ الشائع قصرُ حقّ الجوار على الجار الملاصق وحده.', 6)
