INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f4e7c3ae-862e-50cd-83dc-7af5859e8156', '2d3328c6-0cf6-5840-8090-0c28422394eb', 'ما معنى «اقصِد في مشيك»؟', '[{"id":"a","text":"أن تركض دائمًا بسرعة"},{"id":"b","text":"أن تتوسّط في مشيك وتمشي باعتدال"},{"id":"c","text":"أن تمشي متبخترًا متكبّرًا"},{"id":"d","text":"أن تجلس ولا تمشي"}]'::jsonb, 'b', '«اقصِد في مشيك» معناها التوسّط والاعتدال في المشي، فلا إسراعٌ يؤذي الناس ولا تبختر.', 1)
