INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5e9fdf84-6379-50ed-9a5e-fac499d676d5', '2d3328c6-0cf6-5840-8090-0c28422394eb', 'قال الله في سورة لقمان: «وَاغْضُضْ مِنْ صَوْتِكَ»، ومعناها أن ...', '[{"id":"a","text":"نخفض أصواتنا ولا نرفعها بالصياح"},{"id":"b","text":"نرفع أصواتنا في الطريق"},{"id":"c","text":"نمنع الناس من الكلام"},{"id":"d","text":"نسكت ولا نتكلّم أبدًا"}]'::jsonb, 'a', '«اغضض من صوتك» أمرٌ بخفض الصوت، فلا نرفعه بالصياح لأنّ ذلك يؤذي المارّة.', 2)
