INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('606a8451-6131-50e2-8518-4e5c9610c557', '2d3328c6-0cf6-5840-8090-0c28422394eb', 'كيف نُفشي السلام في الطريق؟', '[{"id":"a","text":"نُشيح بوجهنا عن الناس"},{"id":"b","text":"نُسلّم على من نعرفهم فقط"},{"id":"c","text":"نصيح بأعلى صوتنا"},{"id":"d","text":"نقول: السلامُ عليكم، ونردّ التحيّة"}]'::jsonb, 'd', 'إفشاء السلام أن نقول «السلامُ عليكم» على من نعرف ومن لا نعرف، ونردّ السلام بمثله أو بأحسن منه.', 3)
