INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('54b660f9-87be-5cb8-9032-b0620bba152f', '2d3328c6-0cf6-5840-8090-0c28422394eb', 'ماذا يعني أن «نُميط الأذى» عن الطريق؟', '[{"id":"a","text":"أن نضع الحجارة في الطريق"},{"id":"b","text":"أن نرمي الأوساخ في الطريق"},{"id":"c","text":"أن نُزيل ما يؤذي الناس عن الطريق"},{"id":"d","text":"أن نزاحم الكبار والضعفاء"}]'::jsonb, 'c', 'إماطةُ الأذى أن نُزيل ما يؤذي المارّة كالحجر والزجاج، وقد قال النبيّ ﷺ إنّها صدقة.', 4)
