INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('af6b7a92-d70d-54de-b23f-58051b737430', '2d3328c6-0cf6-5840-8090-0c28422394eb', 'صديقٌ ناداك من بعيدٍ في الطريق فأردتَ اللحاق به، فما الأدبُ الصحيح؟', '[{"id":"a","text":"أركض بين السيّارات والمارّة بسرعة"},{"id":"b","text":"أمشي بهدوءٍ وأنتبه لمن حولي"},{"id":"c","text":"أصيح بأعلى صوتي حتّى يسمعني"},{"id":"d","text":"أدفع المارّة لأمرّ بسرعة"}]'::jsonb, 'b', 'القصدُ في المشي يعني الاعتدال، فأمشي بهدوءٍ وأنتبه للناس ولا أركض فأؤذيَ أحدًا.', 5)
