INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('54ad7f06-1284-5700-97f7-4124f27d6ea5', '03c7b7b1-e227-58a4-aef0-2e9737927869', 'في أيّ سورةٍ أمرَنا الله بالقصد في المشي والغضِّ من الصوت؟', '[{"id":"a","text":"سورة الفجر"},{"id":"b","text":"سورة الأعلى"},{"id":"c","text":"سورة لقمان"},{"id":"d","text":"سورة الطارق"}]'::jsonb, 'c', 'قول الله «وَاقْصِدْ فِي مَشْيِكَ وَاغْضُضْ مِنْ صَوْتِكَ» في سورة لقمان، الآية 19. الخطأ الشائع نِسبةُ الآية إلى سورةٍ أخرى من سور هذا المستوى.', 1)
