INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c707de2d-328c-5341-9b8d-7d757c4885e9', '094f51ba-4bc6-584f-a136-28c0d98a29d2', '«القصدُ في المشي» معناه ...', '[{"id":"a","text":"الإسراع الشديد"},{"id":"b","text":"الاعتدالُ والتوسّط في المشي"},{"id":"c","text":"البطء الزائد"},{"id":"d","text":"المشي بتكبّر"}]'::jsonb, 'b', 'القصدُ هو الاعتدالُ والتوسّط، كما قال الله «وَاقْصِدْ فِي مَشْيِكَ».', 1)
