INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('18926536-6a27-54ac-9f54-87850743e384', '094f51ba-4bc6-584f-a136-28c0d98a29d2', 'من آداب الطريق إفشاءُ السلام، أي ...', '[{"id":"a","text":"أن نقول «السلامُ عليكم» ونردّ التحيّة"},{"id":"b","text":"أن نمرّ بصمتٍ دائمًا"},{"id":"c","text":"أن نُسلّم على الكبار فقط"},{"id":"d","text":"أن نرفع أصواتنا بالتحيّة"}]'::jsonb, 'a', 'إفشاءُ السلام أن نُلقي التحيّة فنقول «السلامُ عليكم» على من نعرف ومن لا نعرف، ونردّ السلام بمثله أو بأحسن منه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e9bfb50-ca50-57bb-b1e5-999acf23decd', '094f51ba-4bc6-584f-a136-28c0d98a29d2', 'آيةُ آداب المشي «وَاقْصِدْ فِي مَشْيِكَ وَاغْضُضْ مِنْ صَوْتِكَ» جاءت في سورة ...', '[{"id":"a","text":"الغاشية"},{"id":"b","text":"الطارق"},{"id":"c","text":"لقمان"},{"id":"d","text":"الأعلى"}]'::jsonb, 'c', 'هذه الآيةُ من سورة لقمان (الآية 19)، وهي من وصيّة لقمان الحكيم لابنه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4e03495b-f3c2-5d5a-ac4c-efb5036debb9', '094f51ba-4bc6-584f-a136-28c0d98a29d2', 'أيُّ هذه السلوكات يُؤذي المارّة في الطريق؟', '[{"id":"a","text":"خفض الصوت"},{"id":"b","text":"إفشاء السلام"},{"id":"c","text":"المشي باعتدال"},{"id":"d","text":"رمي الأوساخ ووضع ما يعرقل الناس"}]'::jsonb, 'd', 'رميُ الأوساخ ووضعُ ما يعرقل الناس من إيذاء المارّة، وهو خلافُ آداب الطريق.', 4)
