INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cefd496d-b044-54b5-8dba-f38d6fe10a65', '094f51ba-4bc6-584f-a136-28c0d98a29d2', 'قال النبيّ ﷺ إنّ إماطةَ الأذى عن الطريق ...', '[{"id":"a","text":"أمرٌ صعبٌ نتركه"},{"id":"b","text":"لا أجر فيها"},{"id":"c","text":"صدقةٌ يُثيبنا الله عليها"},{"id":"d","text":"خاصّةٌ بالكبار"}]'::jsonb, 'c', 'قال النبيّ ﷺ: «وَإِمَاطَةُ الأَذَى عَنِ الطَّرِيقِ صَدَقَةٌ»، فإزالةُ ما يؤذي الناس عملٌ صالحٌ يُثاب عليه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('925aed0e-589e-5792-a066-e40fc0208b9f', '094f51ba-4bc6-584f-a136-28c0d98a29d2', 'خرجتَ مع أصحابك من المدرسة فأردتم الصياح في الشارع، فما الأدبُ الصحيح؟', '[{"id":"a","text":"نخفض أصواتنا رحمةً بالناس من حولنا"},{"id":"b","text":"نرفع أصواتنا أكثر"},{"id":"c","text":"نركض ونصدم المارّة"},{"id":"d","text":"نرمي الأوساخ ونمضي"}]'::jsonb, 'a', 'نتذكّر قول الله «وَاغْضُضْ مِنْ صَوْتِكَ» فنخفض أصواتنا، لأنّ رفع الصوت يؤذي المارّة ومن في البيوت القريبة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

