INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b2b74543-23cd-519d-ac4e-e9146ec027fe', '38f9f6b4-433b-5069-a6e3-5412a0e4adcf', 'مشى تلميذٌ متمايلًا متباهيًا بنفسه أمام أصحابه في الطريق. أيُّ أدبٍ خالف؟', '[{"id":"a","text":"إفشاء السلام"},{"id":"b","text":"إماطة الأذى"},{"id":"c","text":"الغضّ من الصوت"},{"id":"d","text":"القصد في المشي"}]'::jsonb, 'd', 'القصدُ في المشي اعتدالٌ ووقار، والتمايلُ تباهيًا تبخترٌ يخالفه. الخطأ الشائع ظنُّ أنّ التبختر أمام الأصحاب قوّةٌ أو شجاعة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('394b3be7-ac48-5d8f-84b9-df22ed7b3164', '38f9f6b4-433b-5069-a6e3-5412a0e4adcf', 'أرادَ تلميذٌ أن يجمع بين أدبَين أمرَ الله بهما في آيةٍ واحدةٍ من سورة لقمان. ما هما؟', '[{"id":"a","text":"الصومُ والصلاة"},{"id":"b","text":"القصدُ في المشي والغضُّ من الصوت"},{"id":"c","text":"برُّ الوالدين وطلبُ العلم"},{"id":"d","text":"الصدقةُ والحجّ"}]'::jsonb, 'b', 'قال الله «وَاقْصِدْ فِي مَشْيِكَ وَاغْضُضْ مِنْ صَوْتِكَ»، فجمعت الآيةُ بين الاعتدال في المشي وخفضِ الصوت. الخطأ الشائع الخلطُ بين هذه الآية وآياتٍ في موضوعاتٍ أخرى.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6f15b8b6-fdab-55f4-8924-402bcae9246e', '38f9f6b4-433b-5069-a6e3-5412a0e4adcf', 'مرّ تلميذٌ بجارٍ كبيرٍ لا يعرفه جالسٍ أمام بيته. ما الأكملُ في أدبه؟', '[{"id":"a","text":"يمرّ بصمتٍ لأنّه لا يعرفه"},{"id":"b","text":"ينتظر حتّى يبدأه الجارُ بالسلام"},{"id":"c","text":"يبدأهُ بالسلام: السلامُ عليكم"},{"id":"d","text":"يرفع صوته ليلفت انتباهه"}]'::jsonb, 'c', 'إفشاءُ السلام يكون على من نعرف ومن لا نعرف، والبدءُ به أدبٌ وفضل. الخطأ الشائع ظنُّ أنّ السلام لا يكون إلّا على المعارف.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('57654fb7-d080-516b-a536-86bb5c3f6de6', '38f9f6b4-433b-5069-a6e3-5412a0e4adcf', 'رأى تلميذان حجرًا كبيرًا في وسط الطريق يعرقل المارّة. ما أحسنُ تصرّفٍ منهما؟', '[{"id":"a","text":"يُزيلانه إلى جانب الطريق فتكون لهما صدقة"},{"id":"b","text":"يتركانه فهو ليس مسؤوليّتهما"},{"id":"c","text":"يضعان قربه حجرًا آخر"},{"id":"d","text":"يجلسان عليه ليلعبا"}]'::jsonb, 'a', 'إماطةُ الأذى عن الطريق صدقةٌ، فإزالةُ ما يعرقل الناس عملٌ صالحٌ يُثاب عليه. الخطأ الشائع التهرّبُ من الأعمال الصالحة بحجّة أنّها ليست مسؤوليّتنا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5c021035-ed4e-5ed0-b92a-79fc4cb76618', '38f9f6b4-433b-5069-a6e3-5412a0e4adcf', 'في طريقٍ ضيّقٍ مزدحم، رأى تلميذٌ رجلًا كبيرًا في السنّ يريد المرور. ما الأدبُ الذي يجمع آدابَ الطريق؟', '[{"id":"a","text":"يزاحمه ليمرّ هو أوّلًا"},{"id":"b","text":"يرفع صوته ليُفسح الناس له"},{"id":"c","text":"يركض متجاوزًا الجميع"},{"id":"d","text":"يُفسح له الطريق بهدوءٍ ويُسلّم عليه"}]'::jsonb, 'd', 'آدابُ الطريق تجتمع هنا: عدمُ المزاحمة، وخفضُ الصوت، وإفشاءُ السلام، واحترامُ الكبير. الخطأ الشائع تقديمُ النفس على الضعفاء والكبار في الزحام.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6ef7f5c1-43de-5dde-b1b7-3e985c71c86d', '38f9f6b4-433b-5069-a6e3-5412a0e4adcf', 'أيُّ مجموعةٍ كلُّها من آداب الطريق التي تعلّمناها؟', '[{"id":"a","text":"الإسراع، ورفع الصوت، ومزاحمة الناس"},{"id":"b","text":"القصد في المشي، والغضّ من الصوت، وإفشاء السلام، وإماطة الأذى"},{"id":"c","text":"التبختر، ورمي الأوساخ، والصياح"},{"id":"d","text":"ترك السلام، وعرقلة المارّة، والركض"}]'::jsonb, 'b', 'آدابُ الطريق هي: القصدُ في المشي، والغضُّ من الصوت، وإفشاءُ السلام، وعدمُ إيذاء المارّة، وإماطةُ الأذى. الخطأ الشائع الخلطُ بين الأدب وما يُخالفه من السلوكات السيّئة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

