INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('32a65833-8555-599c-8086-a652cd0466d8', '2b21d2ee-7c48-58ff-8c5d-fba535dd84e9', '«وَاقْصِدْ فِي مَشْيِكَ» أمرٌ بأن نمشي ...', '[{"id":"a","text":"مسرعين دائمًا"},{"id":"b","text":"متبخترين"},{"id":"c","text":"باعتدالٍ وتوسّط"},{"id":"d","text":"بطيئين جدًّا"}]'::jsonb, 'c', '«اقصِد في مشيك» أمرٌ بالاعتدال والتوسّط في المشي، لا إسراعٌ يؤذي الناس ولا تبختر.', 1)
