INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b04443bd-1ca9-5a0b-9755-abc8196ddd30', '2b21d2ee-7c48-58ff-8c5d-fba535dd84e9', '«وَاغْضُضْ مِنْ صَوْتِكَ» تعني ...', '[{"id":"a","text":"اخفض صوتك ولا ترفعه"},{"id":"b","text":"ارفع صوتك بالصياح"},{"id":"c","text":"اسكت ولا تتكلّم"},{"id":"d","text":"تكلّم بسرعة"}]'::jsonb, 'a', '«اغضض من صوتك» أمرٌ بخفض الصوت رحمةً بالناس، وليس معناه تركَ الكلام كلِّه.', 2)
