INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5af4e6d2-7b70-5c2a-a493-f69a77953cd4', '2b21d2ee-7c48-58ff-8c5d-fba535dd84e9', 'من أجمل آداب الطريق التي تزرع المحبّة بين الناس ...', '[{"id":"a","text":"رفع الصوت"},{"id":"b","text":"المرور بصمتٍ دائمًا"},{"id":"c","text":"الإسراع في المشي"},{"id":"d","text":"إفشاء السلام"}]'::jsonb, 'd', 'إفشاءُ السلام يزرع المحبّة ويُذهب الوحشة بين الناس، فنقول «السلامُ عليكم».', 3)
