INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ce9935ac-8c52-50b1-890a-f94f9f46af1e', '2b21d2ee-7c48-58ff-8c5d-fba535dd84e9', 'تلميذٌ يركض بسرعةٍ بين المارّة فصدمَ طفلًا صغيرًا. أيَّ أدبٍ خالف؟', '[{"id":"a","text":"إفشاء السلام"},{"id":"b","text":"القصد في المشي"},{"id":"c","text":"الغضّ من الصوت"},{"id":"d","text":"ردّ التحيّة"}]'::jsonb, 'b', 'القصدُ في المشي اعتدالٌ يحفظ سلامة الناس، والركضُ بينهم يؤذيهم ويخالف هذا الأدب. الخطأ الشائع الاستعجالُ دون انتباهٍ لمن حولنا.', 4)
