INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b9f0c736-9760-5b2b-b853-83a2d7aa4953', '2b21d2ee-7c48-58ff-8c5d-fba535dd84e9', 'ما حُكمُ إزالة الحجر والزجاج المؤذي عن طريق المارّة؟', '[{"id":"a","text":"صدقةٌ يُثاب عليها المسلم"},{"id":"b","text":"أمرٌ لا فائدة منه"},{"id":"c","text":"خاصٌّ بالكبار وحدهم"},{"id":"d","text":"مكروهٌ تركه فقط"}]'::jsonb, 'a', 'قال النبيّ ﷺ: «وَإِمَاطَةُ الأَذَى عَنِ الطَّرِيقِ صَدَقَةٌ»، فإزالةُ الأذى عملٌ صالحٌ يُثاب عليه الصغيرُ والكبير. الخطأ الشائع التهاونُ بالأعمال الصغيرة.', 5)
