INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b02b55f-407d-5b8f-86a6-1491d67efd09', '2b21d2ee-7c48-58ff-8c5d-fba535dd84e9', 'أيُّ هذه السلوكات يُخالف آدابَ الطريق؟', '[{"id":"a","text":"المشي باعتدال"},{"id":"b","text":"إلقاء السلام وردُّه"},{"id":"c","text":"مزاحمة الكبار والضعفاء ورفع الصوت"},{"id":"d","text":"إماطة الأذى عن الطريق"}]'::jsonb, 'c', 'مزاحمةُ الكبار والضعفاء ورفعُ الصوت من إيذاء المارّة، وهو خلافُ آداب الطريق. الخطأ الشائع الخلطُ بين الأدب وما يُضادّه من السلوكات.', 6)
