INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('12710bbe-230a-5220-9e5c-9d1529e8bc7d', '79e5381d-7f80-5940-a302-fcc60c77e3d7', 'ماذا نُسمّي زيارةَ المريض خاصّةً؟', '[{"id":"a","text":"الهديّة"},{"id":"b","text":"العِيادة"},{"id":"c","text":"الاستئذان"},{"id":"d","text":"الانصراف"}]'::jsonb, 'b', 'زيارةُ المريض لها اسمٌ خاصّ هو العِيادة، وهي من آداب التزاور بين المسلمين. الخطأ الشائع الخلط بين العِيادة وبين الهديّة.', 1)
