  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f20593a-5826-5e54-902d-5f4711d02547', '79e5381d-7f80-5940-a302-fcc60c77e3d7', 'متى لا يُستحبّ أن نزور الناس؟', '[{"id":"a","text":"في أيّ وقتٍ مناسب اتّفقنا عليه"},{"id":"b","text":"بعد أن نُخبرهم ويستعدّوا"},{"id":"c","text":"حين يكونون مستعدّين مسرورين"},{"id":"d","text":"وقتَ نومهم أو طعامهم أو انشغالهم"}]'::jsonb, 'd', 'من الأدب أن نختار الوقتَ المناسب، فلا نزور الناسَ وقتَ نومهم أو طعامهم أو انشغالهم. الخطأ الشائع الزيارةُ في وقتٍ يُتعِب صاحبَ البيت.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b2eae07f-4617-5b9b-b6da-56832b62af2b', '79e5381d-7f80-5940-a302-fcc60c77e3d7', 'كيف تكون الزيارةُ المحبوبةُ إلى القلوب؟', '[{"id":"a","text":"طويلةً جدًّا حتّى يَملّ صاحبُ البيت"},{"id":"b","text":"بلا سلامٍ ولا استئذان"},{"id":"c","text":"قصيرةً لطيفةً بلا إطالة"},{"id":"d","text":"في وقت نوم أصحاب البيت"}]'::jsonb, 'c', 'الزيارةُ القصيرةُ اللطيفة أحبُّ إلى القلوب من الطويلة التي تُتعِب صاحبَ البيت. الخطأ الشائع ظنّ أنّ طولَ الزيارة دليلُ محبّة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('95b431fa-8e2d-5199-9cf5-c0e66344f21c', '79e5381d-7f80-5940-a302-fcc60c77e3d7', 'في حديث رسول الله ﷺ: «… وإذا مَرِضَ فـ…»، ماذا نفعل لأخينا المسلم؟', '[{"id":"a","text":"نَعُودُه (نزوره ونطمئنّ عليه)"},{"id":"b","text":"نتركه حتّى يَشفى وحده"},{"id":"c","text":"ننتظر حتّى يزورنا أوّلًا"},{"id":"d","text":"نُطيل الجلوسَ عنده كثيرًا"}]'::jsonb, 'a', 'جعلَ النبيّ ﷺ عيادةَ المريض حقًّا من حقوق المسلم: «وإذا مَرِضَ فعُدْهُ» (رواه مسلم). الخطأ الشائع إهمالُ المريض أو إطالةُ الجلوس عنده فنُتعِبه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6cbf94ed-6434-5cb4-95ba-13d6ce305a2f', '79e5381d-7f80-5940-a302-fcc60c77e3d7', 'حين نعود المريض، ما الأدبُ الذي نفعله معه؟', '[{"id":"a","text":"نُحدّثه عن همومنا ونُطيل عنده"},{"id":"b","text":"ندعو له بالشفاء ونُخفّف عنه"},{"id":"c","text":"نطلب منه أن يُحضّر لنا الطعام"},{"id":"d","text":"نرفع صوتنا حتّى يسمعنا"}]'::jsonb, 'b', 'حين نعود المريضَ ندعو له بالشفاء ونقول له كلامًا طيّبًا يُصبّره، ولا نُطيل حتّى لا نُتعِبه. الخطأ الشائع إثقالُ المريض بدل التخفيف عنه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

