INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d6e03ee3-b2d4-5554-b9df-5028acae4f70', '2c0333b3-49ef-58dc-afdd-855937bd7365', 'التزاورُ بين المسلمين يزيد ...', '[{"id":"a","text":"البُعدَ والخصام"},{"id":"b","text":"المحبّةَ بين القلوب"},{"id":"c","text":"التعبَ فقط"},{"id":"d","text":"الكسلَ"}]'::jsonb, 'b', 'التزاورُ من أجمل ما يُقرّب القلوبَ ويزيد المحبّة بين الناس. الخطأ الشائع ظنّ أنّ الزيارة لا فائدة فيها.', 1)
