INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('243d42a0-77bc-52d0-94c7-2d65e7cc9637', '2c0333b3-49ef-58dc-afdd-855937bd7365', 'زيارةُ المريض تُسمّى ...', '[{"id":"a","text":"الاستئذان"},{"id":"b","text":"الهديّة"},{"id":"c","text":"الانصراف"},{"id":"d","text":"العِيادة"}]'::jsonb, 'd', 'زيارةُ المريض لها اسمٌ خاصّ هو العِيادة. الخطأ الشائع الخلط بينها وبين بقيّة الآداب.', 2)
