INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6fa0c6f-9348-57ed-911f-96b1a1c134bb', '2c0333b3-49ef-58dc-afdd-855937bd7365', 'قبل أن ندخل بيتَ مَن نزوره ...', '[{"id":"a","text":"نستأذن ونطرق البابَ برفق"},{"id":"b","text":"ندخل دون سلامٍ ولا إذن"},{"id":"c","text":"نفتح البابَ بقوّة"},{"id":"d","text":"ننادي بصوتٍ مرتفعٍ جدًّا"}]'::jsonb, 'a', 'إذا وصلنا إلى البيت استأذنّا قبل الدخول: نطرق البابَ برفقٍ أو نُسلّم. الخطأ الشائع الدخولُ بلا استئذان.', 3)
