INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8713f2c0-02f0-58b2-9b8c-b92072eaa864', '2c0333b3-49ef-58dc-afdd-855937bd7365', 'إن لم يأذن لنا صاحبُ البيت أو قال «ارجِعوا» ...', '[{"id":"a","text":"نُصرّ على الدخول"},{"id":"b","text":"نغضب ونخاصمه"},{"id":"c","text":"نرجع ولا نغضب"},{"id":"d","text":"نطرق البابَ بقوّة"}]'::jsonb, 'c', 'إن لم يُؤذَن لنا أو قيل «ارجِعوا» رجعنا ولم نغضب، فهذا من الأدب. الخطأ الشائع الغضبُ أو الإصرارُ على الدخول.', 4)
