INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f24e0eee-fe24-5b79-8fee-ff24439374b4', '2c0333b3-49ef-58dc-afdd-855937bd7365', 'الزيارةُ الأحبُّ إلى القلوب هي ...', '[{"id":"a","text":"الطويلةُ التي تُتعِب صاحبَ البيت"},{"id":"b","text":"القصيرةُ اللطيفةُ بلا إطالة"},{"id":"c","text":"التي بلا سلام"},{"id":"d","text":"التي في وقت النوم"}]'::jsonb, 'b', 'الزيارةُ القصيرةُ اللطيفة أحبُّ إلى القلوب من الطويلة التي تُتعِب صاحبَ البيت. الخطأ الشائع ظنّ أنّ طولَ الزيارة أفضل.', 5)
