INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('023d0aa2-1bbf-5c5e-aaf0-9b4859fc98a4', '2c0333b3-49ef-58dc-afdd-855937bd7365', 'حين يمرض جارُنا أو صديقُنا، ماذا نفعل؟', '[{"id":"a","text":"ننتظر حتّى يزورنا هو أوّلًا"},{"id":"b","text":"نتركه فالمرضُ شأنُه وحده"},{"id":"c","text":"نضحك ونلعب أمامه"},{"id":"d","text":"نَعُوده ونطمئنّ عليه وندعو له"}]'::jsonb, 'd', 'عيادةُ المريض حقٌّ من حقوق المسلم، فنزوره ونطمئنّ عليه وندعو له بالشفاء. الخطأ الشائع إهمالُ المريض.', 6)
