INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('844278a4-26b6-583f-b53d-7f18ef8ccf2e', '8168f778-4cd5-5081-8683-defa54d67dde', 'أرادَ سعيدٌ زيارةَ صديقه وقتَ القيلولة وهو نائم. ما الأفضلُ له؟', '[{"id":"a","text":"يطرق البابَ بقوّة حتّى يستيقظ"},{"id":"b","text":"يدخل دون استئذان"},{"id":"c","text":"يختار وقتًا آخرَ مناسبًا لزيارته"},{"id":"d","text":"يُلغي زيارته نهائيًّا ويخاصمه"}]'::jsonb, 'c', 'من الأدب اختيارُ الوقت المناسب، فلا نزور وقتَ النوم بل نختار وقتًا يكون فيه صاحبُ البيت مستعدًّا. الخطأ الشائع إزعاجُ النائم بدل تأجيل الزيارة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('18c83f7c-6712-5e14-8e62-820e26326c33', '8168f778-4cd5-5081-8683-defa54d67dde', 'زارَ أنسٌ جارَه فوجد عنده ضيوفًا. ما الأدبُ الذي فعله؟', '[{"id":"a","text":"سلّم واطمأنّ ولم يُطِل ثمّ انصرف بلطف"},{"id":"b","text":"جلس طويلًا وأكثرَ الكلام"},{"id":"c","text":"طلب من جاره أن يطرد ضيوفه"},{"id":"d","text":"رفع صوته ليسمعه الجميع"}]'::jsonb, 'a', 'من مراعاة ظروف المزور أن نُخفّف إذا كان مشغولًا، فنُسلّم ونطمئنّ ثمّ ننصرف بلطف. الخطأ الشائع الإطالةُ وإثقالُ صاحب البيت.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cdfb6352-c25f-5a4c-8055-1f17ab024177', '8168f778-4cd5-5081-8683-defa54d67dde', 'أُهديَ إليك صديقُك هديّةً صغيرةً بسيطة. ما الأدبُ في قبولها؟', '[{"id":"a","text":"نرفضها لأنّها صغيرة"},{"id":"b","text":"نَقبَلها بفرحٍ وشكرٍ ولو كانت يسيرة"},{"id":"c","text":"نطلب هديّةً أغلى منها"},{"id":"d","text":"نأخذها دون شكر"}]'::jsonb, 'b', 'نَقبَل هديّةَ أخينا بفرحٍ وشكر ولو كانت يسيرة، فالعبرةُ بالمحبّة لا بثمن الهديّة. الخطأ الشائع احتقارُ الهديّة الصغيرة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f48b70f7-2d3c-5c88-ac71-e408d17ce620', '8168f778-4cd5-5081-8683-defa54d67dde', 'متى نستأذن في الانصراف من الزيارة؟', '[{"id":"a","text":"لا ننصرف حتّى يطلب صاحبُ البيت ذلك"},{"id":"b","text":"نبقى إلى آخر الليل دائمًا"},{"id":"c","text":"إذا قضينا حاجتَنا واطمأنّ بعضُنا على بعض"},{"id":"d","text":"لا نستأذن، بل ننصرف فجأةً بلا سلام"}]'::jsonb, 'c', 'إذا قضينا حاجتَنا واطمأنّ بعضُنا على بعض استأذنّا في الانصراف وشكرنا صاحبَ البيت. الخطأ الشائع إطالةُ الجلوس بلا داعٍ.', 4)
