INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e74bd3f-1697-588b-8a4c-51327c0bfcda', '8168f778-4cd5-5081-8683-defa54d67dde', 'ما حقُّ المريض على أخيه المسلم كما في حديث النبيّ ﷺ؟', '[{"id":"a","text":"أن يُهديَه مالًا كثيرًا"},{"id":"b","text":"أن ينتظر حتّى يَشفى وحده"},{"id":"c","text":"أن يدعوَه إلى بيته"},{"id":"d","text":"أن يَعُوده ويزوره"}]'::jsonb, 'd', 'قال النبيّ ﷺ: «وإذا مَرِضَ فعُدْهُ» (رواه مسلم)، فعيادةُ المريض حقٌّ من حقوق المسلم. الخطأ الشائع ظنّ أنّ العيادة تطوّعٌ لا حقّ.', 5)
