INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1e213eb5-5218-5290-868c-4ba98f86c172', '8168f778-4cd5-5081-8683-defa54d67dde', 'دخلَ ولدٌ بيتَ جاره يزوره، فماذا يفعل من الأدب داخل البيت؟', '[{"id":"a","text":"يخفض صوته ولا يُفتّش في الأغراض"},{"id":"b","text":"يفتح الخزائنَ لينظر ما فيها"},{"id":"c","text":"يرفع صوته ويُكثِر الطلبات"},{"id":"d","text":"يأمر أهلَ البيت بما يريد"}]'::jsonb, 'a', 'من مراعاة المزور أن نتأدّب في بيته: نخفض أصواتنا ولا نُفتّش في أغراضه ونحترم أهله. الخطأ الشائع التصرّفُ في بيت الغير بلا أدب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
