  ('e17f990e-52e6-5f4d-99e4-d6bf7a600830', '621ca86e-bf97-5059-95f1-aeccc691e749', 'education-islamique-4eme', '⭐⭐ تمرين مراجعة: آداب الزيارة والعيادة (نمط امتحان)', 2, 75, 15, 'practice', 'admin', 3)
