INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fa8b9847-54e1-560a-9cf1-910e4c022677', 'e17f990e-52e6-5f4d-99e4-d6bf7a600830', 'التزاورُ هو أن ...', '[{"id":"a","text":"نبقى في بيوتنا ولا نزور أحدًا"},{"id":"b","text":"نزور الناسَ في أوقات نومهم"},{"id":"c","text":"نُهمل المريضَ والجار"},{"id":"d","text":"يزور المسلمون بعضُهم بعضًا"}]'::jsonb, 'd', 'التزاورُ أن يزور المسلمون بعضُهم بعضًا في بيوتهم، فتتقوّى المحبّة بينهم. الخطأ الشائع ظنّ أنّ الانعزالَ خيرٌ من التزاور.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
