  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d1effb4a-0cb8-59c8-b03b-116d8b86272a', 'e17f990e-52e6-5f4d-99e4-d6bf7a600830', 'أوّلُ أدبٍ في الزيارة هو ...', '[{"id":"a","text":"الإطالةُ في الجلوس"},{"id":"b","text":"اختيارُ الوقت المناسب"},{"id":"c","text":"رفعُ الصوت في البيت"},{"id":"d","text":"الدخولُ بلا استئذان"}]'::jsonb, 'b', 'أوّلُ أدبٍ في الزيارة اختيارُ الوقت المناسب، فلا نزور وقتَ النوم أو الطعام أو الانشغال. الخطأ الشائع إهمالُ مراعاة الوقت.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
