  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ef5f5f89-0625-5a95-8d1c-b7087e767db6', 'e17f990e-52e6-5f4d-99e4-d6bf7a600830', 'من مراعاة ظروف المزور أن ...', '[{"id":"a","text":"نُخفّف عنه إن كان متعبًا ولا نُثقِل عليه"},{"id":"b","text":"نُكثِر عليه الطلبات"},{"id":"c","text":"نطلب منه ما يَشُقّ عليه"},{"id":"d","text":"نبقى عنده وإن كان مشغولًا"}]'::jsonb, 'a', 'المسلمُ يُراعي ظروفَ مَن يزوره: إن رآه متعبًا أو مشغولًا خفّفَ عنه ولم يُثقِل عليه بالطلبات. الخطأ الشائع إثقالُ صاحب البيت.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f2946e90-288b-5350-8e64-ebfeb151d856', 'e17f990e-52e6-5f4d-99e4-d6bf7a600830', 'الهديّةُ بين المتزاورين ...', '[{"id":"a","text":"تُسبّب الخصام"},{"id":"b","text":"لا قيمةَ لها إن كانت صغيرة"},{"id":"c","text":"تُدخِل الفرحَ وتزيد المحبّة"},{"id":"d","text":"ممنوعةٌ بين الأصدقاء"}]'::jsonb, 'c', 'الهديّةُ ولو كانت صغيرةً تُدخِل الفرحَ على القلب وتزيد المحبّة بين المتزاورين، وكان النبيّ ﷺ يُحبّ التهادي. الخطأ الشائع احتقارُ الهديّة اليسيرة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a84a7a4a-a37f-5ffc-91bc-c726d1eebbb1', 'e17f990e-52e6-5f4d-99e4-d6bf7a600830', 'كيف نُعامل المريضَ حين نعوده؟', '[{"id":"a","text":"نُطيل عنده ونُحدّثه عن همومنا"},{"id":"b","text":"نطلب منه أن يخدمنا"},{"id":"c","text":"نرفع أصواتنا أمامه"},{"id":"d","text":"نُخفّف عنه وندعو له بالشفاء"}]'::jsonb, 'd', 'حين نعود المريضَ نُخفّف عنه ونقول له كلامًا طيّبًا وندعو له بالشفاء، ولا نُطيل حتّى لا نُتعِبه. الخطأ الشائع إثقالُ المريض بدل التخفيف عنه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ff3a0e7a-b9df-54cf-adcf-6d5df4aaed7e', 'e17f990e-52e6-5f4d-99e4-d6bf7a600830', 'بعد أن نقضيَ حاجتَنا في الزيارة، الأدبُ أن ...', '[{"id":"a","text":"نبقى أطولَ وقتٍ ممكن"},{"id":"b","text":"نستأذن في الانصراف ونشكر صاحبَ البيت"},{"id":"c","text":"ننصرف بلا سلامٍ ولا شكر"},{"id":"d","text":"نطلب الطعامَ قبل أن نخرج"}]'::jsonb, 'b', 'إذا قضينا حاجتَنا استأذنّا في الانصراف وشكرنا صاحبَ البيت على حسن استقباله. الخطأ الشائع الإطالةُ أو الانصرافُ بلا شكر.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('23208f90-49a3-5584-801d-0cc78e006897', '621ca86e-bf97-5059-95f1-aeccc691e749', 'education-islamique-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: بطلُ آداب التزاور', 4, 300, 60, 'challenge', 'admin', 4)
