INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('914533dc-424a-5540-a343-99a670a41dd0', '23208f90-49a3-5584-801d-0cc78e006897', 'علِمَ خالدٌ أنّ جارَه مريضٌ في بيته. ما التصرّفُ الموافقُ لهدي النبيّ ﷺ؟', '[{"id":"a","text":"يزوره يعوده ويدعو له بالشفاء بلا إطالة"},{"id":"b","text":"ينتظر حتّى يَشفى الجارُ ثمّ يزوره"},{"id":"c","text":"يكتفي بأن يسأل عنه غيرَه"},{"id":"d","text":"يزوره ويُطيل الجلوسَ ساعاتٍ ليُؤنسه"}]'::jsonb, 'a', 'قال النبيّ ﷺ: «وإذا مَرِضَ فعُدْهُ» (رواه مسلم)، ونعوده بلا إطالةٍ وندعو له بالشفاء. الخطأ الشائع تأخيرُ العيادة أو إطالتُها فنُتعِب المريض.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c15bed00-1318-5839-8f72-f7e00e960876', '23208f90-49a3-5584-801d-0cc78e006897', 'أهدى صديقٌ لزميله ثمرةً واحدةً يحبّها. كيف يكون ردُّ الزميل الموافقُ للأدب؟', '[{"id":"a","text":"يرفضها لأنّها قليلة"},{"id":"b","text":"يسخر منها أمام أصحابه"},{"id":"c","text":"يأخذها صامتًا دون شكر"},{"id":"d","text":"يَقبَلها فرِحًا ويشكره فالعبرةُ بالمحبّة"}]'::jsonb, 'd', 'نَقبَل الهديّةَ بفرحٍ وشكرٍ ولو كانت يسيرة، فالعبرةُ بالمحبّة لا بثمن الهديّة. الخطأ الشائع احتقارُ الهديّة الصغيرة أو ترْكُ الشكر.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9d71a713-aa64-5ac1-98ae-db7f9367a893', '23208f90-49a3-5584-801d-0cc78e006897', 'وصلَ ولدٌ إلى بيت صديقه فطرق البابَ مرّةً فلم يُفتح له ولم يُؤذَن. ما الأصوب؟', '[{"id":"a","text":"يفتح البابَ بنفسه ويدخل"},{"id":"b","text":"يبقى يطرق بقوّةٍ حتّى يُفتح"},{"id":"c","text":"ينصرف بأدبٍ ولا يغضب"},{"id":"d","text":"يصيح باسم صديقه بصوتٍ عالٍ"}]'::jsonb, 'c', 'من الأدب أن نستأذن، فإن لم يُؤذَن لنا انصرفنا بأدبٍ ولم نغضب. الخطأ الشائع الإصرارُ على الدخول أو الغضبُ عند ردّ الزيارة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('08ff10f0-0ed7-5dd5-9859-83b19c558906', '23208f90-49a3-5584-801d-0cc78e006897', 'زارت سُعادُ خالتَها فوجدتها تستعدّ للخروج إلى عملها. ما الموقفُ الأنسب؟', '[{"id":"a","text":"تجلس طويلًا وتطلب منها الطعام"},{"id":"b","text":"تُسلّم وتطمئنّ عليها سريعًا ثمّ تنصرف"},{"id":"c","text":"تمنعها من الخروج لتُكمل الزيارة"},{"id":"d","text":"تغضب لأنّ خالتها مشغولة"}]'::jsonb, 'b', 'مراعاةُ ظروف المزور تقتضي ألّا نُثقِل على المشغول، فنُسلّم ونطمئنّ سريعًا ثمّ ننصرف. الخطأ الشائع الإطالةُ على مَن هو على وشك الخروج.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('36a9122b-8cf3-5a9e-b544-5492306c95bc', '23208f90-49a3-5584-801d-0cc78e006897', 'أيُّ هذه التصرّفات يجمع آدابَ الزيارة الصحيحة؟', '[{"id":"a","text":"أزور في وقتٍ مناسب، أستأذن، لا أُطيل، وأراعي صاحبَ البيت"},{"id":"b","text":"أدخل بلا إذن وأبقى طويلًا"},{"id":"c","text":"أزور وقتَ الطعام وأُكثِر الطلبات"},{"id":"d","text":"أرفع صوتي وأُفتّش في البيت"}]'::jsonb, 'a', 'آدابُ الزيارة مجتمعةً: اختيارُ الوقت المناسب، والاستئذان، وعدمُ الإطالة، ومراعاةُ المزور. الخطأ الشائع الإخلالُ بأحد هذه الآداب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0cf541a3-bb9d-5245-bca1-29600aba8927', '23208f90-49a3-5584-801d-0cc78e006897', 'ما الفكرةُ الجامعةُ من درس آداب الزيارة والعيادة؟', '[{"id":"a","text":"أنّ الزيارةَ يجب أن تكون طويلةً دائمًا"},{"id":"b","text":"أنّ المريضَ لا يُزار حتّى يَشفى"},{"id":"c","text":"أنّ حسنَ الأدب في الزيارة والعيادة يقوّي المحبّة بين المسلمين"},{"id":"d","text":"أنّ الهديّةَ يجب أن تكون غاليةً وإلّا فلا"}]'::jsonb, 'c', 'الدرسُ أنّ التزاورَ بأدبٍ — وقتًا مناسبًا، واستئذانًا، وعدمَ إطالة، ومراعاةً، وتبادلَ هدايا، وعيادةَ مريض — يقوّي المحبّة بين المسلمين. الخطأ الشائع حصرُ الدرس في فكرةٍ واحدة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

