INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e49dea54-ecc9-5f6b-b692-89a7548189fa', 'd8d06034-f7f6-5530-b1c2-7ff905f62bd7', 'العِيادةُ في الإسلام هي زيارةُ ...', '[{"id":"a","text":"السوق"},{"id":"b","text":"المريض للاطمئنان عليه"},{"id":"c","text":"المدرسة"},{"id":"d","text":"المسجد فقط"}]'::jsonb, 'b', 'العِيادةُ اسمٌ خاصّ لزيارة المريض نطمئنّ بها عليه ونُدخِل السرورَ على قلبه. الخطأ الشائع الخلط بين العِيادة وزيارةٍ عاديّة.', 1)
