INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d2264528-540b-5ce0-9240-bb914d5fe406', 'd8d06034-f7f6-5530-b1c2-7ff905f62bd7', 'من آداب الزيارة أن نختار وقتًا ...', '[{"id":"a","text":"وقتَ نوم الناس"},{"id":"b","text":"وقتَ انشغالهم بالطعام"},{"id":"c","text":"حين يكونون متعبين"},{"id":"d","text":"يكون فيه صاحبُ البيت مستعدًّا مسرورًا"}]'::jsonb, 'd', 'نختار الوقتَ المناسب الذي يكون فيه صاحبُ البيت مستعدًّا، ولا نزور وقتَ النوم أو الطعام أو الانشغال. الخطأ الشائع اختيارُ وقتٍ يُتعِب المزور.', 2)
