INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4ffa6acd-508c-501b-b619-e0da13ab2269', 'd8d06034-f7f6-5530-b1c2-7ff905f62bd7', 'لماذا لا نُطيل في الزيارة؟', '[{"id":"a","text":"لأنّ الزيارةَ مكروهةٌ كلَّها"},{"id":"b","text":"لأنّنا نخاف صاحبَ البيت"},{"id":"c","text":"حتّى لا نُتعِب صاحبَ البيت ونُعطّله عن أعماله"},{"id":"d","text":"لأنّ الكلامَ ممنوع"}]'::jsonb, 'c', 'لا نُطيل حتّى لا نُتعِب صاحبَ البيت ونُعطّله عن أعماله، فالزيارةُ القصيرةُ اللطيفة أحبُّ إلى القلوب. الخطأ الشائع ظنّ أنّ الإطالةَ دليلُ محبّة.', 3)
