INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('759be9e2-ea61-5b2f-bc18-1dd69b610af3', 'd8d06034-f7f6-5530-b1c2-7ff905f62bd7', 'قال النبيّ ﷺ في حقّ المسلم: «وإذا مَرِضَ فـ…». ما تمامُها؟', '[{"id":"a","text":"فعُدْهُ"},{"id":"b","text":"فاتركْه"},{"id":"c","text":"فانتظرْه"},{"id":"d","text":"فاهجُرْه"}]'::jsonb, 'a', 'تمامُ الحديث: «وإذا مَرِضَ فعُدْهُ» (رواه مسلم)، أي زُره واطمئنّ عليه. الخطأ الشائع ظنّ أنّ المريضَ يُترك حتّى يَشفى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('35ae4641-0d50-515f-8ada-967145bc903c', 'd8d06034-f7f6-5530-b1c2-7ff905f62bd7', 'إن أُعطيتَ هديّةً يسيرةً من صديقك، فالأدبُ أن ...', '[{"id":"a","text":"تطلب هديّةً أكبرَ منها"},{"id":"b","text":"تَقبَلها بفرحٍ وتشكره عليها"},{"id":"c","text":"تردّها وتقول إنّها قليلة"},{"id":"d","text":"تأخذها دون أن تشكره"}]'::jsonb, 'b', 'نَقبَل الهديّةَ بفرحٍ وشكرٍ ولو كانت يسيرة، فالعبرةُ بالمحبّة لا بالثمن. الخطأ الشائع احتقارُ الهديّة الصغيرة أو ترْكُ الشكر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f5e92d35-4e9d-55a9-bccd-2788277884ad', 'd8d06034-f7f6-5530-b1c2-7ff905f62bd7', 'تلميذٌ دخلَ بيتَ جاره فأخذ يُفتّش في أغراضه ويرفع صوته. ما الخطأ الذي وقع فيه؟', '[{"id":"a","text":"لم يُخطئ، فهذا من حقّه كزائر"},{"id":"b","text":"أخطأ لأنّه استأذن قبل الدخول"},{"id":"c","text":"أخطأ لأنّه أهدى صاحبَ البيت"},{"id":"d","text":"أخطأ لأنّه لم يُراعِ أدبَ بيت المزور"}]'::jsonb, 'd', 'من مراعاة المزور أن نتأدّب في بيته: نخفض أصواتنا ولا نُفتّش في أغراضه. وقد أخطأ التلميذُ لأنّه لم يُراعِ هذا الأدب. الخطأ الشائع التصرّفُ في بيت الغير بلا أدب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

