INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46760daa-6b4a-59f2-935f-bd4588f6d40c', '0f07b3a0-5e74-5687-b87a-8912745f4c6d', 'ما معنى التواضع؟', '[{"id":"a","text":"أن يرى الإنسانُ نفسَه أفضلَ من الناس"},{"id":"b","text":"أن يكونَ الإنسانُ ليِّنًا مع الناس ولا يحتقرَ أحدًا"},{"id":"c","text":"أن يجمعَ الإنسانُ المالَ الكثير"},{"id":"d","text":"أن يبتعدَ الإنسانُ عن الناس كلِّهم"}]'::jsonb, 'b', 'التواضعُ خُلُقٌ كريمٌ معناه أن يكونَ الإنسانُ ليِّنًا متواضعًا مع الناس، فلا يرى نفسَه أفضلَ منهم ولا يحتقرُ أحدًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
