  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9c70e092-8e33-578b-bbaf-2002b1461ae9', '0f07b3a0-5e74-5687-b87a-8912745f4c6d', 'ما هو ضدُّ التواضع؟', '[{"id":"a","text":"الكِبر (التكبّر)"},{"id":"b","text":"الصدق"},{"id":"c","text":"الكرم"},{"id":"d","text":"الصبر"}]'::jsonb, 'a', 'ضدُّ التواضعِ هو الكِبر، وهو أن يرى الإنسانُ نفسَه أعلى من الناس فيحتقرَهم؛ وهو خُلُقٌ ذميمٌ يُبغضه الله.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
