  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9fbff757-275f-547b-8b90-b73a7f6cbf2c', '0f07b3a0-5e74-5687-b87a-8912745f4c6d', 'في وصيّة لقمان: «وَلَا تَمْشِ فِي الْأَرْضِ مَرَحًا» تنهانا الآيةُ عن المشي ...', '[{"id":"a","text":"بسرعةٍ كبيرة"},{"id":"b","text":"حافيَ القدمين"},{"id":"c","text":"مُتباهيًا مُتكبّرًا"},{"id":"d","text":"في الليل"}]'::jsonb, 'c', '«ولا تمشِ في الأرض مرحًا» أي لا تمشِ مُتباهيًا مُتكبّرًا، بل امشِ في سكينةٍ وتواضع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d85cf69b-8090-58cd-a563-1a332bbd8d61', '0f07b3a0-5e74-5687-b87a-8912745f4c6d', 'ما الذي يحصل لمن يتواضع لله، كما في حديث النبيِّ ﷺ؟', '[{"id":"a","text":"يَنقص قَدرُه ويَذِلّ"},{"id":"b","text":"يَنساه الناس"},{"id":"c","text":"يَفقد ماله"},{"id":"d","text":"يَرفعه الله ويُعلي قَدرَه"}]'::jsonb, 'd', 'قال ﷺ: «وَمَا تَوَاضَعَ أَحَدٌ لِلَّهِ إِلَّا رَفَعَهُ اللَّهُ»، فالتواضعُ سببُ الرّفعة لا سببُ الذلّ.', 4)
ON CONFLICT (id) DO UPDATE SET
