  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6193520d-f097-58cf-a16f-40034d21afbf', '0f07b3a0-5e74-5687-b87a-8912745f4c6d', 'من فوائد التواضع أنّه يجعل الناسَ ...', '[{"id":"a","text":"يَخافون منّا"},{"id":"b","text":"يُحبّوننا ويألفوننا"},{"id":"c","text":"يَبتعدون عنّا"},{"id":"d","text":"يَسخرون منّا"}]'::jsonb, 'b', 'من فوائد التواضع محبّةُ الناس، فالمتواضعُ يُحبّه الناسُ ويألفونه، أمّا المتكبّرُ فيُبغضونه ويبتعدون عنه.', 5)
