  ('97ab82a8-66ca-5623-9088-a63ce2b9238e', '3bf6c17b-b8ea-53d2-b060-b79bcbd17af9', 'ضدُّ التواضع هو ...', '[{"id":"a","text":"الكرم"},{"id":"b","text":"العدل"},{"id":"c","text":"الحياء"},{"id":"d","text":"الكِبر"}]'::jsonb, 'd', 'ضدُّ التواضعِ هو الكِبر، وهو أن يرى الإنسانُ نفسَه أعلى من الناس فيحتقرَهم.', 3)
