INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c9fa7e7-9a6c-527b-a41a-0dfb210bd6ee', '3bf6c17b-b8ea-53d2-b060-b79bcbd17af9', 'كان نبيُّنا ﷺ يُسلّم على ...', '[{"id":"a","text":"الأغنياء فقط"},{"id":"b","text":"الصِّبيان إذا مرّ بهم"},{"id":"c","text":"الملوك وحدهم"},{"id":"d","text":"لا أحد"}]'::jsonb, 'b', 'كان النبيُّ ﷺ من تواضعه يُسلّم على الصِّبيان إذا مرّ بهم ويُلاطفهم، فهو قُدوتُنا في التواضع.', 4)
