INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9d0141f6-95bc-5824-b64b-399151b6f20f', '3bf6c17b-b8ea-53d2-b060-b79bcbd17af9', 'إذا تفوّقتَ في الدرس، فالتواضع أن ...', '[{"id":"a","text":"تتباهى على أصدقائك"},{"id":"b","text":"تحتقر مَن لم يتفوّق"},{"id":"c","text":"لا تتباهى وتُساعد أصدقاءك"},{"id":"d","text":"تسخر من الضعفاء"}]'::jsonb, 'c', 'من التواضع ألّا نتباهى على الأصدقاء إذا تفوّقنا، بل نُساعدهم؛ والتباهي من الكِبر المذموم.', 5)
