INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('61badf39-3338-513d-81ee-9d9f30504e8e', '16a2c7cd-3e95-576c-8d66-2cbbce15c06a', 'قال ﷺ: «وَمَا تَوَاضَعَ أَحَدٌ لِلَّهِ إِلَّا رَفَعَهُ اللَّهُ». ما الدرسُ المستفادُ من الحديث؟', '[{"id":"a","text":"أنّ الكِبرَ يرفع صاحبَه"},{"id":"b","text":"أنّ التواضعَ للهِ سببُ الرّفعة لا الذلّ"},{"id":"c","text":"أنّ التواضعَ يُنقص قَدرَ صاحبه"},{"id":"d","text":"أنّ المالَ يرفع صاحبَه"}]'::jsonb, 'b', 'الحديثُ يُعلّمنا أنّ مَن تواضعَ للهِ رفعَه اللهُ وأعلى قَدرَه؛ فالتواضعُ سببُ الرّفعة لا الذلّ. الخطأ الشائع ظنُّ أنّ التواضعَ يُنقص صاحبَه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c1dba47a-8bff-51df-b35b-3071daea8ef3', '16a2c7cd-3e95-576c-8d66-2cbbce15c06a', 'من تواضع النبيِّ ﷺ في بيته أنّه كان ...', '[{"id":"a","text":"يأمر الناسَ بخدمته"},{"id":"b","text":"لا يُكلّم أهلَه"},{"id":"c","text":"يأنف من العمل"},{"id":"d","text":"يخدم أهلَه ويُعينهم"}]'::jsonb, 'd', 'كان النبيُّ ﷺ مع عظمته يخدم أهلَه في بيته ويُعينهم في أعمالهم، وهذا من كمال تواضعه. الخطأ الشائع ظنُّ أنّ خدمةَ الأهل تُنقص قَدرَ الإنسان.', 2)
