INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cd3aa57d-297c-5e49-ad78-3d0564d6cdab', '16a2c7cd-3e95-576c-8d66-2cbbce15c06a', 'في وصيّة لقمان «وَلَا تُصَاعِرْ خَدَّكَ لِلنَّاسِ»، معنى أن تُصاعِرَ خدَّك أن ...', '[{"id":"a","text":"تُكثرَ الكلامَ معهم"},{"id":"b","text":"تُسرعَ في المشي"},{"id":"c","text":"تُعرِضَ بوجهك عنهم تكبّرًا واحتقارًا"},{"id":"d","text":"تنظرَ إليهم وتبتسم"}]'::jsonb, 'c', '«لا تُصاعِرْ خدَّك للناس» أي لا تُمِلْ وجهَك عنهم وتُعرِضْ تكبّرًا واحتقارًا، بل أقبِلْ عليهم بوجهٍ بشوش. الخطأ الشائع ظنُّ أنّ المعنى مجرّدُ الالتفات.', 3)
