  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3acf5f29-2931-55b0-8223-3def45654e42', '16a2c7cd-3e95-576c-8d66-2cbbce15c06a', '«إِنَّ اللَّهَ لَا يُحِبُّ كُلَّ مُخْتَالٍ فَخُورٍ»: مَن هو «المختال»؟', '[{"id":"a","text":"الكريمُ المِعطاء"},{"id":"b","text":"الصادقُ في كلامه"},{"id":"c","text":"الصبورُ على البلاء"},{"id":"d","text":"المتكبّرُ في مِشيته"}]'::jsonb, 'd', '«المختال» هو المتكبّرُ في مِشيته، و«الفخور» هو الذي يفتخر على الناس بما عنده؛ واللهُ لا يحبّ المتكبّرين. الخطأ الشائع الخلطُ بين الافتخار المذموم والصفات الحسنة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0bdee1a4-708a-50f1-8dee-d50ab28461f8', '16a2c7cd-3e95-576c-8d66-2cbbce15c06a', 'تلميذٌ يسخر من زميلٍ فقيرٍ ويأنف أن يجلسَ بجانبه. هذا السلوكُ من ...', '[{"id":"a","text":"الكِبر المذموم"},{"id":"b","text":"التواضع المحمود"},{"id":"c","text":"الكرم"},{"id":"d","text":"الحياء"}]'::jsonb, 'a', 'السخريةُ من الفقير والأنَفةُ من مجالسته من الكِبر المذموم الذي يُبغضه الله. الخطأ الشائع التهوينُ من احتقار الآخرين لأجل مالهم أو هيئتهم.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('94040021-0fd4-5720-9ef9-220383f7cb91', '16a2c7cd-3e95-576c-8d66-2cbbce15c06a', 'أخطأ تلميذٌ في حقّ صديقه. ما التصرّفُ الذي يدلّ على تواضعه؟', '[{"id":"a","text":"يُصرّ على أنّه لم يُخطئ"},{"id":"b","text":"يعترف بخطئه ويعتذر"},{"id":"c","text":"يسخر من صديقه"},{"id":"d","text":"يبتعد عنه ولا يُكلّمه"}]'::jsonb, 'b', 'من علامات التواضع أن يعترفَ المرءُ بخطئه ويعتذرَ ويقولَ «أنا آسف»؛ أمّا الإصرارُ على الخطإ فمن الكِبر. الخطأ الشائع ظنُّ أنّ الاعترافَ بالخطإ ضعفٌ، وهو في الحقيقة قوّةٌ وتواضع.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

