INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0aa9cc1b-6f5e-5197-bb54-42588d6b506b', 'd26722ed-2abb-5f6d-8df4-785a61fa7137', 'التواضعُ من ...', '[{"id":"a","text":"الأخلاق الذميمة"},{"id":"b","text":"العبادات البدنيّة"},{"id":"c","text":"أركان الإسلام"},{"id":"d","text":"مكارم الأخلاق"}]'::jsonb, 'd', 'التواضعُ خُلُقٌ كريمٌ من مكارم الأخلاق، يُحبّه الله ويُحبّه الناس.', 1)
