INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c77227ab-c728-508d-ade5-031cab2e9024', 'd26722ed-2abb-5f6d-8df4-785a61fa7137', 'المتكبّرُ هو الذي ...', '[{"id":"a","text":"يُساعد الناس ويلين لهم"},{"id":"b","text":"يرى نفسَه أعلى من الناس فيحتقرهم"},{"id":"c","text":"يعترف بخطئه"},{"id":"d","text":"يُسلّم على الجميع"}]'::jsonb, 'b', 'المتكبّرُ هو الذي يرى نفسَه أعلى من الناس فيحتقرهم ويسخرُ منهم ولا يقبل النصيحة؛ والكِبرُ خُلُقٌ ذميم.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b58e95f-f970-5a99-a924-a6f63e6f1322', 'd26722ed-2abb-5f6d-8df4-785a61fa7137', 'أوصى لقمانُ ابنَه في القرآن الكريم بـ ...', '[{"id":"a","text":"التواضع وترك الكِبر"},{"id":"b","text":"جمع المال"},{"id":"c","text":"كثرة اللعب"},{"id":"d","text":"السفر الدائم"}]'::jsonb, 'a', 'أوصى لقمانُ ابنَه بالتواضع، فقال الله على لسانه: «وَلَا تُصَاعِرْ خَدَّكَ لِلنَّاسِ وَلَا تَمْشِ فِي الْأَرْضِ مَرَحًا».', 3)
ON CONFLICT (id) DO UPDATE SET
