  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3cf2e39d-6bbe-5e3a-bec4-4b9f4b47d7e7', 'd26722ed-2abb-5f6d-8df4-785a61fa7137', 'من فوائد التواضع في الآخرة والدنيا ...', '[{"id":"a","text":"كثرةُ المال حتمًا"},{"id":"b","text":"النصرُ في الحروب"},{"id":"c","text":"محبّةُ الله ورفعةُ القَدر"},{"id":"d","text":"طولُ العمر"}]'::jsonb, 'c', 'من فوائد التواضع محبّةُ الله، ومحبّةُ الناس، ورفعةُ القَدر؛ قال ﷺ: «وَمَا تَوَاضَعَ أَحَدٌ لِلَّهِ إِلَّا رَفَعَهُ اللَّهُ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1579331b-a33c-58e4-b867-7f6cbec2d110', 'd26722ed-2abb-5f6d-8df4-785a61fa7137', '«المرحُ» المنهيُّ عنه في قوله «وَلَا تَمْشِ فِي الْأَرْضِ مَرَحًا» هو ...', '[{"id":"a","text":"المشيُ تباهيًا وتكبّرًا"},{"id":"b","text":"المشيُ إلى المسجد"},{"id":"c","text":"المشيُ مع الوالدين"},{"id":"d","text":"المشيُ في الصباح"}]'::jsonb, 'a', '«مرحًا» أي تباهيًا وتكبّرًا، فالآيةُ تنهانا عن المشي مُتكبّرين، وتأمرنا بالمشي في سكينةٍ وتواضع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6f8be30f-447d-530a-ad07-6a531afef63f', 'd26722ed-2abb-5f6d-8df4-785a61fa7137', 'اقتداءً بالنبيِّ ﷺ، المتواضعُ مع الفقير والمسكين ...', '[{"id":"a","text":"يحتقره ويبتعد عنه"},{"id":"b","text":"يسخر منه"},{"id":"c","text":"يأنف من مجالسته"},{"id":"d","text":"يجلس معه ولا يحتقره"}]'::jsonb, 'd', 'كان النبيُّ ﷺ يجلس مع المساكين والفقراء ولا يحتقر أحدًا، فنقتدي به فنجلس معهم ونلين لهم.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('812d2579-7614-559a-ac1d-10f7744e9d9c', 'bf3984fb-5fbc-5c96-93ea-8a0f469165fe', 'education-islamique-4eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: بطلُ مكارم الأخلاق', 4, 300, 60, 'challenge', 'admin', 4)
