INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2d1a607f-36e0-54c6-b416-4324226de62d', '812d2579-7614-559a-ac1d-10f7744e9d9c', 'أرادَ تلميذٌ أن يقتديَ بتواضع النبيِّ ﷺ في بيته. أيُّ هذه التصرّفات يوافق ذلك؟', '[{"id":"a","text":"أن يأمرَ إخوتَه بخدمته"},{"id":"b","text":"أن يُعينَ والدَيه في أعمال البيت"},{"id":"c","text":"أن يأنفَ من العمل في البيت"},{"id":"d","text":"أن يجلسَ ولا يُساعد أحدًا"}]'::jsonb, 'b', 'كان النبيُّ ﷺ يخدم أهلَه ويُعينهم، فالاقتداءُ به أن يُعينَ التلميذُ والدَيه في أعمال البيت. الخطأ الشائع ظنُّ أنّ خدمةَ الأهل تُنقص قَدرَ الإنسان.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('55fb7840-e904-5c26-a63f-928ce89cb58e', '812d2579-7614-559a-ac1d-10f7744e9d9c', 'تلميذٌ متفوّقٌ صار يحتقر زملاءه الأقلَّ منه ويتباهى عليهم بدرجاته. ما الذي ابتعد عنه؟', '[{"id":"a","text":"الكرم"},{"id":"b","text":"الصدق"},{"id":"c","text":"التواضع"},{"id":"d","text":"النظافة"}]'::jsonb, 'c', 'احتقارُ الزملاء والتباهي عليهم ابتعادٌ عن التواضع ووقوعٌ في الكِبر المذموم. الخطأ الشائع ظنُّ أنّ التفوّقَ يُبيح الكِبرَ على الناس.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('41898603-524b-5156-88e3-d099f1507353', '812d2579-7614-559a-ac1d-10f7744e9d9c', 'حضرَ طفلٌ غنيٌّ وطفلٌ فقيرٌ، فسلّمَ التلميذُ على الغنيِّ وأعرضَ عن الفقير. كيف نصحّح سلوكه على هَدْي الآية «وَلَا تُصَاعِرْ خَدَّكَ لِلنَّاسِ»؟', '[{"id":"a","text":"يُقبل على الجميع ويُسلّم على الغنيِّ والفقير سواءً"},{"id":"b","text":"يُسلّم على الفقير وحده"},{"id":"c","text":"يُعرض عنهما معًا"},{"id":"d","text":"يختار حسب الملابس"}]'::jsonb, 'a', 'الآيةُ تنهى عن الإعراض عن الناس تكبّرًا، فالواجبُ أن يُقبل على الجميع ويُسلّم على الغنيِّ والفقير سواءً. الخطأ الشائع التفريقُ بين الناس حسب مالهم أو هيئتهم.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bbe58744-9448-5d20-901f-52adf48bc3f0', '812d2579-7614-559a-ac1d-10f7744e9d9c', 'قال صديقٌ لزميله: «إنْ تواضعتَ للناس قلَّ قَدرُك بينهم». بماذا تردّ عليه مستدلًّا بحديث النبيِّ ﷺ؟', '[{"id":"a","text":"صحيحٌ، التواضع يُذِلّ صاحبه"},{"id":"b","text":"التواضع يُنقص القَدرَ دائمًا"},{"id":"c","text":"لا علاقةَ للتواضع بالقَدر"},{"id":"d","text":"بل «مَا تَوَاضَعَ أَحَدٌ لِلَّهِ إِلَّا رَفَعَهُ اللَّهُ»"}]'::jsonb, 'd', 'نردّ بحديث النبيِّ ﷺ: «وَمَا تَوَاضَعَ أَحَدٌ لِلَّهِ إِلَّا رَفَعَهُ اللَّهُ»، فالتواضعُ سببُ الرّفعة لا الذلّ. الخطأ الشائع ظنُّ أنّ التواضعَ يُنقص صاحبَه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('029f4338-80eb-5370-80f4-bd6405e6ee04', '812d2579-7614-559a-ac1d-10f7744e9d9c', 'نصحَ معلّمٌ تلميذًا بتصحيح خطئه، فأصرّ التلميذُ على رأيه ورفض النصيحة. هذا من علامات ...', '[{"id":"a","text":"التواضع"},{"id":"b","text":"الحلم"},{"id":"c","text":"الحياء"},{"id":"d","text":"الكِبر"}]'::jsonb, 'd', 'رفضُ النصيحة والإصرارُ على الخطإ من علامات الكِبر، أمّا المتواضعُ فيقبل النصيحةَ ويعترفُ بخطئه. الخطأ الشائع عدُّ الإصرار على الرأي قوّةً، وهو في الحقيقة كِبر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e925edf7-dc2b-5ece-a3b1-8abbb4602705', '812d2579-7614-559a-ac1d-10f7744e9d9c', 'أيُّ المواقف التالية يجمع بين التواضع وحُسن الخُلُق معًا؟', '[{"id":"a","text":"يتباهى بدرجاته ويسخر من الضعفاء"},{"id":"b","text":"يمشي مُتكبّرًا ويُعرض عن الناس"},{"id":"c","text":"يُسلّم على الجميع، ويُساعد زملاءه، ويعترف بخطئه"},{"id":"d","text":"يرفض النصيحة ويأنف من مجالسة الفقير"}]'::jsonb, 'c', 'التسليمُ على الجميع ومساعدةُ الزملاء والاعترافُ بالخطإ كلُّها من التواضع وحُسن الخُلُق. الخطأ الشائع الخلطُ بين التواضع وبين سلوكات الكِبر كالتباهي والسخرية ورفض النصيحة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

