INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('844c6c8d-e44c-5789-8ee1-a34464ef19e5', '3f1daa08-5eae-5f1e-98a3-2363a30753ca', 'الكِبرُ خُلُقٌ ...', '[{"id":"a","text":"يُحبّه الله"},{"id":"b","text":"محمودٌ نتحلّى به"},{"id":"c","text":"ذميمٌ يُبغضه الله"},{"id":"d","text":"لا بأسَ به"}]'::jsonb, 'c', 'الكِبرُ خُلُقٌ ذميمٌ يُبغضه الله، لأنّ الكبرياءَ لله وحده سبحانه، فالمؤمنُ يبتعد عنه.', 2)
