INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('33b40011-a55b-5a6d-bf37-5319b496bcd3', '3f1daa08-5eae-5f1e-98a3-2363a30753ca', 'من فوائد التواضع أنّه يجلب ...', '[{"id":"a","text":"بُغضَ الناس"},{"id":"b","text":"الوحدةَ والعزلة"},{"id":"c","text":"الحقدَ في القلب"},{"id":"d","text":"محبّةَ الله ومحبّةَ الناس"}]'::jsonb, 'd', 'من فوائد التواضع محبّةُ الله ومحبّةُ الناس وكثرةُ الأحبّة وصفاءُ القلب؛ أمّا الكِبرُ فيجلب البُغضَ والعزلة.', 3)
