INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('41250e4a-0933-5c7d-83fd-e7c8b44bea1f', '3f1daa08-5eae-5f1e-98a3-2363a30753ca', 'كان النبيُّ ﷺ مثالًا في التواضع، فمن ذلك أنّه كان ...', '[{"id":"a","text":"يأنف من مجالسة الفقراء"},{"id":"b","text":"لا يردّ السلام"},{"id":"c","text":"يُجيب دعوةَ الفقير ويجلس مع المساكين"},{"id":"d","text":"يأمر الناسَ بخدمته"}]'::jsonb, 'c', 'كان النبيُّ ﷺ من تواضعه يُجيب دعوةَ الفقير ويجلس مع المساكين ولا يحتقر أحدًا، فهو قُدوتُنا في التواضع.', 4)
