INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d867646c-707a-5615-bbc0-e8ff209b18cc', '3f1daa08-5eae-5f1e-98a3-2363a30753ca', 'في قوله «إِنَّ اللَّهَ لَا يُحِبُّ كُلَّ مُخْتَالٍ فَخُورٍ»، «الفخور» هو الذي ...', '[{"id":"a","text":"يفتخر على الناس بما عنده"},{"id":"b","text":"يُحسن إلى الفقراء"},{"id":"c","text":"يُصلّي في وقتها"},{"id":"d","text":"يصبر على الأذى"}]'::jsonb, 'a', '«الفخور» هو الذي يفتخر على الناس بما عنده من مالٍ أو جاهٍ أو قوّة، واللهُ لا يحبّ المتكبّرين المفتخرين.', 5)
