INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('90778e64-cbce-56bb-bc79-2c76ed03df56', '3f1daa08-5eae-5f1e-98a3-2363a30753ca', 'تلميذٌ يُسلّم على زملائه كلِّهم، ويُساعد الضعيفَ منهم، ولا يسخر من أحد. هذا الخُلُقُ هو ...', '[{"id":"a","text":"التواضع"},{"id":"b","text":"الكِبر"},{"id":"c","text":"البخل"},{"id":"d","text":"الكسل"}]'::jsonb, 'a', 'التسليمُ على الجميع ومساعدةُ الضعيف وتركُ السخرية من خُلُق التواضع الذي يُحبّه الله ويُحبّه الناس.', 6)
