INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73711416-8942-5acd-b7bc-ecfd44b28294', '823b204e-602d-5db6-8b54-f8171b1d4ef6', 'هل يُؤذَّن لصلاة العيد وتُقام كبقيّة الصلوات؟', '[{"id":"a","text":"نعم، لها أذانٌ وإقامة"},{"id":"b","text":"لها إقامةٌ بلا أذان"},{"id":"c","text":"لا أذانَ لها ولا إقامة"},{"id":"d","text":"لها أذانان"}]'::jsonb, 'c', 'صلاة العيدين لا أذانَ لها ولا إقامة، تختلفُ بذلك عن بقيّة الصلوات. الخطأ الشائع ظنُّ أنّ لها أذانًا كالظهر والعصر.', 5)
