INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5cec2b9c-7559-571c-99b8-dcb679c512ca', '80359c4f-5537-5b51-8b5b-6e5250542557', 'صلاة الجمعة هي ركعتان تُقرآن ...', '[{"id":"a","text":"سِرًّا"},{"id":"b","text":"بلا فاتحة"},{"id":"c","text":"بلا سورة"},{"id":"d","text":"جهرًا"}]'::jsonb, 'd', 'صلاة الجمعة ركعتان جهرًا، يقرأ فيهما الإمامُ الفاتحةَ والسورةَ بصوتٍ مسموع.', 2)
