INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7c2bdb0b-086b-5c54-a069-f317854635e1', '80359c4f-5537-5b51-8b5b-6e5250542557', 'في أيّ شهرٍ يكون عيد الفطر؟', '[{"id":"a","text":"في شهر رمضان"},{"id":"b","text":"في غُرّة شهر شوّال"},{"id":"c","text":"في شهر ذي الحجّة"},{"id":"d","text":"في شهر محرّم"}]'::jsonb, 'b', 'عيد الفطر يكون في غُرّة شهر شوّال، أي في أوّل يومٍ بعد انتهاء صيام رمضان.', 3)
