INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('737197b9-fe25-5946-bd6d-067ca5bb9f1d', '80359c4f-5537-5b51-8b5b-6e5250542557', 'بمَ نشهدُ في آخر التشهّد؟', '[{"id":"a","text":"بأنّ الصلاة خمسُ مرّات"},{"id":"b","text":"بأنّ الجمعة فرض"},{"id":"c","text":"أن لا إله إلّا الله وأنّ محمّدًا عبده ورسوله"},{"id":"d","text":"بأنّ العيدين اثنان"}]'::jsonb, 'c', 'في آخر التشهّد نقول: «أشهد أن لا إله إلّا الله وحده لا شريك له، وأشهد أنّ محمّداً عبده ورسوله»، فهي شهادةُ التوحيد وشهادةُ الرسالة.', 4)
