INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e8994eac-7504-55b5-a69f-22b8349303d9', 'cbe7abbb-f059-5a1c-9e5b-51d2237742a1', 'ذهب تلميذٌ إلى المسجد يوم الجمعة فاغتسلَ وتطيّبَ ولبسَ ثيابًا نظيفةً وبكّرَ. ماذا نقولُ عنه؟', '[{"id":"a","text":"أهملَ آدابَ الجمعة"},{"id":"b","text":"راعى آدابَ يوم الجمعة"},{"id":"c","text":"أخطأ في كلّ شيء"},{"id":"d","text":"كان عليه أن يتأخّر"}]'::jsonb, 'b', 'الاغتسالُ والتطيّبُ ولبسُ الثياب الحسنة والتبكيرُ كلّها من آداب يوم الجمعة، فهذا تلميذٌ راعى الآدابَ أحسنَ مراعاة. الخطأ الشائع التهاونُ بهذه الآداب يوم الجمعة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cf78d2f9-efa5-5c49-8e4f-fe4f732f0f89', 'cbe7abbb-f059-5a1c-9e5b-51d2237742a1', 'صلّى تلميذٌ صلاةَ الظهر فأرادَ أن يقنُتَ فيها كما يقنُتُ في الصبح. ما الصواب؟', '[{"id":"a","text":"أصابَ، فالقنوتُ في كلّ صلاة"},{"id":"b","text":"القنوتُ في صلاة العصر فقط"},{"id":"c","text":"القنوتُ خاصٌّ بصلاة الصبح لا الظهر"},{"id":"d","text":"القنوتُ في السجود"}]'::jsonb, 'c', 'دعاءُ القنوت خاصٌّ بصلاة الصبح في الركعة الثانية، ولا يُقال في الظهر. الخطأ الشائع تعميمُ القنوت على كلّ الصلوات.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d518c646-8d71-5578-9696-e7b830073d16', 'cbe7abbb-f059-5a1c-9e5b-51d2237742a1', 'قال طفلٌ: «سأُصلّي الجمعة وحدي في بيتي كما أُصلّي الظهر». ما الصواب؟', '[{"id":"a","text":"كلامُه صحيح"},{"id":"b","text":"الجمعةُ ركعةٌ واحدة"},{"id":"c","text":"الجمعةُ أربعُ ركعات"},{"id":"d","text":"الجمعةُ تُؤدّى جماعةً في المسجد لا وحده في البيت"}]'::jsonb, 'd', 'صلاة الجمعة فرضٌ يُؤدّى جماعةً في المسجد، ولا تُصلّى وحدَها في البيت كالظهر. الخطأ الشائع ظنُّ أنّ الجمعةَ كالظهر تُصلّى فُرادى.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
