  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1180602a-27dd-5bdd-9853-579f16cf1b8f', 'cbe7abbb-f059-5a1c-9e5b-51d2237742a1', 'حضرَ تلميذٌ صلاة العيد فانتظرَ المؤذّنَ ليُؤذّن، فلم يسمع أذانًا. لماذا؟', '[{"id":"a","text":"لأنّ صلاة العيد لا أذانَ لها ولا إقامة"},{"id":"b","text":"لأنّ المؤذّنَ نسي"},{"id":"c","text":"لأنّ الوقتَ تأخّر"},{"id":"d","text":"لأنّ المسجدَ مغلق"}]'::jsonb, 'a', 'صلاة العيدين لا أذانَ لها ولا إقامة، فلا ينتظرُ المصلّي أذانًا. الخطأ الشائع توقّعُ أذانٍ لصلاة العيد كبقيّة الصلوات.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('25ef4010-46dd-5fcb-baf6-7dc3ec22ff24', 'cbe7abbb-f059-5a1c-9e5b-51d2237742a1', 'تلميذٌ صلّى العيدَ ثمّ قام ليذهب قبل خطبة الإمام ظنًّا منه أنّ لا خطبةَ في العيد. ما الصواب؟', '[{"id":"a","text":"أصابَ، فلا خطبةَ في العيد"},{"id":"b","text":"الخطبةُ تكون قبل الصلاة"},{"id":"c","text":"في العيد خطبةٌ بعد الصلاة كان عليه أن يبقى لها"},{"id":"d","text":"الخطبةُ في وسط الصلاة"}]'::jsonb, 'c', 'في العيد خطبةٌ بعد الصلاة يُذكّرُ فيها الإمامُ بأحكام العيد، فكان عليه أن يبقى. الخطأ الشائع مغادرةُ المُصلّى قبل خطبة العيد.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a7b9dfed-76f1-5b9f-93e8-69864804835d', 'cbe7abbb-f059-5a1c-9e5b-51d2237742a1', 'سُئل تلميذٌ: «ما الفرق بين خطبة الجمعة وخطبة العيد في وقتهما؟» فأيُّ جوابٍ صحيح؟', '[{"id":"a","text":"كلتاهما بعد الصلاة"},{"id":"b","text":"خطبةُ الجمعة قبل الصلاة وخطبةُ العيد بعدها"},{"id":"c","text":"كلتاهما قبل الصلاة"},{"id":"d","text":"خطبةُ الجمعة بعد الصلاة وخطبةُ العيد قبلها"}]'::jsonb, 'b', 'خطبةُ الجمعة تكون قبل الصلاة، وخطبةُ العيد تكون بعد الصلاة. الخطأ الشائع توهّمُ أنّ ترتيب الخطبة واحدٌ في الجمعة والعيد.', 6)
