INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a1331022-77b2-5b41-9078-ae852bee7c28', '45402e58-bfe7-5927-9e50-c67197937d5a', 'بدأ الإمامُ صلاة الجمعة. ماذا فعلَ قبل الركعتين مباشرةً؟', '[{"id":"a","text":"نام قليلًا"},{"id":"b","text":"وزّعَ الطعام"},{"id":"c","text":"لعبَ مع الأطفال"},{"id":"d","text":"ألقى خطبتين وجلسَ بينهما جلسةً قصيرة"}]'::jsonb, 'd', 'قبل ركعتَي الجمعة يُلقي الإمامُ خطبتين على المنبر، ويجلسُ بينهما جلسةً قصيرة، ثمّ تُقامُ الصلاة. الخطأ الشائع نسيانُ الجلسة القصيرة بين الخطبتين.', 1)
