INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24053c79-ff4b-5eb5-9388-682ee14901dd', '45402e58-bfe7-5927-9e50-c67197937d5a', 'ما الذي يختصُّ به دعاءُ القنوت؟', '[{"id":"a","text":"يُقال في كلّ صلاة"},{"id":"b","text":"يُقال في صلاة المغرب"},{"id":"c","text":"يُقال في صلاة الصبح في الركعة الثانية"},{"id":"d","text":"يُقال في السجود"}]'::jsonb, 'c', 'دعاءُ القنوت خاصٌّ بصلاة الصبح، يُقال في الركعة الثانية قبل الركوع. الخطأ الشائع جعلُ القنوت في كلّ الصلوات أو في الركعة الأولى.', 3)
