INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5070c5aa-b5df-58a3-b1a9-d7dc4baa2ce5', '45402e58-bfe7-5927-9e50-c67197937d5a', 'بمَ يُذكّرُ الإمامُ في خطبة عيد الأضحى؟', '[{"id":"a","text":"بمواعيد المدرسة"},{"id":"b","text":"بأخبار السوق"},{"id":"c","text":"بقواعد اللعب"},{"id":"d","text":"بأحكام الأُضحية"}]'::jsonb, 'd', 'في خطبة العيد يُذكّرُ الإمامُ بأحكام العيد: أحكامِ الأُضحية في عيد الأضحى، وأحكامِ زكاة الفطر في عيد الفطر. الخطأ الشائع ظنُّ أنّ خطبة العيد بلا موضوعٍ خاص.', 5)
