INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('10c0878a-81ab-5d27-a95f-b003f8e704ec', '45402e58-bfe7-5927-9e50-c67197937d5a', 'قارنَ تلميذٌ بين الجمعة والعيد في الأذان. ما الصواب؟', '[{"id":"a","text":"كلتاهما بلا أذان"},{"id":"b","text":"كلتاهما لهما أذانان"},{"id":"c","text":"الجمعةُ يُؤذَّن لها والعيدُ لا أذانَ له"},{"id":"d","text":"العيدُ له أذانٌ والجمعةُ بلا أذان"}]'::jsonb, 'c', 'صلاة الجمعة يُؤذَّن لها، أمّا صلاة العيد فلا أذانَ لها ولا إقامة. الخطأ الشائع توهّمُ أنّ العيدَ كالجمعة في الأذان.', 6)
